window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q07"]=window.__LIBQ["tien-nghich"]["q07"]||{};window.__LIBQ["tien-nghich"]["q07"]["techniques"]={"updatedAt":"2026-07-06","count":372,"techniques":[{"id":"that-tinh-kiem-tran","name":"Thất Tinh kiếm trận","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm trận","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm"],"blurb":"Kiếm trận do Vương Lâm điều động để vây công Liễu Mi. Bảy đạo kiếm khí gào thét xông ra, phối hợp với Tịch Diệt chỉ ép nàng vào thế nguy hiểm.","detail":"Trong trận với Liễu Mi, Vương Lâm dùng Thất Tinh kiếm trận bao vây nàng. Kiếm trận phát ra bảy đạo kiếm khí, phối hợp với Tịch Diệt chỉ và các thần thông khác để áp đảo phòng ngự của Liễu Mi.","nguon":["@c0635"]},{"id":"nguyen-than-loi-uy-chi","name":"Nguyên thần lôi uy chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"lôi uy nguyên thần","soHuu":["Vương Lâm"],"blurb":"Một chỉ do Vương Lâm phân ra nguyên thần lôi uy ngưng tụ. Hắn định dùng đòn này lấy mạng Liễu Mi khi sát ý đã đạt cực điểm.","detail":"Vương Lâm phân ra nguyên thần lôi uy, ngưng tụ tại đầu ngón tay để thi triển một chỉ đoạt mạng Liễu Mi. Đòn này xuất hiện ở thời khắc Liễu Mi đã bị áp chế, trước khi Huyễn gia Lão Tổ mở lốc xoáy cứu nàng.","nguon":["@c0635"]},{"id":"kiem-khi-cua-lang-thien-hau","name":"Kiếm khí của Lăng Thiên Hầu","cn":"","loai":"than-thong","loaiLabel":"Kiếm khí","phamCap":"không rõ","hePhai":"kiếm đạo","soHuu":["Vương Lâm"],"blurb":"Đạo kiếm khí Vương Lâm ngưng tụ và phóng vào lốc xoáy để truy kích Huyễn gia Lão Tổ. Uy lực của nó khiến lốc xoáy sụp đổ và làm đối phương phát ra tiếng kêu đau.","detail":"Sau khi Huyễn gia Lão Tổ cứu Liễu Mi qua lốc xoáy, Vương Lâm phóng kiếm khí của Lăng Thiên Hầu vào bên trong. Kiếm khí truy kích xuyên qua lối cứu viện, đánh sụp lốc xoáy và chấn động tới nơi Huyễn gia Lão Tổ đang bế quan ở Nhà Tổ Huyễn gia trên Thiên Huyễn Tinh.","nguon":["@c0635"]},{"id":"nguyen-than-xuat-khieu","name":"Nguyên thần xuất khiếu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Huyễn gia","soHuu":["Huyễn gia Lão Tổ"],"blurb":"Thần thông giúp Huyễn gia Lão Tổ dùng nguyên thần vượt qua tinh không để cứu Liễu Mi.","detail":"Trong lần cứu Liễu Mi, Huyễn gia Lão Tổ xuất nguyên thần vượt tinh không. Trạng thái này khiến lão phải trực tiếp đối diện kiếm khí truy kích của Lăng Thiên Hầu và buộc phải bỏ chạy về mật thất Huyễn gia.","nguon":["@c0636"]},{"id":"cam-che-phong-an","name":"Cấm chế phong ấn","cn":"","loai":"khac","loaiLabel":"Cấm pháp","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Cấm pháp Vương Lâm dùng để thu nhỏ và phong ấn màn sương đen chứa oán anh Bình nhi.","detail":"Vương Lâm bấm quyết tạo từng đạo cấm khí bao quanh màn sương đen, thu nhỏ oán anh đang truyền oán khí vào người hắn rồi đưa vào Thiên nghịch không gian để tạm thời trấn giữ.","nguon":["@c0637"]},{"id":"nguyen-than-loi-uy","name":"Nguyên thần lôi uy","cn":"","loai":"than-thong","loaiLabel":"Năng lực nguyên thần","phamCap":"Không rõ","hePhai":"Lôi lực của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Lôi uy trong nguyên thần của Vương Lâm có thể quét sạch oán khí xâm nhập từ oán anh.","detail":"Khi oán khí tích tụ nhiều năm từ Bình nhi chui vào cơ thể Vương Lâm, lôi uy của nguyên thần hắn chỉ cần quét qua là có thể thanh trừ, khiến oán khí không gây ảnh hưởng đáng kể.","nguon":["@c0637"]},{"id":"dao-hoa-hoang-tuyen","name":"Đạo hóa Hoàng Tuyền","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông của Vương Lâm dẫn động linh khí thiên địa và linh mạch tan vỡ, tạo Hoàng Tuyền để trợ Tôn Tích khôi phục tu vi.","detail":"Ở Nhiễm Vân Tinh, Vương Lâm thi triển Đạo hóa Hoàng Tuyền, dẫn linh khí thiên địa cùng linh lực từ các linh mạch dưới đất vào dòng Hoàng Tuyền, làm nền cho Hoàng Tuyền lực và dược lực Bát phẩm đan dược hỗ trợ Tôn Tích thổ nạp.","nguon":["@c0637"]},{"id":"hoang-tuyen-luc","name":"Hoàng Tuyền lực","cn":"","loai":"than-thong","loaiLabel":"Thức thần thông","phamCap":"Thức thứ ba của Đạo hóa Hoàng Tuyền","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thức thứ ba của Đạo hóa Hoàng Tuyền, tạo lực hút mạnh trong Hoàng Tuyền để gom linh khí cho Tôn Tích thổ nạp.","detail":"Vương Lâm gọi ra Hoàng Tuyền lực, dùng lực hút cực lớn hấp thu linh khí từ các linh mạch tan vỡ dưới đất, khiến Tôn Tích tiến vào trong Hoàng Tuyền thổ nạp và khôi phục tu vi.","nguon":["@c0637"]},{"id":"than-thong-tach-nguyen-than-cua-trieu-truyen-van","name":"Thần thông tách nguyên thần của Triệu Truyền Văn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Triệu Truyền Văn","soHuu":["Triệu Truyền Văn"],"blurb":"Thần thông được Tôn Tích nhắc tới, giúp Triệu Truyền Văn tách nguyên thần dù không luyện ra phân thân.","detail":"Tôn Tích nói Triệu Truyền Văn không luyện được phân thân nhưng có một loại thần thông giúp tách nguyên thần, nhờ đó có thể đã rời khỏi Nhiễm Vân Tinh từ trước.","nguon":["@c0637"]},{"id":"huyen-gia-ho-toc-dai-tran","name":"Huyễn gia hộ tộc đại trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Hộ tộc đại trận","hePhai":"Huyễn gia","soHuu":["Huyễn gia"],"blurb":"Đại trận bảo hộ Huyễn gia ở phía Nam Thiên Huyễn Tinh. Trận được Huyễn Vô Tình mở để chống Vương Lâm và có thể hấp thu các đạo lôi đình đầu tiên do Lôi Thú dẫn xuống.","detail":"Huyễn gia hộ tộc đại trận bao phủ khu vực phía Nam Thiên Huyễn Tinh, nơi Nhà Tổ Huyễn gia tọa lạc. Khi Vương Lâm tới đòi giao Liễu Mi, Huyễn Vô Tình dựa vào đại trận để thách hắn phá trận; các lôi đình đầu tiên của Lôi Thú rơi xuống đều bị đại trận hấp thu.","nguon":["@c0638"]},{"id":"dao-than-thong-trong-ngoc-gian-ho-toc-huyen-gia","name":"Đạo thần thông trong ngọc giản hộ tộc Huyễn gia","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Truyền thừa tiên nhân","hePhai":"Huyễn gia","soHuu":["Huyễn gia"],"blurb":"Thần thông do tiên nhân Huyễn gia lưu lại trong ngọc giản hộ tộc. Đây là một trong các chỗ dựa giúp Huyễn gia giữ vị trí thứ hai trên Thiên Huyễn Tinh.","detail":"Đạo thần thông này nằm trong ngọc giản hộ tộc do tiên nhân Huyễn gia để lại. Chương chỉ nêu đây là truyền thừa khiến Huyễn gia được kiêng kị, chưa mô tả cụ thể uy lực khi thi triển.","nguon":["@c0638"]},{"id":"phu-van-loi-phap-cua-thien-quy-tu","name":"Phù văn lôi pháp của Thiên Quỳ Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông lôi pháp","phamCap":"Âm Hư tu sĩ thi triển","hePhai":"Thiên gia","soHuu":["Thiên Quỳ Tử"],"blurb":"Lôi pháp do Thiên Quỳ Tử dùng khi giao chiến với Tiên vệ khôi lỗi. Lão tạo lượng lớn phù văn, khiến chúng hóa lôi quang và Thiên lôi đánh xuống mục tiêu.","detail":"Trong trận chặn Vương Lâm, Thiên Quỳ Tử dùng phù văn bao phủ chiến trường rồi chuyển chúng thành lôi quang và tiếng sấm, ép Tiên vệ khôi lỗi vào thế chịu công kích. Khi Xạ Thần xa hóa Lôi Thú xuất hiện, lôi phù văn bị Lôi Thú khống chế và nuốt mất.","nguon":["@c0638"]},{"id":"kim-than-cong-kich-cua-tien-ve","name":"Kim thân công kích của Tiên vệ","cn":"","loai":"than-thong","loaiLabel":"Khả năng khôi lỗi","phamCap":"Thân thể khôi lỗi Âm Hư","hePhai":"Tiên vệ khôi lỗi","soHuu":["Tiên vệ"],"blurb":"Khả năng chiến đấu bằng thân thể của Tiên vệ khôi lỗi. Tiên vệ vận kim quang khắp thân, hóa thành kim nhân và dùng quyền lực phá phù văn của Thiên Quỳ Tử.","detail":"Tiên vệ do Tiên Đế Thanh Lâm phỏng theo Cổ Thần luyện chế, phần lớn sức mạnh nằm ở cường độ thân thể. Trong chương này, Tiên vệ lao ra, kim quang phủ toàn thân và tung quyền khiến nhiều phù văn của Thiên Quỳ Tử sụp đổ.","nguon":["@c0638"]},{"id":"mo-phong-an-loi-thu","name":"Mở phong ấn Lôi Thú","cn":"","loai":"bi-thuat","loaiLabel":"Thao tác phong ấn","phamCap":"Liên quan Xạ Thần xa","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thao tác Vương Lâm dùng để giải phóng lôi uy của Lôi Thú. Hắn nhỏ máu lên mi tâm Lôi Thú và ra lệnh mở phong ấn, khiến lôi điện bùng phát thành lốc và lưới sấm.","detail":"Khi lôi đình đầu tiên bị Huyễn gia hộ tộc đại trận hấp thu, Vương Lâm dùng máu nhỏ lên mi tâm Lôi Thú rồi mở phong ấn. Sau đó lôi uy trên thân Lôi Thú bùng lên, kéo theo mây lôi, lốc lôi điện và lưới lôi đình bên ngoài thân thể nó.","nguon":["@c0638"]},{"id":"loi-than-thong-loi-uy","name":"Lôi thần thông / lôi uy","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Lôi hệ","soHuu":["Xạ Thần xa"],"blurb":"Lôi điện do Lôi Thú phát ra trong lúc công kích Huyễn gia đại trận, khiến tộc nhân Huyễn gia đặc biệt kính sợ.","detail":"Trong trận công kích Huyễn gia, Lôi Thú dồn lôi điện tới cực hạn, tạo uy áp bao phủ phạm vi trăm dặm. Tộc nhân Huyễn gia nhận ra thân phận Lôi Thú và liên hệ của nó với Lôi Tiên Điện nên càng hoảng sợ trước lôi uy này.","nguon":["@c0639"]},{"id":"quy-tac-luc","name":"Quy tắc lực","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Khái niệm tu đạo / lực quy tắc","phamCap":"Liên quan bước thứ hai của tu đạo","hePhai":"Tu đạo bước thứ hai","soHuu":["Vương Lâm"],"blurb":"Quy tắc lực là tầng lực lượng được Thiên Quỳ Tử liên hệ với tu đạo bước thứ hai. Một kiếm Trảm La Quyết của Vương Lâm bị nhận định là ẩn chứa quy tắc.","detail":"Trong lúc quan sát trận chiến Huyễn gia, Thiên Quỳ Tử cho rằng một kiếm của Vương Lâm có quy tắc, vượt khỏi phạm vi thông thường của bước thứ nhất. Nhận định này khiến hắn nghi ngờ Vương Lâm có liên quan Lôi Tiên Điện.","nguon":["@c0640"]},{"id":"than-thong-cua-phuc-trach-ngoc-gian","name":"Thần thông của Phúc Trạch ngọc giản","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Tiên pháp / vật truyền thừa","phamCap":"Tiên pháp trong chí bảo Huyễn gia","hePhai":"Huyễn gia","soHuu":["Huyễn Vô Tình"],"blurb":"Thần thông do Phúc Trạch ngọc giản phát động khi Huyễn Vô Tình bấm quyết điều khiển. Ngọc giản hóa thành bóng người tỏa tiên lực khổng lồ để tấn công Vương Lâm.","detail":"Sau khi được Huyễn Vô Tình mời ra, Phúc Trạch ngọc giản hóa thành bóng người và bước về phía Vương Lâm. Tiên lực từ bóng người này nồng đậm đến mức áp chế linh lực trên Thiên Huyễn Tinh, buộc Tiên vệ khôi lỗi và Lôi Thú lập tức hộ bên Vương Lâm.","nguon":["@c0640"]},{"id":"lac-an-khong-che-tan-ma","name":"Lạc ấn khống chế Tán Ma","cn":"","loai":"than-thong","loaiLabel":"Thần thông/ấn ký","phamCap":"Không rõ","hePhai":"Liên quan Vương Lâm và Cổ Yêu Bối La","soHuu":["Vương Lâm"],"blurb":"Ấn ký khống chế mà Vương Lâm khắc sâu vào ma hồn Tán Ma trong hơn trăm năm. Vì có thêm thần thông của Cổ Yêu Bối La, lạc ấn này khiến Tán Ma khó phá bỏ trong thời gian ngắn.","detail":"Lạc ấn được dùng để ràng buộc Tán Ma, vốn là nền tảng khiến Vương Lâm có thể gọi Tán Ma ra trong trận tại Thiên Huyễn Tinh. Tán Ma từng nghĩ chiếm thân thể Vương Lâm, nhưng bị lạc ấn ngăn lại; nó chấp nhận giao dịch vì hy vọng sau khi được tự do sẽ mất vài trăm năm khu trừ thần thông của Bối La.","nguon":["@c0641"]},{"id":"hoa-tien-thuat","name":"Hoá Tiên Thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Một chi nhánh Cổ Yêu bộ tộc","soHuu":["hư ảnh Tiên nhân"],"blurb":"Thần thông rút linh khí toàn Thiên Huyễn Tinh, chuyển hóa thành tiên lực và ngưng tụ thành vụ cầu màu trắng ngà. Tán Ma nhận ra đây là thủ đoạn thuộc một chi nhánh Cổ Yêu bộ tộc.","detail":"Trong trận đối đầu Tán Ma nhập thể Vương Lâm, hư ảnh Tiên nhân thi triển Hoá Tiên Thuật khiến linh khí khắp Thiên Huyễn Tinh bị hút sạch và chuyển thành tiên lực. Thủ đoạn này buộc Tán Ma phải dùng Cổ Ma rút tinh hồn Thiên Huyễn Tinh để đối lại.","nguon":["@c0641"]},{"id":"co-ma-rut-ra-tinh-hon","name":"Cổ Ma rút ra tinh hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông Cổ Ma","phamCap":"Không rõ","hePhai":"Cổ Ma/Cổ Tộc","soHuu":["Tán Ma"],"blurb":"Thủ đoạn Tán Ma dùng khi nhập thể Vương Lâm, hóa ma trảo rút tinh hồn Thiên Huyễn Tinh. Đây là đối trọng trực tiếp với Hoá Tiên Thuật của hư ảnh Tiên nhân.","detail":"Tán Ma dùng ngôn ngữ Cổ Tộc gọi Cổ Ma rồi vươn ma trảo xuống Thiên Huyễn Tinh, rút tinh hồn của tinh cầu để so sức với việc hư ảnh Tiên nhân rút linh lực toàn tinh cầu thành tiên lực. Vương Lâm dù bị khống chế thân thể vẫn trực tiếp cảm nhận quá trình này và có cảm ngộ.","nguon":["@c0641"]},{"id":"quy-tac-kiem-thuc","name":"Quy tắc kiếm thức","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Một trong các thủ đoạn được Thiên Quỳ Tử liệt kê khi suy đoán địa vị của Vương Lâm trong Lôi Tiên Điện. Nó được nhắc cùng Lôi Thú, khôi lỗi và Ma.","detail":"Quy tắc kiếm thức không trực tiếp thi triển trong chương này, nhưng được Thiên Quỳ Tử xem là một phần hệ thống chiến lực khiến Vương Lâm trở nên đáng sợ và có khả năng là nhân vật trọng yếu của Lôi Tiên Điện.","nguon":["@c0641"]},{"id":"ngon-ngu-co-toc","name":"Ngôn ngữ Cổ Tộc","cn":"","loai":"khac","loaiLabel":"Ngôn ngữ thi triển thuật","phamCap":"Không rõ","hePhai":"Cổ Tộc","soHuu":["Tán Ma"],"blurb":"Ngôn ngữ được Tán Ma dùng khi phát động thủ đoạn Cổ Ma trong trận tại Thiên Huyễn Tinh. Nó gắn với lời gọi Cổ Ma và mệnh lệnh rút tinh hồn.","detail":"Khi đối đầu Hoá Tiên Thuật, Tán Ma không dùng lời thông thường mà dùng ngôn ngữ Cổ Tộc để gọi Cổ Ma và thi triển thủ đoạn rút tinh hồn Thiên Huyễn Tinh. Ngôn ngữ này cho thấy nguồn gốc cổ xưa của thần thông Tán Ma sử dụng.","nguon":["@c0641"]},{"id":"truu-hon","name":"Trừu hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bước thứ hai tu đạo","hePhai":"Cổ Ma / Tán Ma","soHuu":["Tán Ma"],"blurb":"Thần thông rút hồn quy mô lớn do Tán Ma thi triển khi khống chế thân thể Vương Lâm.","detail":"Trong chương này, Tán Ma dùng Trừu hồn rút tinh hồn Thiên Huyễn Tinh, quy mô vượt xa việc Tham Lang từng dùng Tiên sơn pháp bảo rút Sơn hồn ở Yêu Linh chi địa. Lực lượng tinh hồn tinh cầu được dùng để va chạm với tiên lực của Tiên nhân hư ảnh.","nguon":["@c0642"]},{"id":"vo-tuong-thien-ma-dao","name":"Vô Tướng Thiên Ma đạo","cn":"","loai":"than-thong","loaiLabel":"Ý cảnh thần thông","phamCap":"Truyền thừa Tiên nhân Huyễn gia","hePhai":"Huyễn gia","soHuu":["Tổ tiên Huyễn gia","Huyễn Vô Tình"],"blurb":"Đạo ý cảnh gốc do tổ tiên Huyễn gia cảm ngộ, là căn nguyên của Thiên Ma đạo và Vô Tướng đạo.","detail":"Huyễn Vô Tình muốn lấy ý cảnh của Liễu Mi để đạt tới Vô Tướng Thiên Ma đạo, xem đó là cơ hội liều mạng trước Tán Ma. Chương xác nhận Vạn Huyễn Thiên Ma đạo của Liễu Mi là lý do hắn thu nàng làm đệ tử để ngày sau cắn nuốt.","nguon":["@c0642"]},{"id":"thien-ma-dao","name":"Thiên Ma đạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông ý cảnh","phamCap":"Truyền thừa Tiên nhân Huyễn gia","hePhai":"Huyễn gia","soHuu":["Huyễn gia"],"blurb":"Một trong hai bộ thần thông ý cảnh do vị Tiên nhân Huyễn gia lưu lại.","detail":"Thiên Ma đạo cùng Vô Tướng đạo được tách ra từ cảm ngộ Vô Tướng Thiên Ma đạo. Chương cho biết môn này tu luyện quá khó, trong tộc Huyễn gia chưa ai chân chính luyện thành.","nguon":["@c0642"]},{"id":"vo-tuong-dao","name":"Vô Tướng đạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông ý cảnh","phamCap":"Truyền thừa Tiên nhân Huyễn gia","hePhai":"Huyễn gia","soHuu":["Huyễn gia"],"blurb":"Một trong hai bộ thần thông ý cảnh của truyền thừa Huyễn gia.","detail":"Vô Tướng đạo cùng Thiên Ma đạo vốn phân ra từ Vô Tướng Thiên Ma đạo do tổ tiên Huyễn gia cảm ngộ. Hai bộ đạo pháp này là nền tảng để Huyễn Vô Tình mưu cầu hợp nhất ý cảnh.","nguon":["@c0642"]},{"id":"thien-huyen-vo-tinh-dao","name":"Thiên Huyễn Vô Tình đạo","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Huyễn gia","soHuu":["Liễu Mi"],"blurb":"Thiên Huyễn Vô Tình đạo là đạo pháp Liễu Mi tu luyện. Công pháp này khiến nàng nhiều khi không phân rõ vô tình hay hữu tình mới là bản thân mình.","detail":"Trong chương 643, Thiên Huyễn Vô Tình đạo được nhắc như căn cơ tu luyện của Liễu Mi, liên quan trực tiếp tới ý cảnh bị Huyễn Vô Tình cắn nuốt để cưỡng ép sinh ra một tia Vô Tướng Thiên Ma.","nguon":["@c0643"]},{"id":"than-thong-loi-he","name":"Thần thông Lôi hệ","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Thần thông Lôi hệ được Vương Lâm dùng để trị oán khí trong thân thể Vương Bình. Lôi quang từ mi tâm hắn truyền qua tay, ép hắc khí trong người đứa trẻ ngưng tụ ra ngoài rồi bị bóp nát.","detail":"Trong đời sống ẩn cư tại thôn Lạc Nguyệt, Vương Lâm dùng thần thông Lôi hệ phối hợp với đan dược do Liễu Mi lưu lại để điều trị cho Vương Bình. Khi Vương Bình ngủ, lôi quang từ mi tâm Vương Lâm truyền vào thân thể đứa trẻ, khiến hắc khí bị ép ra khỏi mi tâm và tiêu tán, giúp sắc mặt Vương Bình dần có huyết sắc hơn.","nguon":["@c0644"]},{"id":"xua-tan-oan-khi","name":"Xua tan oán khí","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn Vương Lâm dùng trong đời sống phàm tục tại thôn Lạc Nguyệt để bảo hộ Vương Bình khỏi oán khí.","detail":"Trong mười năm sống như phàm nhân, Vương Lâm gần như không thi triển thần thông nào khác, chỉ ban đêm xua tan oán khí bên ngoài cho Vương Bình. Việc này cho thấy hắn vẫn âm thầm dùng năng lực tu sĩ để che chở con trong khi bản thân cố hòa vào đời thường.","nguon":["@c0645"]},{"id":"sinh-tu-luan-hoi","name":"Sinh tử luân hồi","cn":"","loai":"khac","loaiLabel":"Ý cảnh","phamCap":"Không rõ","hePhai":"Đạo tâm","soHuu":["Vương Lâm"],"blurb":"Cảm ngộ trọng yếu của Vương Lâm khi sống đời phụ tử cùng Vương Bình ở thôn Lạc Nguyệt.","detail":"Qua nhiều năm quan sát Vương Bình trưởng thành và sống giữa sinh lão bệnh tử của phàm nhân, Vương Lâm sinh ra cảm ngộ sâu hơn về sinh tử luân hồi. Cảm ngộ này khiến đạo tâm vốn mệt mỏi của hắn dần thoát khỏi trạng thái cũ và trở thành nền tảng cho biến hóa ý cảnh về sau.","nguon":["@c0645"]},{"id":"nhan-qua-tuan-hoan","name":"Nhân quả tuần hoàn","cn":"","loai":"khac","loaiLabel":"Ý cảnh","phamCap":"Không rõ","hePhai":"Đạo tâm","soHuu":["Vương Lâm"],"blurb":"Hướng thăng hoa ý cảnh được nêu khi Vương Lâm hoàn thiện cảm ngộ sinh tử.","detail":"Chương chỉ ra hoàn thiện sinh tử là nhân quả tuần hoàn. Vương Lâm đã có dấu hiệu thăng hoa ý cảnh theo hướng nhân quả, nhưng do lý giải về “sinh” còn thiếu nên sự biến hóa chưa hoàn toàn thành tựu.","nguon":["@c0645"]},{"id":"y-canh-thang-hoa","name":"Ý cảnh thăng hoa","cn":"","loai":"khac","loaiLabel":"Đạo tâm","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm","Liễu Mi"],"blurb":"Biến hóa hiếm gặp của ý cảnh tu sĩ, được dùng để lý giải cơ duyên của Liễu Mi và trạng thái hiện tại của Vương Lâm.","detail":"Ý cảnh của tu sĩ thường gần như cố định, nên việc thăng hoa ý cảnh là biến hóa hiếm và quan trọng. Liễu Mi từng vì có dấu hiệu này mà được Huyễn Gia Lão Tổ coi trọng, còn Vương Lâm trong đời sống phàm tục cũng xuất hiện dấu hiệu tương tự từ cảm ngộ sinh tử và nhân quả.","nguon":["@c0645"]},{"id":"khau-quyet-tu-dao-ton-thai-truyen-cho-vuong-binh","name":"Khẩu quyết tu đạo Tôn Thái truyền cho Vương Bình","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Khẩu quyết tu đạo","phamCap":"không rõ","hePhai":"Tôn Thái truyền lại","soHuu":["Vương Bình","Tôn Thái"],"blurb":"Khẩu quyết tu đạo do Tôn Thái âm thầm truyền cho Vương Bình trong thời gian nhận hắn làm cháu nuôi. Vương Bình biết khẩu quyết này nhưng nói chưa từng tu luyện.","detail":"Tôn Thái mượn danh nghĩa nhận Vương Bình làm cháu nuôi để âm thầm truyền pháp thuật và khẩu quyết tu đạo cho hắn. Vương Lâm biết việc này bằng thần thông của mình, nhưng vẫn kiên quyết cấm Vương Bình tiếp tục bước vào con đường tu đạo.","nguon":["@c0646"]},{"id":"hu-anh-bao-ho-sau-lung-vuong-binh","name":"Hư ảnh bảo hộ sau lưng Vương Bình","aliases":["Hư ảnh sau lưng Vương Bình"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông bảo hộ","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm","Vương Bình"],"blurb":"Thủ đoạn bảo hộ do Vương Lâm trao cho Vương Bình tại Vương Phủ. Hư ảnh dung nhập sau lưng Vương Bình, trở thành chỗ dựa để hắn hành sự trên Nhiễm Vân tinh.","detail":"Khi Vương Bình muốn tự mình trở thành chí tôn trong phàm nhân, Vương Lâm chấp thuận và vung tay để hư ảnh phía sau xuất hiện, dung nhập vào sau lưng con. Vương Lâm nói mang theo vật này thì ở Nhiễm Vân tinh, Vương Bình có thể làm được hết thảy.","nguon":["@c0650"]},{"id":"y-canh-tinh-yeu-khong-hoi-han","name":"Ý cảnh tình yêu không hối hận","cn":"","loai":"khac","loaiLabel":"Ý cảnh","phamCap":"không rõ","hePhai":"","soHuu":["Thanh Nghi"],"blurb":"Ý cảnh mà Thanh Nghi cảm ngộ khi ở bên Vương Bình, gắn với tình yêu không hối hận.","detail":"Hai mươi năm trước, Thanh Nghi ở bên Vương Bình mà cảm ngộ thiên đạo, đạt được ý cảnh lấy tình yêu không hối hận làm cốt lõi. Ý cảnh này đi cùng lựa chọn của nàng: xem tu vi như bụi bặm, không muốn làm thần tiên vô tình mà muốn làm người thường có tình.","nguon":["@c0654"]},{"id":"than-thuc-loi-dao-tu","name":"Thần thức Lôi Đạo Tử","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông / thần thức","phamCap":"Không rõ","hePhai":"Lôi hệ","soHuu":["Lôi Đạo Tử"],"blurb":"Thần thức mang lôi uy của Lôi Đạo Tử, từng bao trùm toàn bộ Nhiễm Vân tinh trong chớp mắt.","detail":"Khi Lôi Đạo Tử cưỡi lôi thú đến Nhiễm Vân tinh, thần thức này quét ngang toàn tinh, khiến tu sĩ chấn động tinh thần, yêu vật run rẩy và phàm nhân hôn mê. Sau đó hắn tập trung thần thức vào thôn nhỏ trong núi nơi Vương Bình ở, mở đầu biến cố trực tiếp với Vương Bình và Thanh Nghi.","nguon":["@c0655"]},{"id":"loi-quang-loi-dao-tu","name":"Lôi quang Lôi Đạo Tử","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Lôi pháp","phamCap":"Không rõ","hePhai":"Lôi hệ","soHuu":["Lôi Đạo Tử"],"blurb":"Lôi quang quanh thân Lôi Đạo Tử, dùng trong đối kháng và phá hủy.","detail":"Lôi Đạo Tử dùng lôi quang quanh thân để đỡ quyền của tiên vệ khôi lỗi. Sau đó hắn gom điện quang vào chân giẫm xuống, làm căn phòng nơi Vương Bình và Thanh Nghi ở tan biến, đồng thời tạo vòng lôi quang lan ra bốn phía.","nguon":["@c0655"]},{"id":"thien-dia-chi-loi-thu","name":"Thiên địa chi lôi, thu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi hệ","soHuu":["Lôi Đạo Tử"],"blurb":"Pháp quyết thu lôi Lôi Đạo Tử thi triển cùng thiết côn khắc phù để dẫn lôi lực của Vương Lâm.","detail":"Trong giao chiến tại bình nguyên phía tây Nhiễm Vân tinh, Lôi Đạo Tử cắm thiết côn xuống đất, bấm quyết và hô thu thiên địa chi lôi, muốn dùng pháp bảo thu nạp lôi cầu của Vương Lâm. Lôi lực quá mạnh khiến thiết côn rạn nứt rồi sụp đổ, pháp quyết không thể xoay chuyển thế trận.","nguon":["@c0656"]},{"id":"y-canh-loi-uy","name":"Ý cảnh lôi uy","cn":"","loai":"than-thong","loaiLabel":"Ý cảnh","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ý cảnh liên quan lôi uy nằm trong nguyên thần Vương Lâm. Ở chương này, nó được nhắc như một phần sức mạnh chưa phóng xuất khi Lôi Đạo Tử quan sát hắn.","detail":"Trong lúc Lôi Đạo Tử dò xét Vương Lâm, chương cho biết nguyên thần Vương Lâm còn có lôi uy chưa được phóng xuất. Tầng ý cảnh này góp phần làm nền cho năng lực lôi hệ vượt thường của hắn trong trận chiến.","nguon":["@c0657"]},{"id":"loi-chi-tien-thu","name":"Lôi chi tiên thú","cn":"","loai":"than-thong","loaiLabel":"Thần thông triệu hồi","phamCap":"Lôi Tiên Điện","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Thần thông triệu hồi lôi thú của Lôi Đạo Tử. Lôi quang khắp trời ngưng tụ thành lôi cầu rồi hóa thành lôi thú bất phàm.","detail":"Lôi Đạo Tử chỉ trời thi triển Lôi chi tiên thú, khiến lôi quang trên không trung tụ lại thành lôi cầu rồi hóa thành lôi thú của Lôi Tiên Điện. Tiếng sấm từ thần thông này làm tu sĩ trên Nhiễm Vân tinh chấn động tâm thần và linh lực hỗn loạn.","nguon":["@c0657"]},{"id":"loi-tien-kiep","name":"Lôi tiên kiếp","cn":"","loai":"than-thong","loaiLabel":"Lôi hệ thần thông","phamCap":"Không rõ","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Lôi hệ thần thông của Lôi Đạo Tử, ngưng tia chớp tím thành hàng rào điện quang. Chiêu này bị bảy phù văn lôi của Vương Lâm phá tan.","detail":"Lôi Đạo Tử dùng Lôi tiên kiếp trong trận đấu với Vương Lâm, đưa tử lôi trên tay thành điện quang lao tới. Bảy phù văn lôi do Vương Lâm vẽ bằng tiên bút phá vỡ tử lôi, khiến Lôi Đạo Tử phun máu lùi xa.","nguon":["@c0657"]},{"id":"bay-phu-van-loi-bang-tien-but","name":"Bảy phù văn lôi bằng tiên bút","cn":"","loai":"than-thong","loaiLabel":"Phù văn lôi pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm thi triển bằng tiên bút màu vàng. Bảy bút họa dung nhập nguyên thần, hóa thành lôi quang trắng mang thiên lôi thái cổ.","detail":"Vương Lâm dùng tiên bút vẽ bảy phù văn, mỗi nét đều dung nhập một phần nguyên thần đã biến dị sau khi thôn phệ nửa Thái Cổ Lôi Long. Khi hoàn thành, phù văn từ kim quang hóa thành lôi quang trắng, phá tan Lôi tiên kiếp và làm Lôi Đạo Tử lần đầu thua trên phương diện lôi điện thần thông.","nguon":["@c0657"]},{"id":"thien-loi-thai-co-loi-uy-thai-co-loi-long","name":"Thiên lôi thái cổ / lôi uy Thái Cổ Lôi Long","cn":"","loai":"than-thong","loaiLabel":"Lôi uy","phamCap":"Thái cổ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lôi uy bắt nguồn từ nguyên thần Vương Lâm sau khi thôn phệ nửa Thái Cổ Lôi Long. Nó khiến lôi hệ thần thông trên thế gian khó thương tổn được hắn.","detail":"Chương nhấn mạnh nguyên thần Vương Lâm đã biến dị vì từng thôn phệ nửa Thái Cổ Lôi Long, khiến phù văn lôi hắn vẽ mang khí tức thiên lôi thái cổ. Lôi uy này áp chế Lôi tiên kiếp của Lôi Đạo Tử và đặt Vương Lâm vào vị thế vượt trội trong lôi pháp.","nguon":["@c0657"]},{"id":"nguyen-luc-phap-thuat-buoc-thu-hai","name":"Nguyên lực pháp thuật bước thứ hai","cn":"","loai":"than-thong","loaiLabel":"Nguyên lực thần thông","phamCap":"Bước thứ hai","hePhai":"","soHuu":["Lôi Đạo Tử"],"blurb":"Pháp thuật dựa trên nguyên lực thiên địa của tu sĩ bước thứ hai. Lôi Đạo Tử dùng nó để uy hiếp Vương Lâm sau khi lôi hệ thần thông bị áp chế.","detail":"Sau khi bị bảy phù văn lôi đánh lui nhưng nhanh chóng khôi phục nhờ tiên lực và một tia nguyên lực thiên địa, Lôi Đạo Tử tuyên bố sẽ thi triển nguyên lực pháp thuật chỉ tu sĩ bước thứ hai mới tu luyện được. Vương Lâm không lùi mà muốn tự mình nếm thử nguyên lực thần thông của Âm Hư tu sĩ.","nguon":["@c0657"]},{"id":"than-thong-hai-mat","name":"Thần thông hai mắt","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Thần thông Lôi Đạo Tử vận dụng ở hai mắt để nhìn thấu bí mật của mục tiêu.","detail":"Trong trận với Vương Lâm, Lôi Đạo Tử lần đầu thi triển thần thông này ở hai mắt để quan sát Vương Bình, qua đó nhận ra Vương Bình không phải phàm nhân mà là oán anh và phát hiện hai đạo kiếm khí đáng sợ trong thân thể đối phương.","nguon":["@c0658"]},{"id":"nguyen-luc-loi-dinh","name":"Nguyên lực lôi đỉnh","aliases":["Nguyên lực lôi đỉnh của Lôi Đạo Tử"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Nguyên lực thần thông bước thứ hai","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Nguyên lực thần thông của Lôi Đạo Tử, biến thiên địa thành cự đỉnh màu lam để luyện hóa đối thủ.","detail":"Khi bị Trảm La quyết uy hiếp sinh tử, Lôi Đạo Tử điểm mi tâm, dẫn nguyên lực thiên địa từ thiên linh cái, khiến trời thành miệng đỉnh, đất thành thân đỉnh. Trong đại đỉnh, lôi điện mang thần thông và đạo niệm liên tục đánh xuống, buộc Vương Lâm, Tiên vệ khôi lỗi và lôi thú phải cùng phá đỉnh.","nguon":["@c0658"]},{"id":"dao-niem-than-loi","name":"Đạo niệm thần lôi","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Lôi điện trong Nguyên lực lôi đỉnh, do ý niệm và đạo niệm của Lôi Đạo Tử biến thành.","detail":"Bên trong lôi đỉnh, từng đạo lôi điện không chỉ là thần thông mà còn chứa đạo niệm của Lôi Đạo Tử. Chúng liên tục oanh kích Vương Lâm, khiến thân hình hắn chấn động nhưng không đánh tan được nguyên thần biến dị của hắn như với tu sĩ Vấn Đỉnh thông thường.","nguon":["@c0658"]},{"id":"tram-la-quyet","name":"Trảm La quyết","aliases":["Trảm La"],"cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông kiếm quyết được Vương Lâm thi triển liên tiếp trong trận với Lôi Đạo Tử. Khi phối hợp lôi thú và Tiên vệ, nó trực tiếp góp phần phá vỡ đại đỉnh lôi hỏa.","detail":"Trong chương này, Vương Lâm nhớ lời Huyễn gia lão tổ từng nói về uy lực Trảm La khi đạt bước thứ hai, rồi dùng hai ngón tay làm kiếm thi triển Trảm La lần nữa. Do nguyên lực không đủ, việc thi triển liên tiếp khiến nguyên lực nguyên thần gần cạn và cảnh giới có dấu hiệu dao động, nhưng vẫn góp phần quyết định làm đại đỉnh sụp đổ.","nguon":["@c0659"]},{"id":"dao-phong-an-thu-ba-cua-loi-thu","name":"Đạo phong ấn thứ ba của lôi thú","cn":"","loai":"bi-thuat","loaiLabel":"Phong ấn linh thú","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Vương Lâm","Xạ Thần Xa"],"blurb":"Đạo phong ấn được Vương Lâm dùng máu vẽ phù văn để mở trên lôi thú. Sau khi mở, lôi thú phóng ra lôi điện màu đen và khí tức nghịch thiên.","detail":"Vương Lâm thu hồi đại kiếm, dùng máu tươi vẽ phù văn tang thương rồi ấn vào mi tâm lôi thú để mở đạo phong ấn thứ ba. Biến hóa này khiến lôi quang của lôi thú từ ngân sắc hóa thành màu đen, khí tức giống tổ tiên viễn cổ áp đảo lôi thú Lôi Tiên Điện.","nguon":["@c0659"]},{"id":"tien-y-phap-thuat-duy-tri-vuong-binh","name":"Tiên ý pháp thuật duy trì Vương Bình","cn":"","loai":"khac","loaiLabel":"Pháp thuật","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Pháp thuật duy trì quá trình tồn tại và trưởng thành của Vương Bình trong hơn bảy mươi năm. Nó khiến một tia hồn phách và kiếm khí có thể đi qua một đời phàm tục.","detail":"Chân tướng được hé lộ rằng Vương Bình không sinh trưởng như thân thể bình thường: thân thể do kiếm khí hóa thành, oan hồn được kiếm khí khác thủ hộ, còn hơn bảy mươi năm trưởng thành là do tiên ý pháp thuật của Vương Lâm duy trì.","nguon":["@c0659"]},{"id":"am-duong-hu-thuc-canh-gioi","name":"Âm Dương Hư Thực cảnh giới","cn":"","loai":"khac","loaiLabel":"Cảnh giới bước thứ hai","phamCap":"bước thứ hai","hePhai":"","soHuu":[],"blurb":"Cảnh giới bước thứ hai được Vương Lâm dùng để tự đánh giá giới hạn chiến lực sau khi tăng tiến tu vi và ý cảnh.","detail":"Vương Lâm nhận định tu sĩ Âm Hư có thể chiến thắng nhưng cực kỳ gian nan và hao nguyên lực, còn gặp Dương Thực thì không thể địch và chỉ có thể trốn. Đánh giá này khiến hắn đặt trọng tâm vào tiên ngọc và thiên địa nguyên lực.","nguon":["@c0660"]},{"id":"thien-dia-nguyen-luc","name":"Thiên địa nguyên lực","cn":"","loai":"khac","loaiLabel":"Nguồn lực tu sĩ bước thứ hai","phamCap":"bước thứ hai","hePhai":"","soHuu":["Vương Lâm","Lôi Đạo Tử"],"blurb":"Nguồn lực then chốt của tu sĩ bước thứ hai, được nhấn mạnh trong cuộc đối đầu giữa Vương Lâm và Lôi Đạo Tử.","detail":"Lôi Đạo Tử vì nguyên lực gần cạn nên không dám tùy tiện thi triển pháp thuật mạnh. Vương Lâm sau khi tự xét khoảng cách với tu sĩ Âm Dương Hư Thực cũng coi việc tăng thiên địa nguyên lực là chuyện trọng yếu.","nguon":["@c0660"]},{"id":"loi-mac","name":"Lôi mạc","cn":"","loai":"than-thong","loaiLabel":"Phòng ngự lôi pháp","phamCap":"","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Màn lôi phòng ngự do Lôi Đạo Tử tạo ra để chống lại vòng vây của Vương Lâm.","detail":"Lôi Đạo Tử bóp nát ngọc giản lôi quang, hóa thành màn lôi bao quanh thân thể. Lôi mạc chống đỡ Thất Tinh kiếm trận, tiên vệ khôi lỗi, lôi thú và các chủ hồn trong Tôn Hồn Phiên trước khi hắn bị ép phải tản phòng ngự.","nguon":["@c0660"]},{"id":"ba-chung-cuc-chu-hon","name":"Ba chung cực chủ hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông Tôn Hồn Phiên","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ba chủ hồn cực mạnh do hồn phách trong Tôn Hồn Phiên dung hợp tạo thành.","detail":"Trong trận vây Lôi Đạo Tử, vô số hồn phách trong Tôn Hồn Phiên dung hợp thành kỳ lân hắc khí, người khổng lồ hắc khí và châm đen vô hình. Đây là thế công mạnh nhất mà Vương Lâm bày ra từ Tôn Hồn Phiên lúc này, phối hợp tiên vệ, lôi thú và kiếm trận công phá lôi mạc.","nguon":["@c0660"]},{"id":"than-thong-bao-menh-cua-loi-tien-dien-su-gia","name":"Thần thông bảo mệnh của Lôi Tiên Điện sứ giả","cn":"","loai":"than-thong","loaiLabel":"Thần thông bảo mệnh","phamCap":"","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Thần thông bảo mệnh mà Lôi Đạo Tử dùng để uy hiếp khi bị vây ép.","detail":"Lôi Đạo Tử nói mỗi sứ giả Lôi Tiên Điện đều có thần thông bảo mệnh. Trong tình trạng nguyên lực thiếu hụt, nếu thi triển thì phải hi sinh thọ nguyên và có thể khiến tu vi tụt xuống, nên hắn không chắc có thể giết được Vương Lâm.","nguon":["@c0660"]},{"id":"cam-che-khong-che-nguyen-than","name":"Cấm chế khống chế nguyên thần","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Cấm chế do Vương Lâm dùng Cấm Phiên tạo ra để khống chế nguyên thần Lôi Đạo Tử.","detail":"Vương Lâm dùng Cấm Phiên phóng ra tổ hợp cấm chế như tinh quang, nhập vào mi tâm Lôi Đạo Tử, xuyên qua kinh mạch tới nguyên thần rồi hóa thành võng cấm chế bao vây. Lôi Đạo Tử ngoài mặt chịu khống chế nhưng tin rằng sau khi nguyên lực khôi phục sẽ phá được.","nguon":["@c0660"]},{"id":"luyen-che-tien-ve","name":"Luyện chế tiên vệ","cn":"","loai":"bi-thuat","loaiLabel":"Bí pháp luyện khôi lỗi","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Bí pháp Vương Lâm định dùng để biến Lôi Đạo Tử thành tiên vệ thứ hai.","detail":"Vương Lâm quyết định luyện Lôi Đạo Tử thành tiên vệ để triệt để yên tâm, vì đối phương phù hợp điều kiện luyện chế. Hắn còn tính đến việc kết hợp lôi thú bên ngoài nhằm tăng xác suất thành công.","nguon":["@c0660"]},{"id":"nguyen-than-khi","name":"Nguyên thần khí","cn":"","loai":"khac","loaiLabel":"Thuật pháp phụ trợ luyện chế","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Khí nguyên thần Vương Lâm phun ra để mở màn quá trình luyện hóa Lôi Đạo Tử.","detail":"Trong động phủ trên tinh cầu xám, Vương Lâm phun nguyên thần khí hóa thành vô số phù văn rơi lên người Lôi Đạo Tử. Đây là bước phụ trợ trước khi hắn dùng Côn Cực Tiên rút nguyên thần đối phương.","nguon":["@c0660"]},{"id":"cam-che-dien-quang","name":"Cấm chế điện quang","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Cấm chế Vương Lâm hạ sẵn trên nguyên thần Lôi Đạo Tử để khóa chặt đối phương khi phản kháng.","detail":"Khi Lôi Đạo Tử vừa muốn phản kháng, cấm chế trên nguyên thần lập tức bùng phát thành lưới điện quang, phối hợp tiên vệ khôi lỗi, lôi thú, chủ hồn và kiếm trận khiến nguyên thần hắn không thể thoát về thân thể.","nguon":["@c0661"]},{"id":"dinh-hoa-thien-dia","name":"Đỉnh Hóa Thiên Địa","aliases":["Nguyên lực lôi đỉnh","Đại đỉnh lôi hỏa của Lôi Đạo Tử"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Yêu cầu tu vi ít nhất Âm Hư","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử","Vương Lâm"],"blurb":"Thần thông lôi hệ ghi trong ngọc giản của Lôi Đạo Tử. Thuật này lấy đạo niệm bản thân ngưng hóa thành đỉnh, dung hợp ý thiên địa và nguyên lực bản thân.","detail":"Vương Lâm nhận ra đây là thuật Lôi Đạo Tử từng thi triển. Nội dung trong ngọc giản cho thấy người tu luyện phải có tu vi ít nhất Âm Hư mới có thể vận dụng, vì thuật liên quan đến đạo niệm, ý thiên địa và nguyên lực bản thân.","nguon":["@c0662"]},{"id":"loi-nguyen-thuat","name":"Lôi Nguyên Thuật","cn":"","loai":"cong-phap","loaiLabel":"Tiên thuật thiếu","phamCap":"Bản thiếu hạ phẩm tiên thuật","hePhai":"Lôi Tiên Điện","soHuu":["Vương Lâm"],"blurb":"Bản thiếu hạ phẩm tiên thuật dùng thiên lôi để hấp thu nguyên lực thiên địa vào cơ thể. Với nguyên thần lôi của Vương Lâm, thuật này có giá trị đặc biệt lớn.","detail":"Lôi Nguyên Thuật hấp thu nguyên lực thiên địa ẩn trong thiên lôi để tăng tốc ngưng tụ nguyên lực, giảm thời gian đình trệ ở cảnh giới Âm Dương Hư Thực. Tu sĩ bước đầu tiên thường khó chịu nổi thiên lôi nhập thể, nhưng Vương Lâm từng có lôi uy Thái Cổ trong nguyên thần nên cực kỳ coi trọng thuật này.","nguon":["@c0662","@c0686"]},{"id":"loi-uy-trong-ngoc-gian","name":"Lôi uy trong ngọc giản","cn":"","loai":"than-thong","loaiLabel":"Cấm chế lôi hệ","phamCap":"Có thể cản một số tu sĩ bước thứ hai","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Lớp lôi quang ngăn thần thức trong ngọc giản khắc lôi thú. Nó mang một tia thiên địa lôi uy nhưng bị Vương Lâm phá bỏ nhờ lôi uy Thái Cổ trong nguyên thần.","detail":"Khi Vương Lâm dùng thần thức xem xét ngọc giản, lôi quang trong đó tạo thành trở ngại. Nhờ nguyên thần từng nuốt nửa Thái Cổ Thần Long và có lôi uy Thái Cổ, hắn phá được lớp cấm chế này để thấy hai thần thông bên trong.","nguon":["@c0662"]},{"id":"tu-dao-ba-buoc","name":"Tu đạo bước đầu tiên / bước thứ hai / bước thứ ba","cn":"","loai":"khac","loaiLabel":"Hệ thống tu đạo","phamCap":"không rõ","hePhai":"Tu đạo","soHuu":["Vương Lâm"],"blurb":"Hệ thống tu đạo được Vương Lâm suy ngẫm sau khi đạt Vấn Đỉnh hậu kỳ.","detail":"Vương Lâm nhìn lại bước đầu tiên của tu đạo, nhận ra bước thứ hai còn gian nan hơn, còn bước thứ ba thì hư vô mờ mịt đến mức những nhân vật như Thiên Vận Tử cũng chưa đạt tới.","nguon":["@c0664"]},{"id":"tu-dao-buoc-thu-tu","name":"Tu đạo bước thứ tư","cn":"","loai":"khac","loaiLabel":"Khái niệm tu đạo","phamCap":"không rõ","hePhai":"Tu đạo","soHuu":["Vương Lâm"],"blurb":"Câu hỏi về một cảnh giới hoặc tầng nhận thức vượt ngoài ba bước tu đạo.","detail":"Khi cưỡi lôi thú trong tinh không, Vương Lâm đặt vấn đề liệu sau ba bước tu đạo còn tồn tại bước thứ tư hay không. Chương nêu rõ không ai trong thế giới này có thể trả lời hắn.","nguon":["@c0664"]},{"id":"than-thong-loi-thu","name":"Thần thông lôi thú","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Lôi thú"],"blurb":"Thần thông lôi hệ của lôi thú ngân sừng khi tiến vào Thiên Huyễn Tinh.","detail":"Lôi thú kéo lôi vân và lôi đình giáng xuống khi xuất hiện trên Thiên Huyễn Tinh, tạo lôi uy khiến nhiều tu sĩ chấn động và càng làm Vương Lâm giống sứ giả Lôi Tiên Điện.","nguon":["@c0664"]},{"id":"than-thong-chay-tron-cua-lao-gia-yeu-linh","name":"Thần thông chạy trốn của lão giả vùng đất Yêu Linh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chưa rõ","hePhai":"chưa rõ","soHuu":["lão giả vùng đất Yêu Linh","Vương Lâm"],"blurb":"Thần thông đào tẩu của một lão giả từng khiến Vương Lâm chú ý ở vùng đất Yêu Linh.","detail":"Trên đường tới Vân Hà Tinh, Vương Lâm rút hồn phách lão giả trong Tôn Hồn Phiên để tra xét và ghi nhớ phương pháp chạy trốn này.","nguon":["@c0666"]},{"id":"hong-vu-thang-tien-qua","name":"Hồng vụ Thăng Tiên quả","cn":"","loai":"bi-thuat","loaiLabel":"Pháp thuật luyện hóa","phamCap":"chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Cách Vương Lâm luyện Thăng Tiên quả thành hồng vụ để gây tê xúc tu Vọng Nguyệt.","detail":"Hắn nghiền Thăng Tiên quả thành chất lỏng rồi dùng nguyên thần khí đốt thành hồng vụ, khiến xúc tu hấp thu, chậm lại và tạm nới lỏng.","nguon":["@c0666"]},{"id":"lac-an-thang-tien-qua","name":"Lạc ấn Thăng Tiên quả","cn":"","loai":"bi-thuat","loaiLabel":"Phong ấn khống chế","phamCap":"chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Ấn ký Vương Lâm đặt trong chất lỏng Thăng Tiên quả để ảnh hưởng gốc xúc tu Vọng Nguyệt.","detail":"Dựa vào tri thức Cổ Thần Đồ Ti về điểm hưng phấn của Vọng Nguyệt, Vương Lâm dung nhập chất lỏng có lạc ấn vào từng gốc xúc tu, dự định kích hoạt bằng tâm niệm.","nguon":["@c0666"]},{"id":"dai-than-thong-thuat-chua-ro","name":"Đại thần thông thuật chưa rõ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chưa rõ","hePhai":"chưa rõ","soHuu":[],"blurb":"Dấu vết thần thông được Vương Lâm suy đoán từng xuất hiện trong thân thể Vọng Nguyệt.","detail":"Dao động tiên lực bất thường trong niêm dịch khiến Vương Lâm cho rằng có người từng vào bên trong Vọng Nguyệt và thi triển đại thần thông, dẫn tới biến hóa trạng thái của hung thú.","nguon":["@c0666"]},{"id":"dao-hoa-hoang-tuyen-de-tam-thuc","name":"Đạo hóa Hoàng Tuyền đệ tam thức","aliases":["Hoàng Tuyền lực","Hoàng Tuyền đệ tam thức"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"đạo hóa","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Đệ tam thức trong Đạo hóa Hoàng Tuyền, được Vương Lâm dùng dưới dạng Hoàng Tuyền lực để rút xương Vọng Nguyệt.","detail":"Khi thi triển, Hoàng Tuyền hóa thành hai luồng như hoàng long bám theo hai bên xương cốt, tạo lực hút và lực bóc kéo để rút cốt khỏi thân thể Vọng Nguyệt.","nguon":["@c0668"]},{"id":"rut-cot","name":"Rút cốt","cn":"","loai":"than-thong","loaiLabel":"Ứng dụng thần thông","phamCap":"chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Ứng dụng Hoàng Tuyền lực nhằm bóc kéo xương cốt Vọng Nguyệt khỏi thân thể.","detail":"Vương Lâm áp hai tay vào hai đầu xương gãy, dùng Hoàng Tuyền lực làm dao róc dọc xương và quát lệnh rút cốt.","nguon":["@c0668"]},{"id":"tien-luc","name":"Tiên lực","cn":"","loai":"khac","loaiLabel":"Lực lượng tu vi","phamCap":"theo tu vi người dùng","hePhai":"tu sĩ","soHuu":["Vương Lâm"],"blurb":"Lực lượng tu vi được Vương Lâm vận chuyển đến cực hạn khi kéo xương sống Vọng Nguyệt.","detail":"Khi tiên lực toàn thân bùng phát, gân xanh và phù văn nổi lên trên hai tay Vương Lâm, giúp hắn từng chút kéo nửa đoạn xương sống khổng lồ ra khỏi thân thể Vọng Nguyệt.","nguon":["@c0669"]},{"id":"mo-phong-co-than-luyen-hoa-tien-ve","name":"Mô phỏng Cổ Thần luyện hóa Tiên Vệ","cn":"","loai":"luyen-the","loaiLabel":"Phương thức luyện hóa khôi lỗi","phamCap":"chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm","Tiên Vệ"],"blurb":"Cách luyện hóa khiến Tiên Vệ có thân thể và lực lượng mạnh mẽ giống mô phỏng Cổ Thần.","detail":"Nhờ phương thức này, Tiên Vệ có lực lượng vượt xa Vương Lâm ở thời điểm hiện tại và đủ sức kéo nửa đoạn xương sống Vọng Nguyệt.","nguon":["@c0669"]},{"id":"tieng-noi-co-than","name":"Tiếng nói Cổ Thần","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Truyền thừa Cổ Thần","hePhai":"Cổ Thần","soHuu":["Vọng Nguyệt","Vương Lâm","Đồ Ti"],"blurb":"Âm thanh truyền thừa của Cổ Thần, được Vọng Nguyệt phát ra trong lúc truy sát và được Vương Lâm dùng để đáp lại. Việc Vọng Nguyệt biết loại tiếng nói này khiến Vương Lâm nghi hoặc về bản chất của nó.","detail":"Trong chương 670, Vọng Nguyệt phát ra âm thanh mà Vương Lâm nhận ra là tiếng nói Cổ Thần, điều không có trong ký ức Đồ Ti về Vọng Nguyệt. Khi bầu trời nứt vỡ vì thần thông phá nát, Vương Lâm xoay người phát ra tiếng nói Cổ Thần truyền thừa từ Đồ Ti, khiến khe nứt và thế sụp đổ tạm ngừng.","nguon":["@c0670"]},{"id":"ky-thuat-pha-nat-cua-bat-tinh-co-than","name":"Kỹ thuật phá nát của Bát Tinh Cổ Thần","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bát Tinh Cổ Thần","hePhai":"Cổ Thần","soHuu":["Vọng Nguyệt"],"blurb":"Thần thông phá nát mà Vương Lâm nhận ra là năng lực chỉ Bát Tinh Cổ Thần mới thi triển được. Trong chương này, nó khiến bầu trời bốn phía nứt vỡ, đẩy Vương Lâm vào nguy cơ sinh tử.","detail":"Tiếng nói Cổ Thần của Vọng Nguyệt làm bầu trời quanh Vương Lâm xuất hiện vô số khe nứt như sắp sụp đổ. Vương Lâm nhận ra đây là kỹ thuật phá nát của Bát Tinh Cổ Thần, một loại thần thông có thể khiến vật bị nhìn thấy tan vỡ thành tro bụi.","nguon":["@c0670"]},{"id":"ngon-xuat-phap-tuy","name":"Ngôn xuất pháp tùy","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Hiệu ứng lời nói hóa thành uy lực, được dùng để mô tả tiếng quát của Vương Lâm khi gọi Thất Tinh Kiếm Trận trở về. Âm thanh hóa thành nhiều tia sấm sét phóng vào kiếm trận.","detail":"Khi Vương Lâm gầm gọi Thất Tinh Kiếm Trận trong khe nứt của Vọng Nguyệt, giọng quát của hắn được ví như ngôn xuất pháp tùy. Lời nói hóa thành nhiều sấm sét, dẫn động kiếm trận trở lại để hắn ra lệnh tự bạo.","nguon":["@c0670"]},{"id":"dinh-than-thuat","name":"Định Thân Thuật","cn":"","aliases":["Định thân thuật","Định","Thuật định thân","Tiên thuật định thân"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Thần thông định thân được Vương Lâm dùng khi tiên lực bùng phát nhờ tiên tửu.","detail":"Trong lúc bị Vọng Nguyệt truy sát, Vương Lâm uống hai giọt tiên tửu còn lại rồi thi triển Định Thân Thuật, khiến trời đất như ngừng vận chuyển trong chốc lát. Thuật này tạm khóa đàn Vọng Nguyệt nhỏ và sau đó khóa Tham Lang, nhưng không ảnh hưởng tới bản thể Vọng Nguyệt khổng lồ.","nguon":["@c0672","@c0753","@c0757"]},{"id":"than-thong-doi-vi-tri-cua-cu-dinh","name":"Thần thông đổi vị trí của cự đỉnh","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông pháp bảo","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Tham Lang"],"blurb":"Thần thông do Tham Lang kích phát thông qua Cự Đỉnh để đổi vị trí với mục tiêu khác.","detail":"Tham Lang phun máu lên Cự Đỉnh để kích hoạt sóng tròn, đổi vị trí với một Vọng Nguyệt nhỏ đang lao nhanh nhất. Hắn định tiếp tục đổi chỗ với Vương Lâm nhưng bị Định Thân Thuật chặn lại.","nguon":["@c0672"]},{"id":"co-than-chi","name":"Cổ Thần Chỉ","cn":"","aliases":["Một chỉ Cổ Thần","Một chỉ của Cổ Thần do Vọng Nguyệt huyễn hóa"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Uy năng Cổ Thần","hePhai":"Cổ Thần","soHuu":["Vọng Nguyệt"],"blurb":"Uy năng một chỉ được Vọng Nguyệt huyễn hóa khi rơi vào trạng thái phẫn nộ.","detail":"Khi ký hiệu ngôn ngữ Cổ Thần lóe lên trong mắt Vọng Nguyệt, một ngón tay hư ảo trăm trượng xuất hiện. Một chỉ này phá vỡ bình phong Sơn Hà Đồ và khiến Tham Lang phun máu nguyên thần, cho thấy uy áp vượt xa đạo niệm tu sĩ thông thường.","nguon":["@c0672","@c0782"]},{"id":"son-ha-do","name":"Sơn Hà Đồ","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Bình phong Sơn Hà Đồ","Vương Lâm"],"blurb":"Thần thông hiện trên bình phong trong tinh không. Vương Lâm nhận ra nó và mạo hiểm đoạt lấy giữa lúc Cổ Thần Chỉ truy đuổi Tham Lang.","detail":"Sơn Hà Đồ là thần thông gắn với bình phong trôi trong tinh không nơi Vọng Nguyệt thức tỉnh. Vương Lâm lợi dụng thời điểm Cổ Thần Chỉ chuyển hướng về Tham Lang, ôm bình phong thu vào túi trữ vật rồi rút lui.","nguon":["@c0673"]},{"id":"sinh-menh-lac-an","name":"Sinh Mệnh Lạc Ấn","cn":"","aliases":["Sinh Chi Lạc Ấn"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm","Tiên Vệ"],"blurb":"Ấn pháp phòng ngự được tạo từ hàng trăm vạn đạo sát lục khí trong Tiên Vệ. Nó bị Cổ Thần Chỉ nghiền nát như giấy mỏng.","detail":"Khi Cổ Thần Chỉ ép tới, Vương Lâm rút chuẩn bị trong Tiên Vệ, khiến hàng trăm vạn sát lục khí ngưng thành Sinh Mệnh Lạc Ấn để cản một chỉ. Lạc ấn nhanh chóng vỡ vụn, không thể ngăn uy lực của ngón tay Cổ Thần.","nguon":["@c0673"]},{"id":"thai-co-loi-long-nguyen-than","name":"Thái cổ Lôi Long nguyên thần","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Hình thái nguyên thần","phamCap":"không rõ","hePhai":"Lôi","soHuu":["Vương Lâm"],"blurb":"Hình thái nguyên thần của Vương Lâm sau khi lớp màng giam nguyên thần bị Cổ Thần Chỉ phá vỡ. Nguyên thần hóa thành thái cổ Lôi Long, tạo lôi cầu cản địch và bỏ chạy.","detail":"Một chỉ Cổ Thần phá hủy nhục thân Vương Lâm đồng thời phá lớp màng bao quanh nguyên thần, khiến nguyên thần bùng ra hóa thái cổ Lôi Long. Hình thái này gầm rống, tạo nhiều lôi cầu đánh về Cổ Thần Chỉ rồi cuốn đồ vật và đồng bạn đào thoát.","nguon":["@c0673"]},{"id":"nguyen-than-chi-loi","name":"Nguyên thần chi lôi","cn":"","aliases":[],"loai":"khac","loaiLabel":"Năng lực lôi hệ","phamCap":"","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Năng lực lôi hệ gắn với nguyên thần dị hóa thái cổ Lôi Long của Vương Lâm. Lôi quang tự nhiên trên tinh cầu lôi điện có đặc tính gần giống loại lôi này.","detail":"Khi tiến vào tiểu tinh cầu lôi quang, Vương Lâm nhận ra lôi điện nơi đây không phải do pháp thuật hay thần thông biến hóa mà là lôi tự nhiên do trời đất sinh ra. Đặc tính của nó rất giống nguyên thần chi lôi của hắn, đồng thời giải thích vì sao con rối Tiên Vệ tỏ ra e dè trước lôi quang nơi này.","nguon":["@c0674"]},{"id":"loi-tien-thien-loi-hau-thien","name":"Lôi tiên thiên / lôi hậu thiên","cn":"","aliases":["Lôi tiên thiên","Lôi hậu thiên"],"loai":"khac","loaiLabel":"Phân loại lôi lực","phamCap":"","hePhai":"Lôi hệ","soHuu":[],"blurb":"Cách phân biệt lôi lực theo nguồn gốc: lôi hậu thiên do thần thông biến hóa, còn lôi tiên thiên do trời đất tự sinh. Lôi quang trên tinh cầu lôi điện thuộc loại tiên thiên.","detail":"Vương Lâm quan sát phản ứng do dự hiếm thấy của Tiên Vệ trước lôi quang và nhận định lôi ở nơi này là tự nhiên, không phải do pháp thuật thần thông huyễn hóa. Hắn phân biệt lôi hậu thiên là lôi do thần thông tạo thành, còn lôi tiên thiên là lôi do trời đất sinh ra; loại lôi tiên thiên này gần với nguyên thần chi lôi của hắn và thích hợp để hắn chữa thương, ngưng luyện nguyên thần cùng thân thể.","nguon":["@c0674"]},{"id":"than-thong-rut-linh-hon-linh-vat","name":"Thần thông rút linh hồn linh vật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Liên quan cảnh giới Đệ Nhị Bộ","hePhai":"Không rõ","soHuu":["Tán Ma","Vương Lâm"],"blurb":"Thần thông rút linh hồn của tinh cầu, núi, sông và linh vật tương tự. Vương Lâm nhờ cảm ngộ từ Tán Ma và núi đá tiên giới mà thử chạm tới phương pháp này.","detail":"Chương này nêu rõ loại thần thông rút hồn linh vật là điều tu sĩ Đệ Nhị Bộ mới hiểu rõ. Vương Lâm từng có cảm ngộ khi Tán Ma rút Thiên Huyễn Tinh Hồn, nay dùng núi đá tiên giới của Tham Lang để thử kéo Sơn Hồn ra, nhưng khi mở rộng sang mặt đất thì bị phản lực chấn thương nhẹ.","nguon":["@c0675"]},{"id":"son-hon","name":"Sơn Hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Liên quan núi đá tiên giới","soHuu":["Vương Lâm","Tham Lang"],"blurb":"Linh hồn của núi đá tiên giới bị Vương Lâm rút ra thành quả cầu hư ảo. Bản này yếu hơn Sơn Hồn Tham Lang từng dùng nhưng vẫn tỏa khí tức cường đại.","detail":"Khi kiểm tra núi đá tiên giới bị hư hại, Vương Lâm dùng cảm ngộ rút hồn kéo ra một quả cầu hư ảo như sương mù. Quả cầu chứa tiên khí tổ hợp mạnh nhưng không ổn định vì bản thể núi đá đã bị tổn hại.","nguon":["@c0675"]},{"id":"than-thong-son-ha","name":"Thần thông Sơn Hà","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Sơn Hà Đồ","soHuu":["Tham Lang","Vương Lâm"],"blurb":"Thần thông do Sơn Hà Đồ hóa thành, gắn với hình tượng sơn hà trong pháp bảo. Chương này nhấn mạnh uy lực thật sự của Sơn Hà Đồ còn nằm ở nét bút vẽ bằng máu.","detail":"Khi Vương Lâm xem xét bình phong Sơn Hà Đồ, thần thông Sơn Hà được nhắc như năng lực pháp bảo có thể thi triển. Tuy vậy, điểm lợi hại chân chính của Sơn Hà Thiên Đạo Đồ không chỉ là hóa thành Sơn Hà, mà là truyền thuyết nét vẽ bằng máu của Thiên Đạo.","nguon":["@c0675"]},{"id":"phu-van-thien-nghich-vien-man","name":"Phù văn Thiên Nghịch viên mãn","cn":"","loai":"bi-thuat","loaiLabel":"Phù văn","phamCap":"Không rõ","hePhai":"Thiên Nghịch Châu","soHuu":["Vương Lâm"],"blurb":"Phù văn cổ xưa xuất hiện sau khi ngũ hành của Thiên Nghịch Châu viên mãn. Nó tỏa khí tức tang thương cực mạnh trong tâm thần và trước người Vương Lâm.","detail":"Sau khi thuộc tính kim của Thiên Nghịch đạt viên mãn, Vương Lâm nhỏ máu dung hợp thần thức lạc ấn lên hạt châu. Tâm thần hắn chấn động, phù văn tang thương hiện ra rồi được hắn vẽ trước người, khí tức cổ xưa vượt xa lần Tán Ma rút Thiên Huyễn Tinh Hồn.","nguon":["@c0675"]},{"id":"cam-che-tu-quang","name":"Cấm chế tử quang","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Thiên Nghịch dị biến","soHuu":[],"blurb":"Cấm chế hình thành trong vùng tử quang sau khi Hạt Châu Thiên Nghịch viên mãn. Nó bao phủ khu vực quanh cánh cửa tím và ngăn sinh linh tiến vào.","detail":"Khi tử quang lan rộng trên tinh cầu lôi quang và tầng đá ngoài, một tầng cấm chế cực mạnh hình thành trong phạm vi bao phủ. Vương Lâm chỉ nhìn đã bị chấn nhiếp; dưới cấm chế này, sinh linh không thể tiến vào khu vực đang bị tử quang cắt biệt.","nguon":["@c0676"]},{"id":"than-thong-cat-dut-khu-vuc-tu-quang","name":"Thần thông cắt đứt khu vực tử quang","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thiên Nghịch dị biến","soHuu":[],"blurb":"Sức mạnh dị thường khiến vùng tử quang như bị đào khỏi La Thiên Tinh Vực. Khu vực quanh tinh cầu lôi quang bị tách biệt khỏi ngoại giới.","detail":"Trong phạm vi tử quang, không gian tạo cảm giác bị một loại thần thông đào ra và cắt đứt khỏi mọi thứ xung quanh. Hiện tượng này đi kèm sự tan rã của đất đá, tầng bao ngoài và cấm chế mạnh ngăn sinh linh tiếp cận.","nguon":["@c0676"]},{"id":"loi-an","name":"Lôi ấn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Thủ ấn Lôi hệ do Vương Lâm thi triển khi vận chuyển Lôi Nguyên Thuật trong Lôi Trì.","detail":"Một lần bắt quyết của Vương Lâm thực chất gồm chín thủ ấn được thi triển cực nhanh, tạo thành hiệu quả giống Lôi ấn để dẫn động Lôi Đình nhập thể và hỗ trợ chuyển hóa nguyên lực.","nguon":["@c0678"]},{"id":"cam-che-ky-di-cua-thien-nghich","name":"Cấm chế kỳ dị của Thiên Nghịch","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Thiên Nghịch","soHuu":["Vương Lâm"],"blurb":"Cấm chế kỳ dị liên quan tới Thiên Nghịch, tái hiện khi hạt châu hấp thu lôi điện trong Lôi Trì.","detail":"Sau khi Thiên Nghịch hút lôi điện, tử quang bên trong hạt châu lóe lên rồi tản ra, kéo theo cấm chế kỳ dị và cánh cửa lớn từng xuất hiện trước đó giữa trời đất.","nguon":["@c0678"]},{"id":"dao-sinh-tu-luan-hoi","name":"Đạo sinh tử luân hồi","cn":"","aliases":[],"loai":"khac","loaiLabel":"Đạo cảnh / cảm ngộ","phamCap":"Không rõ","hePhai":"Đạo sinh tử","soHuu":["Vương Lâm"],"blurb":"Cảm ngộ Đạo của Vương Lâm qua vòng chuyển sinh tử, tử sinh trong không gian Thiên Nghịch.","detail":"Vương Lâm quan sát vô số vật sáng biến hóa qua sinh tử, từ sinh đến tử rồi từ tử tới sinh, qua đó nhận ra đạo sinh tử luân hồi của chính mình. Cảm ngộ này không trực tiếp tăng tu vi nhưng làm tâm cảnh của hắn thăng hoa ở tầng Đạo.","nguon":["@c0680"]},{"id":"dao-nhan-qua","name":"Đạo nhân quả","cn":"","aliases":[],"loai":"khac","loaiLabel":"Đạo cảnh / cảm ngộ","phamCap":"Không rõ","hePhai":"Nhân quả","soHuu":["Vương Lâm"],"blurb":"Cảm ngộ nhân quả của Vương Lâm qua hình ảnh Lý Mộ Uyển, Vương Bình và Thanh Nghi.","detail":"Từ hình ảnh Lý Mộ Uyển tìm kiếm đáp án, cùng Vương Bình và Thanh Nghi sống cuộc đời bình thường, Vương Lâm hiểu thêm về vòng tuần hoàn nhân quả. Đây là một phần cơ duyên hiểu Đạo hắn đạt được trong Thiên Nghịch.","nguon":["@c0680"]},{"id":"buoc-thu-ba","name":"Bước thứ ba","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cảnh giới / đạo cảnh","phamCap":"Cực cao","hePhai":"Đạo cảnh","soHuu":["Vương Lâm"],"blurb":"Tầng cảnh giới thần bí mà Vương Lâm chưa đạt tới nhưng đã quan sát được khí tức sau cơ duyên Thiên Nghịch.","detail":"Sau khi trải qua cảnh giới trước cánh cửa thiên địa, Vương Lâm tự ví mình vẫn nhỏ bé như con kiến, nhưng đã trở thành con kiến có thể quan sát được bước thứ ba. Ánh mắt hắn sau cảm ngộ còn lưu khí tức này, đủ khiến một tu sĩ Dương Thực chấn động gần như sụp đổ.","nguon":["@c0680"]},{"id":"dao-yem","name":"Đạo Yểm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Truyền thuyết La Thiên","hePhai":"không rõ","soHuu":["Người thi triển Đạo Yểm trong truyền thuyết"],"blurb":"Đạo Yểm là thần thông trong truyền thuyết La Thiên Tinh Vực, từng khiến nhiều tu sĩ bước thứ hai không kịp tế pháp bảo đã bại. Thân Công Hổ nhận lầm dư uy ánh mắt tầm đạo của Vương Lâm là thuật này.","detail":"Theo ký ức và nhận định của Thân Công Hổ, Đạo Yểm từng xuất hiện vô số năm trước tại La Thiên Tinh Vực và đủ sức đánh bại tu sĩ bước thứ hai. Khi bị ánh mắt của Vương Lâm áp chế đến mất khả năng phản kháng, hắn cho rằng cảnh tượng ấy chính là Đạo Yểm trong truyền thuyết.","nguon":["@c0681"]},{"id":"canh-mong-tam-dao-tu-thien-nghich","name":"Cảnh mộng tầm đạo từ Thiên Nghịch","cn":"","loai":"khac","loaiLabel":"Cơ duyên cảm ngộ","phamCap":"Cơ duyên bước thứ ba","hePhai":"Thiên Nghịch","soHuu":["Vương Lâm"],"blurb":"Cảnh mộng tầm đạo từ Thiên Nghịch là cơ duyên khiến Vương Lâm nhìn thấy con đường dẫn tới bước thứ ba Tu Đạo. Chỉ một khe hở của Thiên Nghịch đã làm tâm tính, linh hồn và ý cảnh của hắn biến hóa sâu sắc.","detail":"Sau khi tỉnh lại, Vương Lâm nhận ra cảnh tượng chân thật như mộng do Thiên Nghịch mở ra đã hé cho hắn cánh cửa bước thứ ba. Trải nghiệm này khiến hắn hiểu uy năng Thiên Nghịch vượt xa tưởng tượng, đồng thời ý cảnh có dấu hiệu tiến gần Vấn Đỉnh đại viên mãn.","nguon":["@c0681"]},{"id":"bi-phap-loi-tien-dien-mo-duong-vao-loi-tien-gioi","name":"Bí pháp Lôi Tiên Điện mở đường vào Lôi Tiên Giới","cn":"","loai":"bi-thuat","loaiLabel":"Bí pháp","phamCap":"Bí pháp thế lực","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Tiên Điện"],"blurb":"Bí pháp này cho phép một số tu sĩ bước thứ hai tiến vào Lôi Tiên Giới dù giới hạn thông thường là Vấn Đỉnh hậu kỳ đại viên mãn. Điều kiện được Thân Công Hổ nêu là tu vi chưa vượt quá Khuy Niết sơ kỳ.","detail":"Thân Công Hổ giải thích rằng Lôi Tiên Giới ở La Thiên có hạn chế tu vi khi mở ra, nhưng Lôi Tiên Điện nắm bí pháp đặc thù để đưa một số tu sĩ bước thứ hai vào trong. Bí pháp này chỉ áp dụng cho người chưa vượt qua Khuy Niết sơ kỳ.","nguon":["@c0681"]},{"id":"loi-than-thong-thuc-su","name":"Lôi thần thông thực sự","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Biểu hiện của Vương Lâm khi bước trên lôi đình trong Lôi Trì, được Thân Công Hổ xem là lôi thần thông chân chính.","detail":"Không phải tiên thuật công kích trực tiếp mà là trạng thái cảm ngộ và điều khiển bước chân theo quy luật lôi quang trong Lôi Trì. Thân Công Hổ coi cảnh tượng này là thứ hắn chờ đợi suốt hai năm để được chứng kiến.","nguon":["@c0683"]},{"id":"quy-luat-cua-sam-set","name":"Quy luật của sấm sét","cn":"","loai":"khac","loaiLabel":"Cảm ngộ quy luật","phamCap":"liên hệ bước thứ ba","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Tầng cảm ngộ về bản chất vận hành của sấm sét mà Vương Lâm chạm tới trong Lôi Trì.","detail":"Vương Lâm nhìn Lôi Trì đến mức quên thân thể và ngoại giới, chỉ còn lôi đình cùng các tia sáng ẩn hiện. Từ đó hắn bước đúng theo lôi quang, rồi nhận ra hiểu biết mới về sấm sét có liên hệ tới bước thứ ba và đặc biệt quan trọng cho con đường tu đạo của mình.","nguon":["@c0683"]},{"id":"loi-uy-nguyen-than","name":"Lôi uy nguyên thần","cn":"","loai":"khac","loaiLabel":"Năng lực nguyên thần","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Lôi uy phát ra từ nguyên thần Vương Lâm do từng nuốt một nửa Thái Cổ Lôi Long.","detail":"Năng lực này khiến thân thể, nguyên thần và sấm sét của Vương Lâm gần như hòa hợp, nhưng khi đối diện Lôi Trì thì lôi uy ấy vẫn quá yếu so với uy thế sấm sét nơi đây, không đủ để cưỡng ép tiến sâu.","nguon":["@c0683"]},{"id":"tho-nap-loi-dinh","name":"Thổ nạp lôi đình","cn":"","loai":"cong-phap","loaiLabel":"Tu luyện","phamCap":"Không rõ","hePhai":"Lôi","soHuu":["Vương Lâm"],"blurb":"Cách Vương Lâm hấp thu lôi đình trong vòng trong Lôi Trì để tu luyện.","detail":"Vương Lâm khoanh chân thổ nạp trong vòng trong Lôi Trì, nơi lôi đình dày đặc và ẩn chứa thiên địa nguyên lực rất mạnh. Mỗi đạo lôi đình nhập thể đều khiến thân thể chấn động, toàn thân tê liệt và nguyên thần vận chuyển chậm chạp.","nguon":["@c0684"]},{"id":"nguyen-luc-than-thong-cua-chien-khong-liet","name":"Nguyên lực thần thông của Chiến Không Liệt","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi","soHuu":["Chiến Không Liệt"],"blurb":"Thần thông lôi quang màu tím của Chiến Không Liệt, phối hợp với kiếm gỗ màu tím.","detail":"Chiến Không Liệt bấm quyết tạo lôi quang màu tím, đồng thời dùng kiếm khí từ kiếm gỗ màu tím. Uy phong của chiêu thức có ẩn chứa thiên địa nguyên khí, được hắn triển khai khi chuẩn bị giao chiến với Thân Công Hổ.","nguon":["@c0684"]},{"id":"dan-dong-thien-loi-cua-than-cong-ho","name":"Dẫn động Thiên Lôi của Thân Công Hổ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi","soHuu":["Thân Công Hổ"],"blurb":"Lôi pháp Thân Công Hổ dùng khi chuẩn bị giao chiến với Chiến Không Liệt.","detail":"Thân Công Hổ giơ tay chỉ lên không trung như dẫn động thiên lôi, đồng thời Lôi Thú bên cạnh ngưng tụ sấm sét để phối hợp. Chiêu thức được triển khai trong thế đối đầu trực diện tại Lôi Trì.","nguon":["@c0684"]},{"id":"dan-loi-thuat","name":"Dẫn lôi thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông lôi hệ nguyên lực","hePhai":"Lôi Tiên Điện / Thân Công Hổ","soHuu":["Thân Công Hổ"],"blurb":"Thần thông lôi hệ của Thân Công Hổ, dùng nguyên lực bản thân dẫn sấm sét trời đất giáng xuống. Vương Lâm nhận xét thuật này có lôi uy nhưng thiếu lôi hồn và sức mạnh căn nguyên của sấm sét.","detail":"Trong trận đấu với Chiến Không Liệt tại Lôi Trì, Thân Công Hổ thi triển Dẫn lôi thuật, dẫn lôi quang từ hư không như thần long giáng xuống. Sau khi quan sát, Vương Lâm chỉ ra điểm thiếu của thuật này nằm ở căn nguyên: tuy có uy thế sấm sét nhưng chưa có lôi hồn, chưa chạm được sức mạnh thật của sấm sét.","nguon":["@c0685"]},{"id":"nguyen-luc-hoa-dinh","name":"Nguyên lực hóa đỉnh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông nguyên lực","hePhai":"","soHuu":[],"blurb":"Dạng thần thông nguyên lực được Vương Lâm dùng làm mốc so sánh khi đánh giá Dẫn lôi thuật của Thân Công Hổ.","detail":"Vương Lâm nhận định Dẫn lôi thuật của Thân Công Hổ tuy không phải nguyên lực hóa đỉnh nhưng uy lực lớn, qua đó cho thấy đây là một kiểu vận dụng nguyên lực đáng dùng làm chuẩn so sánh với thần thông lôi hệ.","nguon":["@c0685"]},{"id":"kiem-khi-cua-chien-khong-liet","name":"Kiếm khí của Chiến Không Liệt","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Thần thông kiếm đạo","hePhai":"Chiến gia","soHuu":["Chiến Không Liệt"],"blurb":"Thần thông kiếm đạo Chiến Không Liệt dùng khi giao thủ với Thân Công Hổ trong Lôi Trì.","detail":"Chiến Không Liệt phun nguyên khí lên kiếm gỗ, khiến kiếm tản ra kiếm khí nồng đậm, bay lên đối kháng lôi quang do Thân Công Hổ dẫn xuống. Va chạm giữa kiếm khí và lôi quang tạo tiếng nổ lớn, khiến đôi bên đều bị chấn lui.","nguon":["@c0685"]},{"id":"dan-dat-khi-tuc","name":"Dẫn dắt khí tức","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không nêu rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Hiện tượng khí tức của Vương Lâm tự nhiên áp chế Trương Tân Hải, khiến đối phương sinh phản ứng như phàm nhân đứng trước tu sĩ.","detail":"Tại Hoành Vân Sơn Phong, chỉ khí tức tỏa ra từ Vương Lâm đã khiến Trương Tân Hải theo bản năng cúi thấp, qua đó biểu hiện chênh lệch tầng cấp rất lớn giữa hai người.","nguon":["@c0687"]},{"id":"linh-quyet-tang-tho","name":"Linh quyết tăng thọ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không nêu rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông dùng linh quyết thiêu đốt linh lực của người nhận để kéo dài thọ nguyên thêm một thời hạn nhất định.","detail":"Vương Lâm đánh một đạo linh quyết vào giữa lông mày Trương Tân Hải, không trực tiếp thay đổi vận mệnh nhưng dùng linh lực của Trương Tân Hải thiêu đốt để tăng thêm mười năm tuổi thọ. Khi thi triển, Vương Lâm nhớ tới Lý Mộ Uyển và tiếc nuối năm xưa không thể dùng cách tương tự cho nàng.","nguon":["@c0687"]},{"id":"truyen-than-niem-toan-tinh-cau","name":"Truyền thần niệm toàn tinh cầu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không nêu rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông dùng thần niệm vang khắp toàn bộ Thanh Linh Tinh để truyền đạt ý chí của người thi triển.","detail":"Vương Lâm dùng thần niệm khiến tất cả tu sĩ trên Thanh Linh Tinh nghe được tuyên bố rằng tinh cầu này từ nay là tu chân tinh của hắn, đồng thời cấm mọi người bước vào Hoành Vân Sơn Phong.","nguon":["@c0687"]},{"id":"nhan-qua-y-canh","name":"Nhân quả ý cảnh","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Ý cảnh","phamCap":"Chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ý cảnh của Vương Lâm đang chuyển từ đạo sinh tử luân hồi sang đạo nhân quả. Ở chương này, hắn dùng Côn Cực Tiên làm vật đại diện để bù cho việc ý cảnh chưa thể thực chất hóa hoàn toàn.","detail":"Vương Lâm nhận ra bản thể là nhân, nguyên thần là quả, từ đó nhìn thấy phương hướng của nhân quả ý cảnh. Ý cảnh này chưa thể ngưng hóa ra hình thái hư ảo như sinh tử luân hồi, nhưng đã đủ để hắn tế luyện Côn Cực Tiên, dùng pháp bảo này tạo vòng tròn nhân quả và áp chế viễn cổ kiếm ý của Hứa Lập Quốc.","nguon":["@c0688"]},{"id":"vien-co-kiem-y","name":"Viễn cổ kiếm ý","cn":"","aliases":[],"loai":"kiem-quyet","loaiLabel":"Kiếm ý","phamCap":"Chưa rõ","hePhai":"","soHuu":["Hứa Lập Quốc"],"blurb":"Kiếm ý tang thương mà Hứa Lập Quốc dung vào hình thái đại kiếm khi phản kháng Vương Lâm. Nó bị Vương Lâm quy về nhân quả và áp chế bằng Côn Cực Tiên.","detail":"Sau khi thoát khỏi túi trữ vật, Hứa Lập Quốc hóa thành đại kiếm giống tiên kiếm, mang kiếm khí sắc bén và viễn cổ kiếm ý lao tới. Vương Lâm cho rằng nhân của kiếm ý này là do mình tạo ra, nên quả phải thuộc về mình, khiến Hứa Lập Quốc bị vòng nhân quả của Côn Cực Tiên làm tan rã.","nguon":["@c0688"]},{"id":"hoa-ma-chi","name":"Hóa Ma Chỉ","cn":"","aliases":["Hóa Ma"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chỉ pháp","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Hóa Ma Chỉ là một trong ba chỉ pháp của Vương Lâm được rà soát trước khi trùng kích cảnh giới cao hơn.","detail":"Ở chương này, Vương Lâm cảm thấy Hóa Ma cùng Tịch Diệt và Hoàng Tuyền đều chưa hoàn chỉnh, nếu tiếp tục theo hướng cũ sẽ bất lợi cho bước thứ ba, nên liên tục suy luận để điều chỉnh.","nguon":["@c0689"]},{"id":"ngung-hoa-tuyen-hon","name":"Ngưng Hóa Tuyền Hồn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Đạo niệm","phamCap":"tam thức Hoàng Tuyền","hePhai":"Sinh tử luân hồi ý cảnh","soHuu":["Vương Lâm"],"blurb":"Ngưng Hóa Tuyền Hồn là một trong tam thức đạo niệm Hoàng Tuyền của Vương Lâm.","detail":"Khi Vương Lâm hấp thu oán khí phàm nhân vào Hoàng Tuyền, thần thông này dần xuất hiện bóng dáng Tuyền Hồn, liên hệ trực tiếp với hướng ngưng tụ Tuyền Hồn.","nguon":["@c0689"]},{"id":"ao-thuat-cua-hua-lap-quoc","name":"Ảo thuật của Hứa Lập Quốc","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thuật mê hoặc","phamCap":"không rõ","hePhai":"Hứa Lập Quốc","soHuu":["Hứa Lập Quốc"],"blurb":"Ảo thuật Hứa Lập Quốc dùng để dụ tu sĩ bên ngoài phạm vi Hoành Vân Phong.","detail":"Trong lúc Vương Lâm bế quan, Hứa Lập Quốc dùng ảo thuật lừa vài tu sĩ vốn không dám tiến vào, trêu đùa một phen rồi thả đi, khiến họ về sau vẫn sợ hãi khi nhớ lại.","nguon":["@c0689"]},{"id":"tran-phap-tien-ngoc-o-hoang-mac-tay-bac-thanh-linh-tinh","name":"Trận pháp tiên ngọc ở hoang mạc tây bắc Thanh Linh Tinh","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp tu luyện","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Trận pháp do Vương Lâm bố trí bằng lượng lớn tiên ngọc để trùng kích Vấn Đỉnh viên mãn.","detail":"Tại hoang mạc tây bắc Thanh Linh Tinh, Vương Lâm sắp tiên ngọc thành trận pháp khổng lồ, ngồi trong trận thổ nạp tiên khí suốt một năm cho tới khi tiên ngọc cạn sạch.","nguon":["@c0689"]},{"id":"van-dinh-vien-man","name":"Vấn Đỉnh viên mãn","cn":"","aliases":["Vấn Đỉnh đại viên mãn"],"loai":"khac","loaiLabel":"Cảnh giới","phamCap":"bước tu đạo đầu tiên","hePhai":"tu chân","soHuu":["Vương Lâm"],"blurb":"Vấn Đỉnh viên mãn là trạng thái Vương Lâm đạt được sau mười chín năm tám tháng ở Thanh Linh Tinh.","detail":"Sau khi sinh tử luân hồi ý cảnh hoàn toàn viên mãn, Vương Lâm dùng trận pháp tiên ngọc và tiên dịch bổ sung tiên lực, chính thức đạt Vấn Đỉnh viên mãn, hoàn thành bước tu đạo đầu tiên của mình.","nguon":["@c0689"]},{"id":"am-hu","name":"Âm Hư","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cảnh giới","phamCap":"sau Vấn Đỉnh","hePhai":"tu chân","soHuu":[],"blurb":"Âm Hư là cảnh giới được Vương Lâm nghĩ tới sau khi đạt Vấn Đỉnh viên mãn.","detail":"Vương Lâm nhớ lời Cổ Yêu Bối La về thiên phạt của nghịch tu và tự hỏi khi đột phá khỏi Vấn Đỉnh tiến vào Âm Hư, thiên phạt có giáng xuống hay không.","nguon":["@c0689"]},{"id":"truu-linh-chi-lai","name":"Trừu Linh Chi Lai","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"cao cấp","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông rút khí tức tang thương từ Tiên Sơn, ngưng thành sương mù công kích.","detail":"Vương Lâm thi triển thông qua Tiên Sơn, khiến lão già Trương gia kinh hãi vì cho rằng tu sĩ Vấn Đỉnh đại viên mãn không thể dùng được thần thông bực này.","nguon":["@c0690"]},{"id":"hac-hoa-than-thong","name":"Hắc hỏa thần thông","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Trương gia","soHuu":["Lão già Trương gia"],"blurb":"Thuật tạo ngọn lửa màu đen để bao phủ, ngăn cản địch thủ.","detail":"Lão già Trương gia dùng hắc hỏa đối phó khôi lỗi Tiên Vệ khi bị Vương Lâm ép giao Lôi Đỉnh.","nguon":["@c0690"]},{"id":"khien-lua","name":"Khiên lửa","cn":"","loai":"than-thong","loaiLabel":"Phòng ngự thuật","phamCap":"không rõ","hePhai":"Trương gia","soHuu":["Lão già Trương gia"],"blurb":"Thuật phòng ngự tạo khiên lửa trước người.","detail":"Lão già Trương gia dùng để chắn khôi lỗi Tiên Vệ, nhưng bị một quyền đánh nứt rồi vỡ.","nguon":["@c0690"]},{"id":"loi-dien-thuc-chat-hoa","name":"Lôi điện thực chất hóa","cn":"","loai":"than-thong","loaiLabel":"Thần thông lôi hệ","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lôi quang được ngưng tụ thành dạng thực chất trong tay.","detail":"Vương Lâm ngưng tụ lôi quang trong tay phải, dẫn tiếng sấm từ tinh không và hình thành một đạo lôi điện thực chất hóa để nối tiếp thế công.","nguon":["@c0690"]},{"id":"de-tam-nhan","name":"Đệ Tam Nhãn","cn":"","loai":"than-thong","loaiLabel":"Thần thông gia tộc","phamCap":"cao cấp","hePhai":"Gia tộc của lão già Âm Hư","soHuu":["Lão già Trương gia","Vương Lâm"],"blurb":"Thần thông mở mắt thứ ba ở giữa lông mày, phát hồng quang có thể làm tan rã hồn phách Tiên Sơn.","detail":"Lão già Trương gia là người đầu tiên trong gia tộc luyện thành thuật này. Vương Lâm nhận ra nó ẩn chứa một chút phương hướng bước thứ ba và khí tức quay về căn nguyên nên đổi ba thuật lấy ngọc giản, rồi tự tu chỉnh các chỗ sai.","nguon":["@c0691"]},{"id":"sat-luc-tien-quyet","name":"Sát Lục Tiên Quyết","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"cao cấp","hePhai":"","soHuu":["Vương Lâm","Lão già Trương gia"],"blurb":"Thuật dùng kiếm khí giết chóc đoạt sinh cơ, ngưng thành Sinh Chi Lạc Ấn.","detail":"Vương Lâm học từ tiền bối Toái Niết bước thứ hai và dùng làm mồi trao đổi Đệ Tam Nhãn. Thuật vừa có lực công kích vừa có khả năng phòng hộ bằng dấu ấn sinh cơ, nhưng Vương Lâm cảnh báo không nên tích Sát Lục Chi Khí quá mười vạn.","nguon":["@c0691"]},{"id":"sinh-chi-lac-an","name":"Sinh Chi Lạc Ấn","cn":"","loai":"than-thong","loaiLabel":"Ấn phòng hộ","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Dấu ấn sinh cơ do Sát Lục Tiên Quyết ngưng thành.","detail":"Sau khi kiếm khí giết chóc đoạt sinh cơ, sức sống hóa thành dấu ấn bao quanh thân thể. Số lượng càng nhiều thì phòng hộ càng vững, nhưng tích quá nhiều có thể nguy hiểm.","nguon":["@c0691"]},{"id":"dao-hon","name":"Đạo hồn","cn":"","loai":"khac","loaiLabel":"Thần hồn liên hệ","phamCap":"không rõ","hePhai":"","soHuu":["Thân Công Hổ"],"blurb":"Liên hệ thần hồn khiến Thân Công Hổ bị xem là đạo hồn không đầy đủ.","detail":"Đường Ngôn Phong dùng tình trạng đạo hồn để mỉa mai Thân Công Hổ. Chính đạo hồn này giúp Thân Công Hổ cảm nhận được một tia khí tức Tôn Chủ trong sao băng lôi đình.","nguon":["@c0693"]},{"id":"phan-than-thu-cua","name":"Phân thân thử cửa","cn":"","loai":"than-thong","loaiLabel":"Thần thông phân thân","phamCap":"không rõ","hePhai":"","soHuu":["Tu sĩ Âm Hư thả phân thân"],"blurb":"Thần thông tách phân thân dùng để dò xét cửa Lôi Tiên Giới.","detail":"Một tu sĩ Âm Hư dùng phân thân chạm vào sấm sét đỏ sậm trước cửa Lôi Tiên Giới; phân thân lập tức tan vỡ và khiến bản thể bị tia chớp truy diệt.","nguon":["@c0693"]},{"id":"hoa-thanh-vo-so-tinh-diem","name":"Hóa thành vô số tinh điểm","cn":"","loai":"than-thong","loaiLabel":"Thân pháp biến hóa","phamCap":"không rõ","hePhai":"","soHuu":["Lão già tóc bạc trong Lôi Tiên Giới"],"blurb":"Cách biến mất bằng vô số tinh điểm, kèm khí tức quay về căn nguyên.","detail":"Lão già tóc bạc trong Lôi Tiên Giới thi triển trên lôi sơn đen sau khi cảm ứng dị biến từ xa.","nguon":["@c0693"]},{"id":"than-thong-giam-cam-bun-dat","name":"Thần thông giam cầm bùn đất","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"cao cấp","hePhai":"","soHuu":["Lão già tóc bạc trong Lôi Tiên Giới"],"blurb":"Thần thông khiến bùn đất chứa thiên địa nguyên lực, phong tỏa đường thoát dưới lòng đất.","detail":"Sau khi Vương Lâm rơi xuống, khu vực quanh thạch thất bị lực lượng này giam cầm. Hắn không thể xuyên qua bùn đất ra ngoài, chỉ còn lối phía trước dẫn vào thông đạo bị điều khiển.","nguon":["@c0694"]},{"id":"than-thong-xuyen-qua","name":"Thần thông xuyên qua","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Năng lực xuyên qua bùn đất hoặc vật cản mà Vương Lâm vốn định dùng để thoát ra.","detail":"Trong thạch thất dưới lòng đất Lôi Tiên Giới, Vương Lâm thử dùng năng lực này nhưng bị bùn đất chứa thiên địa nguyên lực bắn ngược trở lại.","nguon":["@c0694"]},{"id":"than-thong-cua-ra-trong-thong-dao","name":"Thần thông cửa ra trong thông đạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi Tiên Giới","soHuu":["Lão giả tóc bạc"],"blurb":"Thần thông giam khốn trong hệ thống thông đạo dưới lòng đất ở Lôi Tiên Giới, tạo cửa ra xuất hiện theo thời gian và vị trí đặc thù. Dù thông đạo vật lý bị phá sập, mạng thiên địa nguyên lực vẫn duy trì cơ chế sinh cửa.","detail":"Cửa ra trong thông đạo bị người điều khiển, nhiều lần hiện trước mắt Vương Lâm rồi biến mất khiến hắn không thể rời đi ngay. Sau khi Vương Lâm phá sập hệ thống bùn đất, các tia thiên địa nguyên lực vẫn đan rậm như mạng lưới; tại những điểm giao nhau, cửa ra vẫn tiếp tục hình thành, cho thấy cốt lõi thần thông không nằm ở địa hình mà ở mạng nguyên lực.","nguon":["@c0695"]},{"id":"loi-uy-trong-nguyen-than-cua-vuong-lam","name":"Lôi uy trong nguyên thần của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông/lực lượng","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Lực lượng lôi uy nằm trong nguyên thần của Vương Lâm, được hắn vận cùng tiên lực khi phá thông đạo dưới đất. Khi xuất thủ, lôi uy ngưng thành tia chớp trong tay để phối hợp với Lôi Thú và Tiên Vệ.","detail":"Trong lúc phá cục giam khốn, Vương Lâm bắt quyết, vận tiên lực và lôi uy trong nguyên thần, ngưng tụ lôi điện để đánh vào cùng điểm mà Lôi Thú, Tiên Vệ và tiên kiếm đang công kích. Lực lượng này góp phần làm một thông đạo vỡ ra rồi kéo theo phản ứng dây chuyền khiến hệ thống thông đạo tan nát.","nguon":["@c0695"]},{"id":"la-thien-dai-tran","name":"La Thiên đại trận","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"La Thiên","soHuu":["Lão giả tóc trắng"],"blurb":"La Thiên đại trận là trận pháp trọng tâm trong kế hoạch mấy vạn năm của lão giả tóc trắng. Ông định bố trí đại trận sau khi thu được hồn của tiên sơn trong Lôi tiên giới.","detail":"Lão giả tóc trắng tạm bỏ qua chuyện Vương Lâm thoát sớm để tập trung thu hồn tiên sơn và bố trí La Thiên đại trận. Kế hoạch này được ông xem là bước then chốt giúp mình trở thành đệ nhất La Thiên tinh vực và quét ngang Liên Minh Tinh Vực.","nguon":["@c0696"]},{"id":"ma-cong-cua-hua-phong-han","name":"Ma công của Hứa Phong Hàn","cn":"","aliases":["Ma công của thanh niên áo tím"],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Hứa Phong Hàn"],"blurb":"Ma công của Hứa Phong Hàn tạo ma khí, ma diễm và ma ảnh đầu một sừng. Trong giao chiến, công pháp này còn điều khiển nước mưa hóa thành tên nước và trường thương nước mang ma khí.","detail":"Hứa Phong Hàn xuất hiện trong cầu vồng đen, toàn thân ma khí dày đặc và đứng trên ma ảnh đầu một sừng. Khi giao chiến với Vương Lâm, hắn dùng ma khí phối hợp mưa hóa thành mũi tên nước, màn nước và trường thương nước, về sau còn dùng Ma Thôn để cho ma ảnh nuốt lôi cầu.","nguon":["@c0696"]},{"id":"ma-thon","name":"Ma Thôn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Hứa Phong Hàn"],"blurb":"Ma Thôn là thần thông của Hứa Phong Hàn, khiến ma ảnh đầu một sừng mở ma khẩu để thôn phệ công kích. Nó được dùng để nuốt lôi cầu màu lam của Vương Lâm.","detail":"Trong trận giao thủ, Hứa Phong Hàn bắt quyết và quát Ma Thôn, khiến vết nứt trên ma ảnh mở rộng như ma khẩu. Ma khẩu này lập tức nuốt chửng lôi cầu do Vương Lâm ngưng tụ từ lôi uy và lôi lực Lôi tiên giới.","nguon":["@c0696"]},{"id":"loi-phap-cua-vuong-lam","name":"Lôi pháp của Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Lôi pháp của Vương Lâm vận chuyển nguyên thần, dẫn lôi uy và lôi lực trong Lôi tiên giới để ngưng tụ công kích. Chương này hắn dùng lôi cầu màu lam phá mưa tên ma khí và đánh về phía Hứa Phong Hàn.","detail":"Đứng trong Lôi tiên giới, Vương Lâm có thể mượn lôi lực dồi dào nơi đây để ngưng lôi cầu màu lam. Lôi pháp này giúp hắn phá tan mưa tên nước chứa sát khí, đồng thời buộc Hứa Phong Hàn phải dùng Ma Thôn để thôn phệ lôi cầu.","nguon":["@c0696"]},{"id":"loi-bao","name":"Lôi, bạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi pháp","soHuu":["Vương Lâm"],"blurb":"Lôi, bạo là thủ đoạn Vương Lâm dùng để dẫn nổ lôi cầu đã bị ma ảnh nuốt vào.","detail":"Trong trận với Hứa Phong Hàn, Vương Lâm quát lệnh khiến lôi cầu chưa bị hóa giải bộc phát từ trong cơ thể ma ảnh, làm ma ảnh màu đen tan nát trong lôi quang.","nguon":["@c0697","@c0762"]},{"id":"dong-lam-chi-mac","name":"Đông Lâm chi mạc","cn":"","loai":"than-thong","loaiLabel":"Thần thông phòng ngự","phamCap":"không rõ","hePhai":"Ma công Âm Hư","soHuu":["Hứa Phong Hàn"],"blurb":"Đông Lâm chi mạc là thần thông phòng ngự Hứa Phong Hàn dùng trong khoảnh khắc nguy cơ sinh tử.","detail":"Hứa Phong Hàn phun nguyên thần tinh huyết chứa thiên địa nguyên lực, hóa thành màn sương máu trước người để chặn một quyền đỉnh phong của Tiên Vệ. Va chạm khiến đại lục chấn động, Tiên Vệ bị đẩy lùi và suy giảm kim quang.","nguon":["@c0697"]},{"id":"dao-niem-hoa-ma","name":"Đạo niệm hóa ma","cn":"","loai":"than-thong","loaiLabel":"Đạo niệm thần thông","phamCap":"Âm Hư","hePhai":"Ma đạo","soHuu":["Hứa Phong Hàn"],"blurb":"Đạo niệm hóa ma là biến hóa đạo niệm thuộc cảnh giới Âm Hư của Hứa Phong Hàn.","detail":"Hứa Phong Hàn dùng đạo niệm hóa ma để triển khai Ma Liên, đưa trận chiến với Vương Lâm từ tầng pháp bảo và thần thông sang đối kháng đạo niệm ngưng thật.","nguon":["@c0697"]},{"id":"dao-hoa-ma-lien-de-nhat-chuyen","name":"Đạo hóa Ma Liên, đệ nhất chuyển","cn":"","loai":"than-thong","loaiLabel":"Đạo niệm thần thông","phamCap":"Âm Hư","hePhai":"Ma đạo","soHuu":["Hứa Phong Hàn"],"blurb":"Đạo hóa Ma Liên, đệ nhất chuyển là đạo niệm thần thông chủ lực của Hứa Phong Hàn trong trận với Vương Lâm.","detail":"Hứa Phong Hàn khiến Ma Liên trên không xoay chuyển, ma diễm như thay thế thiên địa và tạo áp lực xóa diệt đối phương. Thần thông này trực tiếp đối đầu Hoàng Tuyền do Vương Lâm ngưng hiện.","nguon":["@c0697"]},{"id":"ma-diem-dot","name":"Ma diễm, đốt","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Hứa Phong Hàn"],"blurb":"Ma diễm, đốt là đòn công kích Hứa Phong Hàn thúc phát từ Ma Liên.","detail":"Sau khi Ma Liên xoay chuyển, Hứa Phong Hàn thúc dòng xoáy ma diễm lao về phía Vương Lâm, kéo theo cuồng phong nóng rực và ép Vương Lâm thi triển Thức thứ hai.","nguon":["@c0697"]},{"id":"thuc-thu-hai-ngung-tu-tuyen-hon","name":"Thức thứ hai, ngưng tụ tuyền hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hoàng Tuyền","soHuu":["Vương Lâm"],"blurb":"Thức thứ hai, ngưng tụ tuyền hồn là chiêu Vương Lâm dùng khi ma diễm áp sát.","detail":"Trong đạo niệm chi chiến, Vương Lâm thi triển thức này khiến Hoàng Tuyền rung động, oán khí bên trong điên cuồng ngưng tụ để đối phó ma diễm của Hứa Phong Hàn.","nguon":["@c0697"]},{"id":"ma-lien-bach-chuyen","name":"Ma Liên, bách chuyển","cn":"","loai":"than-thong","loaiLabel":"Thần thông đạo niệm","phamCap":"Không rõ","hePhai":"","soHuu":["Hứa Phong Hàn"],"blurb":"Thần thông đạo niệm của Hứa Phong Hàn, dùng Ma Liên xoay chuyển để áp chế đối thủ.","detail":"Hứa Phong Hàn thi triển khiến liên hoa xoay chuyển, tạo cảm giác thiên địa đảo lộn và ép thân thể Vương Lâm phải lùi. Khi gặp Hoàng Tuyền lực, tốc độ xoay chuyển của Ma Liên bị lực hút khổng lồ làm chậm lại.","nguon":["@c0698"]},{"id":"roi-nhan-qua","name":"Roi nhân quả","cn":"","aliases":["Nhân quả Côn Cực Tiên"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông từ mi tâm của Vương Lâm, đánh vào sơ hở tâm thần đối phương.","detail":"Vương Lâm triệu ra roi dài từ mi tâm, đánh cách không vào Hứa Phong Hàn. Một roi khiến thân thể Hứa Phong Hàn run rẩy, tâm thần bị ý niệm hỗn tạp xé rách và đạo niệm trở nên bất ổn.","nguon":["@c0698"]},{"id":"nguyen-hoa-ma-than","name":"Nguyên Hóa Ma Thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông nguyên lực","phamCap":"Không rõ","hePhai":"","soHuu":["Hứa Phong Hàn"],"blurb":"Thần thông nguyên lực ngưng ma diễm thành ma vật một sừng.","detail":"Sau khi bại trong chiến đạo niệm, Hứa Phong Hàn vận thiên địa nguyên lực, ngưng tụ ma diễm đen giữa hai tay thành ma vật một sừng giống tán ma nhưng yếu hơn. Ma vật vừa hiện ra đã quay lại cắn vai và nuốt chính Hứa Phong Hàn.","nguon":["@c0698"]},{"id":"con-mat-thu-ba","name":"Con mắt thứ ba","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông ở mi tâm của Vương Lâm, phát hồng mang khi đối diện nguy cơ.","detail":"Khi Hứa Phong Hàn thi triển Nguyên Hóa Ma Thần, Vương Lâm cảm nhận nguy hiểm, đặt tay trái lên mi tâm và mở con mắt thứ ba. Hồng mang trong mắt ngưng tụ không tan, nhưng ma vật đã quay lại nuốt Hứa Phong Hàn trước khi Vương Lâm xuất thủ rõ ràng.","nguon":["@c0698"]},{"id":"dao-niem-tao-khong-gian-tru-vat","name":"Đạo niệm tạo không gian trữ vật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Đạo niệm","soHuu":["Hứa Phong Hàn"],"blurb":"Thần thông dùng đạo niệm biến thành không gian chứa đồ, thay thế túi trữ vật thông thường.","detail":"Vương Lâm phát hiện Ma Liên không chỉ là đạo niệm thực thể mà còn là không gian chứa vật quý. Cách dùng đạo niệm làm túi trữ vật có năng lực bảo vệ mạnh, giải thích vì sao Hứa Phong Hàn không mang túi trữ vật bên ngoài.","nguon":["@c0699"]},{"id":"nang-luc-nuot-hon","name":"Năng lực nuốt hồn","cn":"","loai":"khac","loaiLabel":"Năng lực nguyên thần","phamCap":"không rõ","hePhai":"Nuốt hồn","soHuu":["Vương Lâm"],"blurb":"Năng lực nguyên thần đặc thù giúp Vương Lâm nuốt ma hồn trong Ma Liên.","detail":"Nhờ căn cơ nuốt hồn năm xưa, Vương Lâm có thể nuốt ma hồn mà tu sĩ tầm thường khó xử lý nếu không tu ma đạo công pháp. Việc nuốt ma hồn giúp nguyên lực của hắn phục hồi hoàn toàn và còn tinh tiến.","nguon":["@c0699"]},{"id":"tran-phap-cam-che-du-tu-si","name":"Trận pháp cấm chế dụ tu sĩ","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"không rõ","hePhai":"Cấm chế","soHuu":["Lý Nguyên","Nữ tu mắt phượng"],"blurb":"Cấm chế bẫy được bố trí kín trên đại lục vỡ trong Lôi Tiên Giới, hòa lẫn núi đá và dùng tiên lực làm mồi. Bề ngoài để lộ sơ hở khiến tu sĩ tưởng có thể phá trận và tiến vào cửa động bên dưới.","detail":"Trận pháp có phạm vi nhỏ, che giấu cửa động và phối hợp với tồn tại trong hang để săn tu sĩ. Sơ hở tiên lực không dung hợp hoàn toàn khiến Vương Lâm nghi ngờ đây là bố cục cố ý, còn tu sĩ trung niên dùng hình nhân mộc linh phá cấm thì lập tức bị dẫn vào cửa động và gặp nạn.","nguon":["@c0700"]},{"id":"muoi-tam-cam-che-lien-hoan","name":"Mười tám cấm chế liên hoàn","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế công kích","phamCap":"không rõ","hePhai":"Cấm chế","soHuu":["Lý Nguyên"],"blurb":"Thủ đoạn cấm chế do Lý Nguyên thi triển khi đối đầu Vương Lâm. Mười tám đạo cấm chế chồng lớp liên kết với nhau, biến hóa quỷ dị trong chiến đấu.","detail":"Lý Nguyên vung tay tạo tàn ảnh cấm chế, hợp thành mười tám đạo cấm chế liên hoàn. Vương Lâm nhận ra nếu phá giải đơn thuần sẽ tốn thời gian, nên chọn dùng lôi quang ngưng thành chưởng ấn hư ảo đánh thẳng vào hệ cấm chế này.","nguon":["@c0700"]},{"id":"loi-dinh-tu-ngon-tro-vuong-lam","name":"Lôi đình từ ngón trỏ Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông lôi pháp","phamCap":"không rõ","hePhai":"Lôi pháp","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn lôi pháp Vương Lâm phóng ra từ ngón trỏ tay phải. Một đạo lôi đình đánh tan lông chim pháp bảo của nữ tu, khiến nàng chịu phản chấn thổ huyết.","detail":"Khi nữ tu dùng quạt lông công kích, Vương Lâm không né tránh mà bước tới, đưa tay phải điểm ra. Lôi quang từ ngón trỏ bùng lên, trực tiếp phá hủy lông chim mang sát khí và làm chủ nhân pháp bảo bị thương.","nguon":["@c0700"]},{"id":"chuong-an-loi-quang-hu-ao","name":"Chưởng ấn lôi quang hư ảo","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông lôi pháp","phamCap":"không rõ","hePhai":"Lôi pháp","soHuu":["Vương Lâm"],"blurb":"Lôi quang được Vương Lâm ngưng thành chưởng ấn hư ảo để phá cấm chế trong lúc giao chiến. Thủ đoạn này dùng sức lôi đình trực diện thay vì chậm rãi phá giải cấm chế.","detail":"Đối diện mười tám cấm chế liên hoàn của Lý Nguyên, Vương Lâm nhận định đây là chiến đấu nên không cần phá giải từng bước. Hắn ngưng lôi quang thành chưởng ấn hư ảo, đánh thẳng vào cấm chế chồng lớp.","nguon":["@c0700"]},{"id":"cam-che-an-giau-than-hinh-cua-ly-nguyen","name":"Cấm chế ẩn giấu thân hình của Lý Nguyên","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Cấm chế của Lý Nguyên","soHuu":["Lý Nguyên","Vương Lâm"],"blurb":"Phương pháp cấm chế giúp ẩn giấu thân hình, được Lý Nguyên in vào ngọc giản giao cho Vương Lâm.","detail":"Vương Lâm yêu cầu Lý Nguyên giao ra phương pháp cấm chế ẩn giấu thân hình. Khi xem ngọc giản, hắn nhận ra hệ cấm chế này khác với tiên cấm thuật quen thuộc và chưa thể hiểu rõ ngay.","nguon":["@c0701"]},{"id":"thuat-cam-che-muoi-tam-pho-tuong","name":"Thuật cấm chế mười tám pho tượng","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Cấm chế của Lý Nguyên","soHuu":["Lý Nguyên","Vương Lâm"],"blurb":"Thuật cấm chế trong ngọc giản khiến tâm thần Vương Lâm hiện ra mười tám pho tượng lớn lồng vào nhau.","detail":"Khi Vương Lâm xem kỹ ngọc giản của Lý Nguyên, trong đầu hiện ra mười tám pho tượng lớn, mỗi pho tượng lại có một pho tượng khác bên trong, tạo cảm giác khác hẳn hệ tiên cấm hắn từng biết.","nguon":["@c0701"]},{"id":"cam-che-thien-cap-trung-pham","name":"Cấm chế thiên cấp trung phẩm","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"thiên cấp trung phẩm","hePhai":"cấm chế","soHuu":[],"blurb":"Cấm chế khổng lồ được Lý Nguyên nhận định ở trước đường đi trong Lôi Tiên Giới. Nó lấy lôi uy của Lôi Tiên Giới làm nền móng và vượt xa khả năng phá giải chắc chắn của hắn.","detail":"Trước đám sương mù tiên khí vô biên chắn đường, Lý Nguyên dùng la bàn tính toán nhưng la bàn nổ tung thành tro bụi. Sau đó hắn xác định đây là cấm chế thiên cấp trung phẩm, gồm vô số tổ hợp, lấy Lôi Tiên Giới làm nền, dùng nhiều điểm vững chắc cùng hồn linh vật làm cấm nhãn để hình thành đại trận luyện hóa vạn vật.","nguon":["@c0702"]},{"id":"diet-tuyet-dai-tran","name":"Diệt tuyệt đại trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"cấm chế","soHuu":[],"blurb":"Đại trận do cấm chế thiên cấp trung phẩm hình thành trong Lôi Tiên Giới. Theo Lý Nguyên, trận này có thể luyện hóa vạn vật trong trời đất.","detail":"Diệt tuyệt đại trận lấy lôi uy của Lôi Tiên Giới làm nền móng, dùng chín nghìn chín trăm chín mươi chín điểm vững chắc làm kết cấu và hồn linh vật làm cấm nhãn. Lý Nguyên nhận ra quy mô của nó sau khi la bàn tính toán cấm chế nổ tung, cho thấy trận pháp này vượt xa cấm chế thông thường.","nguon":["@c0702"]},{"id":"dao-nguoc","name":"Đảo ngược","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lão già chủ Lôi tiên giới cầm Lôi quang thiết liên","soHuu":["Lão già chủ Lôi tiên giới cầm Lôi quang thiết liên"],"blurb":"Thần thông không gian của lão già Lôi tiên giới, đảo lộn phương hướng trong khoảnh khắc. Vương Lâm đang bỏ chạy bị kéo ngược về trước mặt lão, không còn cách phản kháng.","detail":"Lão già vỗ nhẹ vào không trung, khiến không gian vặn vẹo như bị kéo giãn thành nhiều gợn sóng rồi hô Đảo ngược. Toàn bộ phương hướng trong không trung đảo lộn, Vương Lâm vốn đã dùng thần thông bỏ chạy liền bị lùi trở về cách lão ba trượng, tư thế vẫn như lúc đang chạy.","nguon":["@c0703"]},{"id":"than-thong-bo-chay-mau-huyet-hoc-o-yeu-linh","name":"Thần thông bỏ chạy máu huyết học ở Yêu Linh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Mảnh đất Yêu Linh","soHuu":["Vương Lâm"],"blurb":"Thần thông bỏ chạy Vương Lâm từng học ở mảnh đất Yêu Linh, vận dụng máu huyết tạo thành vòng tuần hoàn để thuấn di thoát thân. Trong chương này hắn dùng nó để thoát khỏi trảo định thân của lão già.","detail":"Khi bị trảo của lão già khóa cứng thân thể, Vương Lâm cắn chót lưỡi, nuốt giọt máu ẩn chứa tiên lực rồi vận dụng máu huyết trong người tạo thành một vòng tuần hoàn. Thần thông giúp hắn biến mất ngay trước khoảnh khắc bị bắt, nhưng sau đó vẫn bị Đảo ngược kéo trở lại.","nguon":["@c0703"]},{"id":"cam-che-tren-mi-tam-cua-ly-nguyen","name":"Cấm chế trên mi tâm của Lý Nguyên","cn":"","loai":"than-thong","loaiLabel":"Cấm chế thần thông","phamCap":"không rõ","hePhai":"Cấm chế","soHuu":["Lý Nguyên"],"blurb":"Cấm chế ở mi tâm giúp Lý Nguyên vận dụng thần thức quan sát trạng thái của Vương Lâm trong hành trình trên đại lục Lôi tiên giới.","detail":"Trong lúc phi hành, Lý Nguyên dùng ánh sáng cấm chế ở mi tâm để theo dõi biến hóa trong thân thể Vương Lâm. Hắn nhận định tu vi Vương Lâm càng cao càng có lợi cho chuyến đi, nhưng nếu đạt tới Âm Dương hư thực thì sẽ phát sinh biến số.","nguon":["@c0704"]},{"id":"cam-che-can-tim","name":"Cấm chế cần tìm","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Cấm chế","soHuu":["Lý Nguyên"],"blurb":"Mục tiêu cấm chế mà Lý Nguyên dẫn Vương Lâm và Cát Hồng tìm kiếm trên đại lục trong Lôi tiên giới.","detail":"Sau khi tới trung tâm đại lục và đối chiếu địa hình với ký ức, Lý Nguyên xác định cấm chế không nằm tại chỗ đó mà đại khái ở phía đông. Hành trình tiếp tục thêm ba tháng, cuối cùng dừng trước ngọn núi cao vút trong mây mà hắn xác nhận là nơi cần tìm.","nguon":["@c0704"]},{"id":"mai-hoa-thuat","name":"Mai hoa thuật","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"Cấm chế cổ đã thất truyền","hePhai":"Truyền thừa Mai hoa thuật","soHuu":["Lý Nguyên"],"blurb":"Mai hoa thuật là cấm chế cổ nổi danh, có dấu vết từng xuất hiện trong tiên phủ ở mảnh đất Yêu Linh. Vương Lâm nhận ra dấu hiệu của nó trên cấm chế của Lý Nguyên và yêu cầu lấy pháp môn này làm thù lao.","detail":"Mai hoa thuật có danh tiếng rất lớn trong cấm chế cổ, tồn tại phân nhánh và quy củ truyền thừa nghiêm ngặt. Theo hiểu biết của Vương Lâm, người ngoài không thể tùy tiện học, đệ tử đích hệ cũng chỉ học được một phần, còn đầy đủ nhất thuộc về chưởng môn; vì vậy khi Lý Nguyên lộ phản ứng trước lời thăm dò, Vương Lâm xác nhận hắn thi triển đúng là Mai hoa thuật.","nguon":["@c0705"]},{"id":"cam-che-tren-ngon-nui-vo-danh","name":"Cấm chế trên ngọn núi vô danh","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Lý Nguyên"],"blurb":"Hệ thống cấm chế bao phủ ngọn núi vô danh trong Lôi tiên giới, từng bị người đời trước phá bớt qua nhiều lần Lôi tiên giới mở ra. Dù vậy ngọn núi vẫn mang sức hạn chế khiến Lý Nguyên dùng nó để gây sức ép với Vương Lâm.","detail":"Ngọn núi vô danh có nhiều lớp cấm chế phủ kín, không phải tự nhiên có đường lên núi mà là do người dò xét các đời trước dần bài trừ một phần. Lý Nguyên dựa vào địa thế và cấm chế nơi này để nói rằng Vương Lâm đã bước lên núi thì không thể tự rời đi nếu không được cho phép.","nguon":["@c0705"]},{"id":"mai-hoa-thap-tam-cam","name":"Mai hoa thập tam cấm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm thuật","phamCap":"thuộc Mai Hoa thuật","hePhai":"cấm chế","soHuu":["Lý Nguyên","Vương Lâm"],"blurb":"Mai hoa thập tam cấm là phần đầu của Mai Hoa thuật được Lý Nguyên giao cho Vương Lâm trong ngọc giản. Nội dung gồm mười ba hình ảnh lớn và mười ba đóa hoa mai, ẩn chứa quy tắc cấm chế.","detail":"Lý Nguyên lấy ngọc giản từ túi trữ vật giao cho Vương Lâm, nói bên trong có Mai hoa thập tam cấm. Đây là phần đầu của Mai Hoa thuật, còn năm loại khác được hắn hẹn giao sau khi vào núi.","nguon":["@c0706"]},{"id":"tu-dai-cam-thuat","name":"Tứ đại cấm thuật","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm thuật cấp Hư","phamCap":"cấp Hư","hePhai":"cấm chế","soHuu":[],"blurb":"Tứ đại cấm thuật là cấp độ cấm chế trên Thiên, Địa, Huyền, Hoàng. Lý Nguyên nói ngọn núi trước mặt do tứ đại cấm thuật tan vỡ mà tạo thành.","detail":"Trong lời giảng của Lý Nguyên, phía trên bốn cấp Thiên, Địa, Huyền, Hoàng còn có cấp Hư, gồm tứ đại cấm thuật. Ngọn núi không có điểm cuối trước mặt Vương Lâm là sản phẩm do tứ đại cấm thuật tan vỡ tạo nên.","nguon":["@c0706"]},{"id":"cap-cam-che-thien-dia-huyen-hoang","name":"Cấp cấm chế Thiên/Địa/Huyền/Hoàng","cn":"","aliases":["Thiên Địa Huyền Hoàng"],"loai":"khac","loaiLabel":"Phân cấp cấm chế","phamCap":"bốn cấp cơ bản","hePhai":"cấm chế","soHuu":[],"blurb":"Thiên, Địa, Huyền, Hoàng là bốn cấp phân chia cấm chế được Lý Nguyên giải thích trên đường lên núi. Chúng thấp hơn cấp Hư và tứ đại cấm thuật.","detail":"Lý Nguyên nói cấm chế ban đầu bắt nguồn từ quy tắc trời đất, lâu ngày được phân chia thành Thiên, Địa, Huyền, Hoàng. Trên bốn cấp này còn có một cấp độ khác là Hư.","nguon":["@c0706"]},{"id":"hoa-gia","name":"Hóa giả","cn":"","aliases":["Phương pháp hóa giả"],"loai":"khac","loaiLabel":"Phương pháp phá giải cấm chế","phamCap":"không rõ","hePhai":"cấm chế","soHuu":["Lý Nguyên"],"blurb":"Hóa giả là phương pháp hóa giải cần dùng để tìm tòi và nhìn thấu ngọn núi cấm thuật. Lý Nguyên cho rằng nếu không có cách hóa giả chính xác thì không thể thấy hết ngọn núi trong mây mù.","detail":"Khi giải thích lai lịch ngọn núi, Lý Nguyên nhấn mạnh người không biết phương pháp hóa giả sẽ không thể tìm tòi toàn bộ ngọn núi, bởi nơi này do tứ đại cấm thuật tan vỡ tạo nên và không có điểm cuối theo cách nhìn thông thường.","nguon":["@c0706"]},{"id":"an-quyet-tren-canh-tay-phai-tuong-da","name":"Ấn quyết trên cánh tay phải tượng đá","cn":"","aliases":["Ấn quyết trên tượng đá"],"loai":"khac","loaiLabel":"Ấn quyết cấm chế","phamCap":"không rõ","hePhai":"cấm chế","soHuu":["Chủ nhân của Lý Nguyên"],"blurb":"Ấn quyết phức tạp nằm trên cánh tay phải tượng đá ở đỉnh núi. Khi Vương Lâm nhìn kỹ, tâm thần hắn chấn động và bị kéo vào huyễn cảnh chiến trường Tiên giới.","detail":"Trên tượng đá trung niên nam tử ở đỉnh núi có ấn quyết phức tạp. Vương Lâm vừa nhìn thấy ấn quyết này thì tinh thần chấn động, tầm mắt tối lại và hắn chứng kiến cảnh tiên nhân lôi điện giao chiến cùng thanh bảo kiếm tím.","nguon":["@c0706"]},{"id":"no-an","name":"Nô ấn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Tiên thuật / ấn ký","phamCap":"Không rõ","hePhai":"Tiên nhân tượng đá","soHuu":["Chủ nhân của Lý Nguyên"],"blurb":"Thủ ấn trên tượng đá là tiên thuật truyền thừa nô lệ, không truyền lực lượng mà khắc dấu nô hóa lên huyết mạch hậu nhân Lý gia.","detail":"Nô ấn khiến Lý gia sau lần đầu vào Lôi tiên giới bị hút mất tiềm lực, không vượt qua Vấn Đỉnh đại viên mãn và tuổi thọ chỉ còn một phần ba người cùng cảnh giới. Dù trải qua thời gian dài đã suy yếu, thủ ấn vẫn có thể xâm nhập tâm thần Vương Lâm khi hắn quan sát tượng đá.","nguon":["@c0707"]},{"id":"thuat-cam-che-cua-ly-gia","name":"Thuật cấm chế của Lý gia","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Lý gia","soHuu":["Lý Nguyên"],"blurb":"Lý gia nổi danh ở La Thiên tinh vực nhờ sở trường phá cấm chế và tu luyện cấm chế.","detail":"Thuật cấm chế là nền tảng của Lý gia, từng giúp gia tộc trở thành một trong sáu gia tộc cổ. Trong chương này, Lý Nguyên dùng nhiều đạo thủ ấn do cấm chế tạo thành đánh vào mi tâm để tạm thời khống chế nô ấn khi cảm xúc dao động.","nguon":["@c0707"]},{"id":"thuat-cam-che-quan-sat","name":"Thuật cấm chế quan sát","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Lý gia","soHuu":["Lý Nguyên"],"blurb":"Cấm chế được Lý Nguyên dùng để quan sát trận chiến của Vương Lâm với tu sĩ Âm Hư.","detail":"Lý Nguyên nói nhờ thuật cấm chế này mà hắn đã quan sát toàn bộ trận chiến của Vương Lâm với tu sĩ Âm Hư, từ đó biết đến thần thông Định Thân thuật mà hắn muốn mượn để xử lý linh hồn bất diệt trong tượng đá.","nguon":["@c0708"]},{"id":"cam-che-tam-giac-den","name":"Cấm chế tam giác đen","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Lý gia","soHuu":["Lý Nguyên"],"blurb":"Cấm chế dùng sợi tơ đen kết thành tam giác để trói chặt tiên vệ khôi lỗi.","detail":"Khi tiên vệ khôi lỗi của Vương Lâm đánh tới, Lý Nguyên bắt quyết tạo sợi tơ đen thành hình tam giác, phóng lớn rồi bao phủ toàn thân tiên vệ, khiến khôi lỗi không thể giãy thoát.","nguon":["@c0708"]},{"id":"tran-phap-khong-lo-tren-dai-luc-nho","name":"Trận pháp khổng lồ trên đại lục nhỏ","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":[],"blurb":"Trận pháp nằm ở trung tâm một đại lục nhỏ trong Lôi Tiên giới, nơi Huyết Tổ xuất hiện.","detail":"Trận pháp khổng lồ được bốn lão nhân tóc bạc canh giữ; khi Huyết Tổ xuất hiện trong trận, bốn người mở mắt với vẻ ngưng trọng.","nguon":["@c0708"]},{"id":"cam-che-ly-gia","name":"Cấm chế Lý gia","cn":"","loai":"khac","loaiLabel":"Cấm chế gia tộc","phamCap":"không rõ","hePhai":"Lý gia","soHuu":["Lý Nguyên","Lý gia"],"blurb":"Hệ cấm chế truyền thừa của Lý gia, bị ảnh hưởng vì trong linh hồn Lý Nguyên tồn tại hai suy nghĩ xung đột.","detail":"Vương Lâm nhận ra linh hồn Lý Nguyên chưa tiêu tán nhưng bị tàn hồn nô ấn cùng tồn tại, khiến các cấm chế Lý gia khi thi triển như Mai Hoa thuật và Phá Diệt cấm đều khó phát huy toàn bộ uy lực.","nguon":["@c0709"]},{"id":"tam-cam","name":"Tâm cấm","cn":"","loai":"khac","loaiLabel":"Truyền thừa cấm chế","phamCap":"truyền thừa gia chủ Lý gia","hePhai":"Lý gia","soHuu":["Lý Nguyên"],"blurb":"Tâm cấm là phần then chốt để thật sự nắm Phá Diệt cấm của Lý gia. Lý Nguyên nói chỉ mỗi đời gia chủ được truyền thừa và hứa chia một nửa cho Vương Lâm.","detail":"Tâm cấm không phải chỉ là khẩu quyết bên ngoài mà là phần lõi khiến Phá Diệt cấm phát huy chân chính. Lý Nguyên giải thích người ngoài dù biết khẩu quyết vẫn thiếu tâm đối với cấm chế, còn tâm cấm được truyền trong từ đường truyền thừa của Lý gia và chỉ dành cho gia chủ mỗi đời.","nguon":["@c0710","@c0725"]},{"id":"hoa-mai-cam-thuat","name":"Hoa Mai cấm thuật","cn":"","loai":"khac","loaiLabel":"Cấm thuật","phamCap":"phái sinh từ Phá Diệt cấm","hePhai":"Lý gia","soHuu":["Lý gia"],"blurb":"Hoa Mai cấm thuật được Lý Nguyên nói là sinh ra từ Phá Diệt cấm. Do từng bị truyền ra ngoài, cấm thuật này có nhiều người biết.","detail":"Trong lời giải thích của Lý Nguyên, Hoa Mai cấm thuật chỉ là một nhánh sinh ra từ Phá Diệt cấm, không phải phần lõi chân chính. Việc Lý gia từng bị nô ấn khống chế khiến một phần truyền thừa bị lan ra ngoài.","nguon":["@c0710"]},{"id":"tien-cam-lay-bun-dat-lam-chinh","name":"Tiên cấm lấy bùn đất làm chính","cn":"","loai":"khac","loaiLabel":"Tiên cấm","phamCap":"tiên cấm","hePhai":"không rõ","soHuu":[],"blurb":"Tiên cấm trên mảnh đại lục hoang vu dùng khung cảnh và bùn đất để che giấu thần thức. Lý Nguyên nhận ra kết cấu của nó rồi phá giải, làm lộ ra tiên sơn và cung điện rách nát.","detail":"Cấm chế này lấy bùn đất làm chủ, dùng hoàn cảnh trên mặt đất để che mắt người ngoài. Khi Lý Nguyên rút tơ đen từ mi tâm hóa thành phù ấn và vỗ xuống đất, khu vực xung quanh sụp xuống, lộ ra ngọn núi có cung điện cùng dấu vết nơi trồng tiên thảo từng bị đào sạch.","nguon":["@c0710"]},{"id":"phap-thu-ba-trong-bat-phap-cua-tien-cam","name":"Pháp thứ ba trong bát pháp của tiên cấm","cn":"","loai":"bi-thuat","loaiLabel":"Cấm pháp huyễn thuật","phamCap":"Tiên cấm","hePhai":"Tiên cấm","soHuu":["Lý Nguyên"],"blurb":"Một pháp trong bát pháp của tiên cấm, lấy huyễn thuật làm chính. Lý Nguyên nhận ra cấm chế quanh cái cây thuộc loại này sau khi phá cảnh giả.","detail":"Cấm pháp này tạo ra cảnh cây cối, hài cốt và giáp da như một huyễn tượng che giấu truyền tống trận bên dưới. Sau khi bị Lý Nguyên phá, toàn bộ cảnh tượng tan vỡ, lộ ra trận pháp phát sáng dịu.","nguon":["@c0711"]},{"id":"cam-che-hoa-mai-muoi-tam-doa","name":"Cấm chế hoa mai mười tám đóa","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Mai hoa thuật","soHuu":["Lý Nguyên"],"blurb":"Cấm chế do Lý Nguyên thi triển, hóa thành mười tám đóa hoa mai để công phá huyễn cảnh. Chiêu này được dùng trực tiếp lên khu vực cái cây.","detail":"Lý Nguyên bắt quyết tạo một đạo cấm chế, cấm chế hóa thành mười tám đóa hoa mai đánh vào khu vực cái cây. Sau cú phá này, cây cối và hài cốt trong huyễn cảnh biến mất, truyền tống trận ẩn bên dưới hiện ra.","nguon":["@c0711"]},{"id":"truyen-tong-tran","name":"Truyền tống trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Trận pháp ẩn dưới huyễn cấm quanh cái cây, trở thành lối thoát của Vương Lâm và Lý Nguyên. Sau khi lộ ra ngoài, trận xuất hiện dấu hiệu bất ổn và sắp hủy.","detail":"Truyền tống trận phát sáng dịu sau khi cảnh giả bị phá. Do tiếp xúc với ngoại giới và tiên khí, mép trận sinh ra nhiều dòng xoáy nhỏ, hiện ảo ảnh kiến trúc cổ và thi thể hài cốt, khiến Vương Lâm cùng Lý Nguyên phải gấp rút lao vào trước khi bị truy sát chặn lại.","nguon":["@c0711"]},{"id":"cam-che-ngan-am-hon","name":"Cấm chế ngăn âm hồn","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Cấm chế Lý gia","soHuu":["Lý Nguyên"],"blurb":"Cấm chế phòng ngự do Lý Nguyên thi triển để ngăn vô số âm hồn trong sương đỏ. Nó được dùng khi Vương Lâm ôm Lý Nguyên lao về truyền tống trận.","detail":"Trước làn sương đỏ hóa thành vô số âm hồn, Lý Nguyên liên tục tạo cấm chế; một hóa mười tám rồi lan thành nhiều lớp để cản âm hồn đang truy kích. Nhờ vậy hai người tạm thời kéo dài khoảng cách với thế công của chủ nhân thần thức.","nguon":["@c0711"]},{"id":"ngung-huyet","name":"Ngưng huyết","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Bóng người màu hồng"],"blurb":"Thần thông của chủ nhân thần thức cực mạnh, dùng để khóa không gian trong phạm vi trăm trượng. Khi thi triển, Vương Lâm và Lý Nguyên bị giữ lại chỉ cách truyền tống trận vài bước.","detail":"Ngưng huyết khiến không gian quanh mục tiêu như bị dồn nén và đông cứng, làm mọi vật trong phạm vi trăm trượng gần như đứng yên. Sức ép này khiến Vương Lâm và Lý Nguyên không thể nhấc tay dùng pháp bảo, bị chặn trước lối thoát trong lúc bóng người màu hồng lao tới.","nguon":["@c0711"]},{"id":"cam-che-ngan-cach-bon-phia-cua-vuong-lam","name":"Cấm chế ngăn cách bốn phía của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Cấm chế","phamCap":"Không nêu","hePhai":"Cấm chế","soHuu":["Vương Lâm"],"blurb":"Cấm chế tạm thời do Vương Lâm dựng quanh khu vực nói chuyện với Diêu Tích Tuyết.","detail":"Sau khi tới không gian lạ và cân nhắc tình thế Huyết Tổ, Vương Lâm bố trí cấm chế ngăn cách bốn phía trước khi lấy Diêu Tích Tuyết ra khỏi túi trữ vật để đối thoại.","nguon":["@c0712"]},{"id":"cam-che-giam-dieu-tich-tuyet","name":"Cấm chế giam Diêu Tích Tuyết","cn":"","loai":"than-thong","loaiLabel":"Cấm chế phong ấn","phamCap":"Không nêu","hePhai":"Cấm chế","soHuu":["Vương Lâm"],"blurb":"Vòng sáng cấm chế dùng để phong giữ Diêu Tích Tuyết trong tay Vương Lâm.","detail":"Cấm chế hiện ra như vòng sáng nở tựa hoa sen, bên trong là Diêu Tích Tuyết đang bị giam giữ; sau cuộc đối thoại, Vương Lâm lại gia cố cấm chế rồi thu nàng trở lại túi trữ vật.","nguon":["@c0712"]},{"id":"cam-che-suong-mu-thung-lung-thu-nhat","name":"Cấm chế sương mù thung lũng thứ nhất","cn":"","loai":"than-thong","loaiLabel":"Cấm chế trận pháp","phamCap":"Không nêu","hePhai":"Cấm chế","soHuu":[],"blurb":"Cấm chế ẩn trong thung lũng thứ nhất của không gian trữ vật tiên nhân.","detail":"Bề ngoài chỉ là lớp sương mù mỏng bị Lý Nguyên phá như cấm chế đơn giản, nhưng khi Tiên vệ bước vào thì sương mù tái hiện, ngưng tụ thành các mũi tên sắc bén đánh bật Tiên vệ ra ngoài.","nguon":["@c0712"]},{"id":"cam-che-sang-toi-cua-tru-vat-khong-gian","name":"Cấm chế sáng/tối của trữ vật không gian","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"","soHuu":["Tiên nhân vô danh"],"blurb":"Cấm chế hai tầng trong thung lũng thứ nhất, có lớp lộ và lớp ngầm.","detail":"Lý Nguyên nhận định cấm chế này chuyên nhằm vào người quá tự tin về cấm chế; nếu chỉ nhìn lớp ngoài sẽ rơi vào sát cục ẩn bên trong.","nguon":["@c0713"]},{"id":"huyet-quang-bo-chay","name":"Huyết quang bỏ chạy","cn":"","loai":"than-thong","loaiLabel":"Thần thông độn tốc","phamCap":"Cần Vấn Đỉnh đại viên mãn mới dùng an toàn","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông độn tốc cực nhanh lấy từ hồn phách lão già ở vùng đất Yêu Linh.","detail":"Vương Lâm kích phát huyết quang liên tiếp chín lần để đạt tốc độ gần như thuấn di, nhờ đó vượt vùng khe nứt tới thung lũng thứ hai. Người dưới Vấn Đỉnh đại viên mãn dùng thuật này sẽ có nguy cơ nổ tan xác.","nguon":["@c0713"]},{"id":"cam-che-hoa-mai","name":"Cấm chế hoa mai","cn":"","loai":"khac","loaiLabel":"Cấm chế tổ hợp","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Tổ hợp hơn mười đạo cấm chế thành hình hoa mai để thăm dò lối vào thung lũng thứ hai.","detail":"Mỗi đạo cấm chế phân thành mười bốn phần rồi tổ hợp, được Vương Lâm dùng để dẫn dụ bóng ma vô hình cắn nuốt, qua đó phối hợp con mắt thứ ba quan sát cơ chế quầng sáng.","nguon":["@c0713"]},{"id":"kiem-tran-tam-doan-kiem","name":"Kiếm trận tám đoản kiếm","cn":"","loai":"kiem-quyet","loaiLabel":"Trận thế kiếm khí","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Trận thế do tám đoản kiếm phối hợp công kích trong thung lũng chứa đầu thú.","detail":"Tám kiếm từ tám hướng truy sát, kiếm khí chứa tiên lực và tạo sát khí dày đặc, ép Vương Lâm vào hiểm cảnh sau khi đầu thú bị lấy.","nguon":["@c0714"]},{"id":"pha-thien-cam","name":"Phá Thiên cấm","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Truyền thừa Lý gia","hePhai":"Lý gia","soHuu":["Lý Nguyên"],"blurb":"Cấm chế Lý Nguyên dùng để bố trí các điểm sụp đổ trong không gian trữ vật.","detail":"Một ngàn bốn trăm sáu mươi lăm điểm sụp đổ được đặt bằng Phá Thiên cấm. Khi Vương Lâm đưa tiên lực vào cầu cấm chế, toàn bộ hệ thống có thể nổ đồng loạt khiến không gian sụp đổ.","nguon":["@c0715","@c0738"]},{"id":"cam-che-sup-do-tru-vat-khong-gian","name":"Cấm chế sụp đổ trữ vật không gian","cn":"","loai":"khac","loaiLabel":"Cấm chế trận","phamCap":"Không rõ","hePhai":"Lý gia","soHuu":["Lý Nguyên","Vương Lâm"],"blurb":"Hệ thống cấm chế đặt tại các điểm sụp đổ trong trữ vật không gian.","detail":"Được bố trí để làm toàn bộ trữ vật không gian sụp đổ trong nháy mắt, trở thành bẫy nhắm vào Huyết Tổ và Diêu Tích Tuyết.","nguon":["@c0715"]},{"id":"cam-che-an-giau-khi-tuc-cua-ly-nguyen","name":"Cấm chế ẩn giấu khí tức của Lý Nguyên","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Lý gia","soHuu":["Vương Lâm"],"blurb":"Phương pháp cấm chế trong ngọc giản Lý Nguyên giúp Vương Lâm che giấu bản thể.","detail":"Vương Lâm nghiên cứu trong một tháng rồi dùng để lập quả cầu cấm chế quanh bản thể, phối hợp kế nghi binh bằng Tiên vệ để tránh bị Huyết Tổ trực tiếp tìm ra.","nguon":["@c0716"]},{"id":"qua-cau-cam-che-an-ban-the","name":"Quả cầu cấm chế","cn":"","loai":"khac","loaiLabel":"Cấm chế phòng hộ","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Nhiều đạo cấm chế khép quanh thân Vương Lâm thành quả cầu để ẩn bản thể.","detail":"Quả cầu co rút thành điểm sáng biến mất, giúp bản thể Vương Lâm ẩn sâu trong lòng đất trong khi Tiên vệ ra ngoài làm mồi nhử.","nguon":["@c0716"]},{"id":"nguyen-than-dung-nhap-tien-ve","name":"Nguyên thần dung nhập Tiên vệ","cn":"","loai":"than-thong","loaiLabel":"Thần thông điều khiển","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông cho phép nguyên thần người luyện chế dung nhập thân Tiên vệ để điều khiển.","detail":"Vương Lâm tách một luồng nguyên thần khỏi bản thể rồi nhập vào Tiên vệ, biến con rối thành thân thể hoạt động bên ngoài nhằm dụ Huyết Tổ.","nguon":["@c0716"]},{"id":"than-thuc-buoc-thu-hai","name":"Thần thức bước thứ hai","cn":"","loai":"than-thong","loaiLabel":"Thần thông áp chế","phamCap":"Bước thứ hai","hePhai":"","soHuu":["Diêu Không"],"blurb":"Thần thức của Huyết Tổ mang uy năng bước thứ hai, ép đại lục mơ hồ sụp đổ.","detail":"Khi Huyết Tổ giáng lâm, thần thức quét ngang mảnh vỡ đại lục, tạo áp lực khiến tu sĩ run rẩy và không gian như muốn sụp đổ.","nguon":["@c0717"]},{"id":"mot-chi-cua-huyet-to","name":"Một chỉ của Huyết Tổ","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"Bước thứ hai","hePhai":"","soHuu":["Diêu Không"],"blurb":"Một chỉ Huyết Tổ điểm thẳng về mi tâm Vương Lâm trong thân Tiên vệ.","detail":"Dù Huyết Tổ thu bớt lực vì lời uy hiếp liên quan Diêu Tích Tuyết, dư lực vẫn khiến thân Tiên vệ phun máu, xương cốt vỡ nhiều nơi và mặt đất nứt toác.","nguon":["@c0717"]},{"id":"truyen-tong-tran-tinh-the","name":"Truyền tống trận tinh thể","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không ổn định","hePhai":"Lý gia","soHuu":["Vương Lâm"],"blurb":"Trận pháp từ tinh thể truyền tống do Vương Lâm phun ra trước mặt Huyết Tổ.","detail":"Tinh thể chạm đất hóa thành truyền tống trận không ổn định, mang khí tức Diêu Tích Tuyết, được Vương Lâm dùng làm dương mưu ép Huyết Tổ lựa chọn.","nguon":["@c0717"]},{"id":"bien-mau-luyen-hoa","name":"Biển máu luyện hóa","cn":"","loai":"than-thong","loaiLabel":"Thần thông luyện hóa","phamCap":"Bước thứ hai","hePhai":"","soHuu":["Diêu Không"],"blurb":"Thần thông Huyết Tổ dùng để luyện hóa thân Tiên vệ và nguyên thần phân ra của Vương Lâm.","detail":"Biển máu bao phủ hư vô, ngưng lại quanh Tiên vệ rồi xâm nhập từ lông tóc vào trong, khiến nguyên thần phân ra của Vương Lâm đau đớn như bị xé nát.","nguon":["@c0717"]},{"id":"huyet-quang-truy-ban-the","name":"Huyết quang truy bản thể","cn":"","loai":"than-thong","loaiLabel":"Thần thông truy sát","phamCap":"Không rõ","hePhai":"","soHuu":["Diêu Không"],"blurb":"Đạo huyết quang từ thiên linh Tiên vệ phá hư vô truy tới bản thể Vương Lâm.","detail":"Huyết quang lần theo liên hệ với nguyên thần phân ra, xuyên qua hư vô và dưới đại địa ngưng thành hồng châm truy sát bản thể Vương Lâm đang ẩn nấp.","nguon":["@c0717"]},{"id":"tu-bao-tien-ve-am-hu","name":"Tự bạo Tiên vệ Âm hư","cn":"","loai":"bi-thuat","loaiLabel":"Tự bạo","phamCap":"Âm hư","hePhai":"","soHuu":["Vương Lâm","Tiên vệ"],"blurb":"Vương Lâm thông qua liên hệ với Tiên vệ chưa bị luyện hóa hết, khiến con rối Âm hư tự bạo để phá truyền tống trận của Huyết Tổ.","detail":"Dù bị thần thông của Huyết Tổ làm tan rã phần lớn lực lượng, sức tự bạo còn lại vẫn đánh sụp truyền tống trận đúng lúc Huyết Tổ định thoát khỏi trữ vật không gian.","nguon":["@c0718"]},{"id":"dong-than-hoa-huyet","name":"Dong thần hóa huyết","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật huyết hệ","phamCap":"Dòng chính Diêu gia","hePhai":"Diêu gia","soHuu":["Diêu Không"],"blurb":"Bí thuật dòng chính Diêu gia khiến người thi triển hóa thành vô số giọt máu chứa nguyên thần để bảo toàn sinh cơ.","detail":"Huyết Tổ dùng ba viên Huyết Hồn đan phối hợp bí thuật này sau khi trữ vật không gian sụp đổ; các giọt máu cần thời gian dung hợp để nguyên thần thức tỉnh.","nguon":["@c0718"]},{"id":"long-phong-an-bang-tinh-khi-nguyen-than-va-tien-luc","name":"Lồng phong ấn bằng tinh khí nguyên thần và tiên lực","cn":"","loai":"bi-thuat","loaiLabel":"Phong ấn","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn Vương Lâm dùng tinh khí nguyên thần tạo lồng vây, rồi dùng tiên lực co rút thành phong ấn.","detail":"Được dùng để bắt giữ hồng châm đang suy yếu, biến thần thông truy sát thành dấu vết dẫn đường tới Huyết Tổ.","nguon":["@c0718"]},{"id":"than-the-co-than-bon-sao","name":"Thân thể Cổ Thần bốn sao","cn":"","loai":"luyen-the","loaiLabel":"Cổ Thần thể","phamCap":"Bốn sao","hePhai":"Cổ Thần","soHuu":["Vương Lâm bản tôn"],"blurb":"Thân thể Cổ Thần bốn sao của bản tôn Vương Lâm, khi buông áp chế có thể hóa thành người khổng lồ trăm trượng.","detail":"Trong tinh không, hình thể này mang phù văn, khí tức hoang dã và uy nghiêm Cổ Thần, khiến tu sĩ và mãnh thú xung quanh kinh sợ.","nguon":["@c0720"]},{"id":"co-than-thuat-che-giau-dau-hieu","name":"Cổ Thần thuật che giấu dấu hiệu","cn":"","loai":"bi-thuat","loaiLabel":"Cổ Thần thuật","phamCap":"không rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm bản tôn"],"blurb":"Thủ đoạn Cổ Thần dùng để che giấu điểm sao ở mi tâm.","detail":"Vương Lâm dùng ấn ký viễn cổ che điểm sáng Cổ Thần, khiến người tu vi không đủ mạnh khó nhìn ra thân phận thật.","nguon":["@c0720"]},{"id":"hoa-linh","name":"Hóa linh","cn":"","loai":"bi-thuat","loaiLabel":"Cổ Thần hộ mệnh thần thông","phamCap":"Cổ Thần lúc nhỏ","hePhai":"Cổ Thần","soHuu":["Vương Lâm bản tôn"],"blurb":"Thần thông hộ mạng của Cổ Thần lúc nhỏ, có thể dung nhập vào tinh cầu để ẩn giấu.","detail":"Người dùng có thể hút linh lực tinh cầu, chuyển hóa thành linh khí bản thân và ngủ say để tránh bị tu sĩ dưới cấp Cổ Thần phát hiện.","nguon":["@c0720"]},{"id":"thien-kiep","name":"Thiên Kiếp","cn":"","loai":"khac","loaiLabel":"Thiên uy/kiếp lôi","phamCap":"không rõ","hePhai":"","soHuu":[],"blurb":"Tầng mây và sấm sét bao phủ mảnh lục địa Lôi Tiên Giới, liên tục giáng xuống cơ thể Vương Lâm.","detail":"Huyết Tổ nhận ra đây là Thiên Kiếp do tu luyện dẫn tới nên không dám xông vào, sợ trở thành người giúp Vương Lâm chống kiếp.","nguon":["@c0721"]},{"id":"thien-luyen","name":"Thiên luyện","cn":"","loai":"khac","loaiLabel":"Quá trình luyện hóa bởi thiên lôi","phamCap":"hiếm thấy","hePhai":"","soHuu":[],"blurb":"Quá trình thiên lôi luyện vật như trong hồng lô trời đất, không do tu sĩ trực tiếp luyện ra.","detail":"Mảnh lục địa Lôi Tiên Giới vì từng là vật liệu tiên giới chịu Tiên Lôi nhiều năm nên dưới thiên lôi không hủy diệt hoàn toàn mà dần hóa thành phôi pháp bảo.","nguon":["@c0721"]},{"id":"duong-thuc","name":"Dương Thực","cn":"","loai":"khac","loaiLabel":"Cảnh giới","phamCap":"Bước quá độ sau Âm Hư","hePhai":"Tu luyện nguyên lực","soHuu":[],"blurb":"Dương Thực là giai đoạn tiên lực tiêu tán và bị nguyên lực thay thế trong cơ thể tu sĩ.","detail":"Chương giải thích Dương Thực cùng Âm Hư tạo thành ranh giới chuyển hóa giữa bước thứ nhất và bước thứ hai; ở giai đoạn này tiên lực dần bị nguyên lực thay thế, đưa tu sĩ tiến gần hình thái Luyện Khí Sĩ.","nguon":["@c0722"]},{"id":"hoa-nguyen","name":"Hóa Nguyên","cn":"","loai":"khac","loaiLabel":"Quá trình tu luyện","phamCap":"Chuyển hóa nguyên lực","hePhai":"Tu luyện nguyên lực","soHuu":[],"blurb":"Hóa Nguyên là quá trình tu sĩ chuyển hóa tiên lực sang nguyên lực.","detail":"Quá trình này khiến tu sĩ biến đổi sâu về nguyên thần và lực lượng trong thân, trở nên gần với Luyện Khí Sĩ thượng cổ hơn so với tu sĩ bước thứ nhất thông thường.","nguon":["@c0722"]},{"id":"nguyen-than-chan-chinh","name":"Nguyên thần chân chính","cn":"","loai":"khac","loaiLabel":"Khái niệm tu luyện","phamCap":"Sau biến đổi Âm Hư","hePhai":"Tu luyện nguyên thần","soHuu":[],"blurb":"Nguyên thần chân chính là nguyên thần sinh ra trong nguyên lực và có thể nuốt nhả nguyên lực trời đất.","detail":"Sau biến đổi Âm Hư, nguyên thần không còn chỉ là hình thái cũ của tu sĩ bước thứ nhất mà có khả năng giao hòa với nguyên lực trời đất, mở đường cho các tầng tu luyện cao hơn.","nguon":["@c0722"]},{"id":"nguyen-khi-cua-luyen-khi-si","name":"Nguyên khí của Luyện Khí Sĩ","cn":"","loai":"khac","loaiLabel":"Hệ thống tu luyện","phamCap":"Thượng cổ","hePhai":"Luyện Khí Sĩ","soHuu":[],"blurb":"Nguyên khí là khí mà Luyện Khí Sĩ thượng cổ tu luyện.","detail":"Chương nêu nguyên khí của Luyện Khí Sĩ nếu ẩn lâu trong cơ thể sẽ hóa thành thần, tức nguyên thần; tu sĩ hiện tại phải qua Âm Hư, Dương Thực và Hóa Nguyên mới miễn cưỡng đi theo dấu vết ấy.","nguon":["@c0722"]},{"id":"nguyen-than-thai-co-loi-long","name":"Nguyên thần Thái Cổ Lôi Long","cn":"","loai":"than-thong","loaiLabel":"Hình thái nguyên thần","phamCap":"Lôi hệ","hePhai":"Thái Cổ Lôi Long","soHuu":["Vương Lâm"],"blurb":"Nguyên thần của Vương Lâm hóa thành Thái Cổ Lôi Long, có thể trực tiếp thôn phệ kiếp lôi.","detail":"Trong Thiên Kiếp, nguyên thần Vương Lâm không hiện hình người mà hóa thành Thái Cổ Lôi Long, há miệng nuốt tám đạo sấm sét đen rồi đưa lực lượng trở lại thân thể.","nguon":["@c0722"]},{"id":"loi-nguyen-than","name":"Lôi nguyên thần","cn":"","loai":"than-thong","loaiLabel":"Thuộc tính nguyên thần","phamCap":"Lôi hệ","hePhai":"Thái Cổ Lôi Long","soHuu":["Vương Lâm"],"blurb":"Lôi nguyên thần giúp Vương Lâm hấp thu sấm sét và thích ứng với Thiên Kiếp.","detail":"Trong tầng mây Thiên Kiếp, lôi nguyên thần khiến Vương Lâm như cá gặp nước, có thể hút lôi lực, thôn phệ mây và chiếm ưu thế so với Huyết Tổ bị kiếp lực áp chế.","nguon":["@c0723"]},{"id":"thai-co-loi-long-hoa-than-nguyen-than","name":"Thái Cổ Lôi Long","cn":"","loai":"than-thong","loaiLabel":"Hóa thân nguyên thần","phamCap":"Lôi hệ","hePhai":"Thái Cổ Lôi Long","soHuu":["Vương Lâm"],"blurb":"Nguyên thần Vương Lâm rời thân và biến thành Thái Cổ Lôi Long dài trăm trượng.","detail":"Cuối chương, Vương Lâm đặt tay lên mi tâm, để thân thể hạ xuống tĩnh tọa còn nguyên thần lao ra hóa thành Thái Cổ Lôi Long nhằm đối đầu Huyết Tổ.","nguon":["@c0723"]},{"id":"huyet-anh","name":"Huyết ảnh","cn":"","loai":"than-thong","loaiLabel":"Thần thông huyết đạo","phamCap":"Huyết Tổ","hePhai":"Huyết đạo","soHuu":["Huyết Tổ"],"blurb":"Huyết ảnh là thần thông Huyết Tổ dùng để đối kháng Trảm La Quyết.","detail":"Huyết Tổ tạo huyết ảnh trước người để chống Trảm La Quyết của Vương Lâm, nhưng huyết ảnh tan vỡ sau va chạm và bị ảnh hưởng bởi tu vi suy giảm.","nguon":["@c0723"]},{"id":"huyet-quang-ky-hieu","name":"Huyết quang ký hiệu","cn":"","loai":"than-thong","loaiLabel":"Thần thông huyết đạo","phamCap":"Huyết Tổ","hePhai":"Huyết đạo","soHuu":["Huyết Tổ"],"blurb":"Huyết quang ký hiệu đẩy tầng mây xung quanh lui lại trong chốc lát.","detail":"Huyết Tổ bắt pháp quyết khiến huyết quang toàn thân hóa thành ký hiệu rồi tan vỡ, tạm thời đẩy tầng mây Thiên Kiếp quanh người lùi ra một trượng.","nguon":["@c0723"]},{"id":"huyet-cau-than-thong","name":"Huyết cầu","cn":"","loai":"than-thong","loaiLabel":"Thần thông huyết đạo","phamCap":"Huyết Tổ","hePhai":"Huyết đạo","soHuu":["Huyết Tổ"],"blurb":"Huyết cầu là thần thông Huyết Tổ ngưng tụ để tốc chiến tốc thắng.","detail":"Trong tầng mây Thiên Kiếp, Huyết Tổ ngưng tụ hai huyết cầu khác biệt rồi phóng về phía Vương Lâm nhằm nhanh chóng kết thúc giao chiến.","nguon":["@c0723"]},{"id":"thien-kiep-sam-set-bay-mau","name":"Thiên Kiếp sấm sét bảy màu","cn":"","loai":"khac","loaiLabel":"Thiên kiếp","phamCap":"Kiếp lôi bảy màu","hePhai":"Thiên Kiếp","soHuu":[],"blurb":"Thiên Kiếp sấm sét bảy màu vừa oanh kích Vương Lâm vừa trở thành môi trường để hắn phản kích.","detail":"Sấm sét bảy màu liên tục giáng xuống, phá hủy mảnh lục địa, luyện hóa lực lượng trong thân Vương Lâm và cho hắn cơ hội hấp thu lôi lực trong tầng mây.","nguon":["@c0723"]},{"id":"huyet-bao","name":"Huyết bạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông huyết đạo","phamCap":"Huyết Tổ","hePhai":"Huyết đạo","soHuu":["Huyết Tổ"],"blurb":"Huyết bạo là thần thông Huyết Tổ dùng huyết cầu kích nổ để đánh tan hình thái Lôi Long của Vương Lâm.","detail":"Huyết Tổ ném huyết cầu rồi kích nổ, tạo ra lực lượng lan rộng đủ mạnh khiến nguyên thần Thái Cổ Lôi Long của Vương Lâm tạm thời tiêu tán thành mưa lôi.","nguon":["@c0724"]},{"id":"huyet-phong","name":"Huyết Phong","cn":"","loai":"bi-thuat","loaiLabel":"Phong ấn huyết đạo","phamCap":"Huyết Tổ","hePhai":"Huyết đạo","soHuu":["Huyết Tổ"],"blurb":"Huyết Phong là phong ấn Huyết Tổ dùng để giam nguyên thần Vương Lâm trong Huyết Thân.","detail":"Trước luồng Thiên Kiếp cuối cùng, Huyết Tổ phun máu hóa thành phong ấn dạng lưới lớn, dùng nó khóa Huyết Thân và tranh thủ cho nguyên thần mình thoát khỏi tầng mây.","nguon":["@c0724"]},{"id":"mua-loi-nguyen-than","name":"Mưa lôi nguyên thần","cn":"","loai":"than-thong","loaiLabel":"Biến hóa nguyên thần","phamCap":"Lôi hệ","hePhai":"Thái Cổ Lôi Long","soHuu":["Vương Lâm"],"blurb":"Mưa lôi nguyên thần là biến hóa sau khi hình thái Thái Cổ Lôi Long bị Huyết bạo đánh tan.","detail":"Nguyên thần Vương Lâm phân tán thành mưa lôi từ bốn phía, quấn lấy huyết quang của Huyết Tổ và tiếp tục dẫn Thiên Kiếp ép đối phương.","nguon":["@c0724"]},{"id":"tien-cam","name":"Tiên cấm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"Tiên giới","hePhai":"Lôi tiên giới","soHuu":["Lôi tiên giới"],"blurb":"Cấm chế trong Lôi tiên giới, có thể dùng cảnh vật và bùn đất để che giấu thần thức, khiến người ngoài khó phát hiện.","detail":"Trong chương này, Lý Nguyên nhận ra khu vực đất đen có tiên cấm lấy biến đổi cảnh vật làm lớp che giấu. Pháp thứ tư tại đây không đầy đủ vì từng bị người khác phá bằng thủ pháp thô thiển; khi hắn phá cấm, bùn đất sụp xuống và lộ ra tiên sơn cùng cung điện rách nát.","nguon":["@c0710"]},{"id":"suc-dia-thanh-thon","name":"Súc Địa Thành Thốn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông di chuyển vượt xa thuấn di, Na Di và Đại Na Di, được Vương Lâm cảm ứng trong cảnh giới Dương Thực khi dung hợp thiên địa.","detail":"Khi quen thuộc cảnh giới Dương Thực, Vương Lâm thuận theo cảm giác dung hợp với thiên địa, bước một bước khiến thân thể biến mất trong hư vô. Nhờ Súc Địa Thành Thốn, hắn liên tiếp vượt khoảng cách cực xa để truy kịp Huyết Tổ, dù bản thân chưa đạt Khuy Niết; chương cũng nêu thần thông này thường thuộc tầng cấp tu sĩ bước thứ hai cao hơn mới có thể cảm ứng thi triển.","nguon":["@c0725","@c0772"]},{"id":"hoang-tuyen-nguyen-luc","name":"Hoàng tuyền nguyên lực","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Hoàng tuyền của Vương Lâm sau khi tu vi tăng lên chứa thiên địa nguyên lực, đủ sức bao phủ chiến trường và áp chế Huyết Tổ.","detail":"Trong trận với Huyết Tổ, Vương Lâm thi triển Hoàng tuyền đã biến hóa theo cảnh giới mới, khiến khu vực xung quanh đều trở thành Hoàng tuyền. Oán khí trong đó ngưng tụ thành oan hồn, đặc biệt hóa ra nhiều bóng dáng Diêu Tích Tuyết để đánh vào điểm yếu tinh thần của Huyết Tổ.","nguon":["@c0725"]},{"id":"ngung-tu-tuyen-hon","name":"Ngưng tụ tuyền hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lệnh ngưng tụ oán khí trong Hoàng tuyền thành tuyền hồn để công kích đối thủ.","detail":"Vương Lâm dùng lệnh này trong Hoàng tuyền, khiến oán khí ngưng tụ thành vô số bóng dáng Diêu Tích Tuyết. Những hình bóng này lao vào Huyết Tổ, khiến lão đau đớn về tinh thần dù biết đó chỉ là giả tượng do oán khí hóa thành.","nguon":["@c0725"]},{"id":"huyet-hoa","name":"Huyết hóa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Huyết Tổ"],"blurb":"Thần thông khiến Huyết Tổ hóa nguyên thần thành huyết trảo lớn để phản kích và phá vây.","detail":"Khi bị Hoàng tuyền áp chế, Huyết Tổ vận dụng Huyết hóa, biến toàn bộ nguyên thần thành huyết trảo lớn. Huyết trảo tạo ra ba khe nứt như cuồng long, chụp về phía Vương Lâm và xé rách Hoàng tuyền để lão lao ra.","nguon":["@c0725"]},{"id":"huyet-than-bang","name":"Huyết Thần Băng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Huyết Tổ"],"blurb":"Thần thông bộc phát hồng quang yêu dị từ nguyên thần, dùng để phá thế vây của Tôn Hồn Phiên.","detail":"Huyết Tổ dùng chú ngữ thi triển Huyết Thần Băng, khiến lực lượng từ nguyên thần bùng phát thành hồng quang yêu dị. Chiêu này đẩy lui và làm tổn hại các chủ hồn trong Tôn Hồn Phiên, khiến Kỳ Lân hồn tiêu tán, hồn thứ tư nứt vỡ, đồng thời giúp lão xé màn sương đen để tìm đường thoát.","nguon":["@c0725"]},{"id":"pha-diet-cam","name":"Phá Diệt Cấm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Lý gia","soHuu":["Lý Nguyên"],"blurb":"Thần thông cấm chế của Lý gia, giúp Lý Nguyên kéo dài mạng sống khi bị nhóm Diêu gia truy sát.","detail":"Trong lúc trọng thương, mất cánh tay phải và bị tử khí bao phủ nguyên thần, Lý Nguyên dựa vào Phá Diệt Cấm của Lý gia để chạy trốn khỏi nhóm Diêu gia. Nếu không có cấm chế này, hắn đã khó sống tới thời điểm Vương Lâm phát hiện.","nguon":["@c0725"]},{"id":"loi-dinh-tim","name":"Lôi đình màu tím","loai":"than-thong","loaiLabel":"Thần thông","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Vương Lâm nâng tay gọi lôi đình màu tím, khiến phạm vi trăm trượng đầy mây tím rồi ngưng thành cánh tay lôi đình giáng xuống.","detail":"Vương Lâm thi triển lôi đình màu tím tạo thành cánh tay lôi đình, phá vỡ tấm chắn hỏa diễm của lão già Âm Hư và khiến lôi đình xâm nhập thân thể lão.","nguon":["@c0726"]},{"id":"suu-hon-thuat","name":"Sưu hồn thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm"],"blurb":"Thần thông dùng để sưu ký ức và phá hủy thần thức mục tiêu.","detail":"Vương Lâm vận chuyển Sưu hồn thuật trên nguyên thần Sửu thúc, hủy thần thức lão, lấy ký ức liên quan Diêu gia và luyện nguyên thần thành nguyên lực cầu để trợ giúp Lý Nguyên.","nguon":["@c0727"]},{"id":"than-thong-dung-hop-voi-thien-dia","name":"Thần thông dung hợp với thiên địa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm"],"blurb":"Năng lực Vương Lâm xem là then chốt để thoát khỏi nguy cơ cực lớn.","detail":"Sau khi biết Diêu gia và Huyết Thần Tử rất mạnh, Vương Lâm vẫn tự tin nếu nắm giữ thần thông dung hợp với thiên địa thì ngay cả trước kẻ cực mạnh như Thác Sâm cũng có khả năng toàn thân trở ra.","nguon":["@c0727"]},{"id":"tran-phap-cam-che-trong-tu-mau-dao-kho","name":"Trận pháp cấm chế trong Tử Mẫu Đạo Khô","cn":"","loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"không rõ","hePhai":"Tiên gia pháp bảo","soHuu":[],"blurb":"Hệ cấm chế nằm trong bộ thú cốt và phi kiếm của Tử Mẫu Đạo Khô.","detail":"Khi nguyên thần Vương Lâm đi vào hệ thú cốt và phi kiếm, kiếm khí vô tận công kích nguyên thần, buộc hắn phải không ngừng thôi diễn cấm chế và phá mở trận pháp bên trong mới có thể lưu thần thức nhận chủ.","nguon":["@c0727"]},{"id":"cam-che-suong-mu-nguyen-luc","name":"Cấm chế sương mù nguyên lực","cn":"","loai":"khac","loaiLabel":"Cấm chế phòng hộ","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm"],"blurb":"Lớp phòng hộ do nguyên lực tản ra thành sương trắng trong phạm vi nghìn trượng.","detail":"Vương Lâm tản nguyên lực thành sương trắng bao phủ nghìn trượng, tạo uy áp như tu sĩ bước thứ hai đang bế quan để ngăn người ngoài tùy tiện xâm nhập trong lúc hắn luyện hóa thú cốt.","nguon":["@c0727"]},{"id":"tien-tran-mat-that","name":"Tiên trận mật thất","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Tiên trận","hePhai":"Lôi chi Tiên giới","soHuu":[],"blurb":"Trận pháp ẩn dưới đống đổ nát phía đông Dẫn Cơ phủ, dẫn tới mật thất của cửa hàng Tiên nhân. Khi được Lý Nguyên cưỡng ép mở bằng máu và cấm chế, trận phát sinh tiết linh rồi lộ hắc động.","detail":"Trận vốn đã mất tiên lực, không còn dao động và bị che dưới phế tích khu phía đông Dẫn Cơ phủ. Lý Nguyên nhận định đây là trận dẫn tới mật thất trong cửa hàng Tiên nhân; sau khi hắn dùng máu và hắc tuyến cấm chế khôi phục sinh cơ, trận bất ngờ phun cột sáng lên trời, phát tiết linh tính rồi mở ra hắc động tỏa dao động tiên lực.","nguon":["@c0728"]},{"id":"tu-tran","name":"Tử trận","cn":"","loai":"khac","loaiLabel":"Trạng thái trận pháp","phamCap":"Không rõ","hePhai":"Lý Nguyên nhận định","soHuu":[],"blurb":"Cách Lý Nguyên gọi trận pháp đã mất sinh cơ và không thể phá giải theo lối thông thường. Trận ở Dẫn Cơ phủ thuộc dạng này trước khi được hắn dùng biện pháp cưỡng ép khôi phục.","detail":"Tử trận là trạng thái trận pháp mất tiên lực, mất sinh cơ, khiến người phá trận không thể dùng cách giải thông thường. Trong Dẫn Cơ phủ, Lý Nguyên xác định tiên trận dưới đống đổ nát đã thành tử trận nhưng vẫn có thể được hắn khôi phục dao động sinh cơ bằng máu và cấm chế.","nguon":["@c0728"]},{"id":"hac-tuyen-cam-che","name":"Hắc tuyến cấm chế","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Cấm chế của Lý Nguyên","soHuu":["Lý Nguyên"],"blurb":"Hắc tuyến từ mi tâm Lý Nguyên bay ra, hóa thành cấm chế rơi vào tiên trận. Chính động tác này kích phát biến cố cột sáng tiết linh tại Dẫn Cơ phủ.","detail":"Sau khi dùng máu khiến tử trận xuất hiện dao động sinh cơ, Lý Nguyên phóng hắc tuyến từ mi tâm vào trận pháp. Hắc tuyến hóa thành cấm chế nhập trận, khiến tiên trận bất ngờ phun ra cột sáng sáng ngời xông thẳng lên trời và mở đầu quá trình tiết linh.","nguon":["@c0728"]},{"id":"nam-dao-hac-khi-hoa-hac-long","name":"Năm đạo hắc khí hóa hắc long","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đường gia","soHuu":["Đường Ngôn Vân"],"blurb":"Thần thông Đường Ngôn Vân dùng khi giao chiến với Vương Lâm trước hắc động.","detail":"Đường Ngôn Vân hóa tay phải thành trảo, gọi năm đạo hắc khí biến thành năm hắc long để cắn nuốt lôi quang màu tím của Vương Lâm. Về sau lôi điện bộc phát từ bên trong khiến năm hắc long lần lượt nổ tung.","nguon":["@c0729"]},{"id":"nguyen-long-thon","name":"Nguyên long thôn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đường gia","soHuu":["Đường Ngôn Vân"],"blurb":"Thần thông hắc long nghìn trượng của Đường Ngôn Vân.","detail":"Đường Ngôn Vân thi triển hắc long dài nghìn trượng, mang uy áp và nguyên lực dao động, há miệng định nuốt Thú cốt. Thần thông này bị Thú cốt của Vương Lâm phóng sát khí và u hỏa hóa thành thạch điêu màu xám rồi rơi xuống.","nguon":["@c0729"]},{"id":"nguyen-luc-de-ep-chan-thuan-di","name":"Nguyên lực đè ép chặn thuấn di","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tự nghiên cứu","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Cách vận dụng thiên địa nguyên lực của Vương Lâm để phong tỏa thuấn di trong phạm vi gần.","detail":"Vương Lâm ép kín thiên địa nguyên lực trong phạm vi trăm trượng, dùng lực đè ép khiến Đường Ngôn Vân không thể thuấn di chạy trốn. Chương nêu rõ đây là thần thông do Vương Lâm tự mình nghiên cứu.","nguon":["@c0729"]},{"id":"cam-che-cua-ly-nguyen","name":"Cấm chế của Lý Nguyên","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Cấm chế","soHuu":["Lý Nguyên"],"blurb":"Cấm chế do Lý Nguyên thi triển tại cửa hắc động để giữ đường lui. Hắc tuyến từ mi tâm hóa thành nhiều cấm chế bao quanh khu vực, tạm thời ngăn người ngoài tiến vào.","detail":"Tại khu hắc động, Lý Nguyên biết tu vi của mình khó trực tiếp giúp Vương Lâm đối địch nên lùi về cửa vào, kết pháp quyết tại mi tâm rồi thả hắc tuyến ra ngoài. Hắc tuyến này nhanh chóng hóa thành cấm chế bao quanh hắc động, mục đích là phong tỏa lối vào trong thời gian ngắn.","nguon":["@c0730"]},{"id":"uy-ap-nguyen-luc-bang-anh-mat-va-buoc-chan","name":"Uy áp nguyên lực bằng ánh mắt và bước chân","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Nguyên lực","soHuu":["Vương Lâm"],"blurb":"Ứng dụng nguyên lực của Vương Lâm qua ánh mắt và từng bước chân. Chiêu này khiến đối thủ cảm giác thân thể, nguyên thần bị nhìn thấu rồi bị nguyên lực dẫn động đến sụp đổ.","detail":"Trong phạm vi nghìn trượng quanh hắc động, Vương Lâm không dùng pháp bảo mà lấy ánh mắt và bước chân ép chết nam tử trung niên xâm nhập cấm địa. Đối phương bị cảm giác toàn thân và nguyên thần bị nhìn thấu, sau đó nguyên lực trong cơ thể nghịch chuyển, tim sụp đổ và nguyên thần bị xé nát; Đường Ngôn Phong nhìn thấy cũng đánh giá đây là cách vận dụng nguyên lực cực kỳ xảo diệu.","nguon":["@c0730"]},{"id":"dai-tran-chua-thuong-chin-ky-hieu","name":"Đại trận chữa thương chín ký hiệu","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Tiên giới","hePhai":"Tiên Cấm","soHuu":[],"blurb":"Đại trận chữa thương khổng lồ được Lý Nguyên suy đoán từ ký hiệu thông đạo trong Lôi Tiên Giới.","detail":"Ký hiệu do thông đạo tạo thành có công dụng chữa thương. Lý Nguyên suy đoán có chín thông đạo hoặc chín dấu ấn ký hiệu hợp lại thành một đại trận chữa thương khổng lồ, muốn dựng nên phải trả giá cực lớn.","nguon":["@c0731"]},{"id":"dai-tran-chua-thuong","name":"Đại trận chữa thương","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Người bên trong trận pháp"],"blurb":"Trận pháp được suy đoán dùng để duy trì hoặc chữa thương cho một tồn tại ẩn bên trong qua vô số năm.","detail":"Vương Lâm và Lý Nguyên căn cứ vào cơn lốc xoáy, trận nhãn và trạng thái khóa kín bên trong để suy đoán đại trận này có thể đang được một tồn tại dùng chữa thương. Nếu thật sự có người tồn tại lâu dài trong trận, Vương Lâm cho rằng khả năng rất lớn đó là tiên nhân.","nguon":["@c0732"]},{"id":"loi-uy-trong-nguyen-than","name":"Lôi uy trong nguyên thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Lôi uy do Vương Lâm vận ra từ nguyên thần để ngăn hồng quang truy kích trong thông đạo.","detail":"Khi cảm nhận nguy hiểm từ phía thông đạo, Vương Lâm vận lôi uy hóa thành lôi quang lớn trên tay rồi đẩy ra chặn cửa thông đạo. Hồng quang Cực Cảnh vẫn xuyên phá lớp phòng thủ này, cho thấy uy lực của đòn truy kích vượt xa phòng ngự thông thường.","nguon":["@c0732"]},{"id":"cam-che-phong-an-tang-pham-cac","name":"Cấm chế phong ấn Tàng Phẩm Các","cn":"","loai":"khac","loaiLabel":"Cấm chế phong ấn","phamCap":"Do tứ đại gia tộc kết hợp tạo thành","hePhai":"Cấm chế","soHuu":["Tứ đại gia tộc"],"blurb":"Cấm chế che giấu mảnh vỡ chứa Tàng Phẩm Các ở trung tâm phần lớn mảnh vỡ Lôi Tiên Giới.","detail":"Phong ấn này do tứ đại gia tộc kết hợp bố trí, khiến người ngoài không thể trực tiếp tiến vào Tàng Phẩm Các. Lý Nguyên dùng tâm cấm dò được gợn sóng cấm chế, nhận ra thủ pháp cùng loại với tiên cấm nhưng có điểm khác biệt, rồi bắt đầu phá giải để hư ảnh đại lục và lầu các hiện ra.","nguon":["@c0733"]},{"id":"tam-cam-tieu-tan","name":"Tâm cấm tiêu tan","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Cấm chế","soHuu":["Lý Nguyên"],"blurb":"Thủ pháp cấm chế của Lý Nguyên, dùng dấu ấn hắc quang tạo thông đạo hình tròn bất ổn.","detail":"Lý Nguyên kết dấu ấn hắc quang bằng nhiều cấm chế rồi thi triển thủ pháp này, khiến mảnh vỡ đại lục liên tục hiện-ẩn và mở ra một thông đạo hình tròn không ổn định để đưa Vương Lâm vào bên trong.","nguon":["@c0734"]},{"id":"cam-che-tach-manh-vo-dai-luc","name":"Cấm chế tách mảnh vỡ đại lục","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Cấm chế","soHuu":[],"blurb":"Quầng sáng cấm chế tách mảnh vỡ đại lục khỏi Lôi Tiên Giới, biến nơi đây thành cấm địa của bốn gia tộc tu chân.","detail":"Sau khi Vương Lâm vào đại lục, phía sau hắn hiện ra quầng sáng cấm chế khiến mảnh vỡ đại lục bị tách hẳn khỏi Lôi Tiên Giới và trở thành cấm địa được phong tỏa đặc biệt.","nguon":["@c0734"]},{"id":"tien-loi","name":"Tiên Lôi","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi pháp","soHuu":["Tu sĩ áo đen thủ vệ Tàng Phẩm Các"],"blurb":"Thần thông lôi pháp dẫn sức mạnh từ trời xuống biến thành một đạo lôi công kích.","detail":"Tu sĩ áo đen dẫn sức mạnh từ trời xuống thành một đạo Tiên Lôi đánh Vương Lâm, nhưng bị nguyên thần Vương Lâm há miệng nuốt lấy.","nguon":["@c0734"]},{"id":"do-hinh-am-duong","name":"Đồ hình âm dương","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Ba tu sĩ thủ vệ còn lại của Tàng Phẩm Các"],"blurb":"Thần thông hợp kích, hai tu sĩ cùng bấm quyết tạo đồ hình âm dương xoay tròn để đối kháng mảnh vỡ đại ấn.","detail":"Hai tu sĩ thủ vệ cùng nhau bấm quyết tạo đồ hình âm dương xoay tròn, dùng để đối kháng và áp chế mảnh vỡ đại ấn của Vương Lâm.","nguon":["@c0734"]},{"id":"cuong-phong-loc-xoay","name":"Cuồng phong lốc xoáy","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Ba tu sĩ thủ vệ còn lại của Tàng Phẩm Các"],"blurb":"Thần thông tạo cơn cuồng phong thành lốc xoáy để công kích và ngăn cản.","detail":"Một tu sĩ thủ vệ tạo cơn cuồng phong thành lốc xoáy để công kích và ngăn Vương Lâm xử lý nguyên thần tu sĩ áo đen.","nguon":["@c0734"]},{"id":"huyet-quang-thoat-than","name":"Huyết quang thoát thân","loai":"bi-thuat","loaiLabel":"Bí pháp","phamCap":"Không rõ","hePhai":"Huyết pháp","soHuu":["Tu sĩ áo đen thủ vệ Tàng Phẩm Các"],"blurb":"Bí pháp cắn đầu lưỡi phun máu, toàn thân lóe huyết quang để thoát khỏi uy áp.","detail":"Tu sĩ áo đen cắn đầu lưỡi phun máu, toàn thân lóe huyết quang để thoát khỏi uy áp mảnh vỡ đại ấn trong lúc nguy hiểm.","nguon":["@c0734"]},{"id":"than-thong-loc-xoay","name":"Thần thông lốc xoáy","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Tu sĩ họ Lữ"],"blurb":"Thần thông do tu sĩ họ Lữ thi triển khi đối đầu Vương Lâm trước Tàng Phẩm Các. Sát khí của Thú Cốt khiến lốc xoáy biến thành màu xám rồi hóa đá.","detail":"Trong trận ép mở Tàng Phẩm Các, tu sĩ họ Lữ dùng thần thông lốc xoáy chống lại Vương Lâm. Khi Thú Cốt bộc phát sát khí, lốc xoáy bị xâm nhiễm, chuyển xám và hóa tượng đá, kéo theo việc thân thể người thi triển cũng bị hủy.","nguon":["@c0735"]},{"id":"ho-phong-hoan-vu","name":"Hô phong hoán vũ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên thuật tầng chín Tàng Phẩm Các","soHuu":[],"blurb":"Cụm thần thông xuất hiện trong câu thơ trên bức họa tầng chín Tàng Phẩm Các. Vương Lâm nhận định đây là hai thần thông.","detail":"Ở tầng chín Tàng Phẩm Các, Vương Lâm thấy bức họa kèm câu thơ nhắc đến Hô phong hoán vũ. Hắn cho rằng cụm này nói về hai thần thông, liên hệ với các tiên thuật được cất giữ tại tầng cao nhất.","nguon":["@c0735"]},{"id":"tat-dau-thanh-binh","name":"Tát đậu thành binh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên thuật tầng chín Tàng Phẩm Các","soHuu":[],"blurb":"Thần thông được nhắc trong câu thơ trên bức họa tầng chín Tàng Phẩm Các. Vương Lâm xem đây là một thần thông riêng.","detail":"Tát đậu thành binh xuất hiện cùng Hô phong hoán vũ trong câu thơ ở tầng chín. Vương Lâm suy xét nội dung câu thơ và nhận định cụm này cũng chỉ một thần thông.","nguon":["@c0735"]},{"id":"dia-liet-son-bang","name":"Địa liệt sơn băng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên thuật tầng chín Tàng Phẩm Các","soHuu":[],"blurb":"Cụm thần thông hoặc ý niệm tiên thuật xuất hiện trong câu thơ tầng chín Tàng Phẩm Các. Vương Lâm đặt nó cùng loại với Hô phong hoán vũ.","detail":"Địa liệt sơn băng nằm trong câu thơ trên bức họa cây và đồng tử ở tầng chín. Vương Lâm cho rằng cụm này tương tự Hô phong hoán vũ ở phía trước, hàm ý liên quan một dạng thần thông.","nguon":["@c0735"]},{"id":"ho-phong","name":"Hô phong","cn":"","aliases":["Hô Phong","Hô Phong thuật"],"loai":"than-thong","loaiLabel":"Tiên thuật / thần thông","phamCap":"tiên thuật của Tiên Đế","hePhai":"Tiên giới","soHuu":["Vương Lâm"],"blurb":"Hô phong là tiên thuật Vương Lâm cảm ngộ trong bức họa tầng chín Tàng Phẩm Các. Khi thi triển trong cảnh tranh, gió đen hóa thành chín hắc long, mang ý diệt sinh cơ vạn linh.","detail":"Trong không gian bức họa, người mờ ảo giảng đạo vung tay gọi gió đen, hóa thành chín hắc long phun gió lạnh. Uy năng này khiến nguyên thần Vương Lâm tan vỡ; sau đó thanh âm Tiên Quân cuốn nguyên thần hắn như mực viết thành hai chữ Hô phong, khiến hắn nhận được tiên thuật trong đầu.","nguon":["@c0736","@c0768"]},{"id":"thu-an-cua-dong-tu-trong-tranh","name":"Thủ ấn của đồng tử trong tranh","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Thủ quyết / pháp quyết nhập tranh","phamCap":"không rõ","hePhai":"Tàng Phẩm Các","soHuu":["Vương Lâm"],"blurb":"Thủ ấn của đồng tử trong tranh là chuỗi thủ quyết biến hóa rất nhỏ ẩn trong bức họa tầng chín. Vương Lâm quan sát bảy ngày, thi triển lại vào ngày thứ tám và nhờ đó nhập vào không gian trong tranh.","detail":"Đồng tử trong bức họa vốn như đang ngồi thổ nạp, sau đó lộ ra các động tác bấm quyết biến hóa theo chu kỳ vài canh giờ. Vương Lâm ghi nhớ toàn bộ thủ ấn, thi triển lại khiến lầu các chấn động, tâm thần hướng vào tranh và nguyên thần bị kéo vào cảnh giới trong bức họa.","nguon":["@c0736"]},{"id":"hu-anh-tien-khi-cua-tu-si-ho-tran","name":"Hư ảnh tiên khí của tu sĩ họ Trần","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Trần gia","soHuu":["Tu sĩ họ Trần"],"blurb":"Thần thông do tu sĩ họ Trần thi triển trong đợt đánh úp Vương Lâm ngoài Tàng Phẩm Các.","detail":"Tu sĩ họ Trần bấm quyết tạo một hư ảnh lớn có tiên khí lượn lờ, điểm chỉ công kích Vương Lâm. Khi Hô Phong nổi lên, hư ảnh này bị thổi tan như ánh nến trước gió.","nguon":["@c0737"]},{"id":"am-duong-do-cua-tu-si-ho-tong","name":"Âm dương đồ của tu sĩ họ Tống","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Tu sĩ họ Tống"],"blurb":"Thần thông công kích bằng đồ hình âm dương, tia chớp và thiên địa nguyên lực của tu sĩ họ Tống.","detail":"Tu sĩ họ Tống vận chuyển hai tay tạo âm dương đồ, trong đó có tia chớp cùng thiên địa nguyên lực lao về phía Vương Lâm. Đòn này bị hắc phong của Hô Phong làm tan vỡ trong lần giao kích ngoài Tàng Phẩm Các.","nguon":["@c0737"]},{"id":"soi-to-uy-ap-mau-luc-cua-tu-si-ho-tong","name":"Sợi tơ uy áp màu lục của tu sĩ họ Tống","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Tu sĩ họ Tống"],"blurb":"Thần thông tạo hư ảnh sợi tơ dài mang uy áp và sương xanh lục.","detail":"Tu sĩ họ Tống đánh ra một dấu ấn quỷ dị, khiến hư ảnh sợi tơ dài xuất hiện, tự sinh uy áp và sương xanh lục trong đợt vây công Vương Lâm. Thần thông này nằm trong loạt công kích bị Hô Phong phá giải.","nguon":["@c0737"]},{"id":"sau-hoa-long-mau-tim-cua-tu-si-ho-lu","name":"Sáu hỏa long màu tím của tu sĩ họ Lữ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lữ gia","soHuu":["Tu sĩ họ Lữ"],"blurb":"Thần thông do tu sĩ họ Lữ dùng pháp bảo nguyên thần và tinh khí hóa thành sáu hỏa long màu tím.","detail":"Tu sĩ họ Lữ phun cây quạt nhỏ, dùng tinh khí nguyên thần hóa ra sáu hỏa long màu tím để vây giữ Vương Lâm và ngăn hắn bỏ chạy. Hắc phong của Hô Phong thổi qua làm pháp bảo tan vỡ, khiến thần thông này thất bại.","nguon":["@c0737"]},{"id":"thu-an-thu-tang-pham-cac","name":"Thủ ấn thu Tàng Phẩm Các","cn":"","loai":"bi-thuat","loaiLabel":"Ấn quyết","phamCap":"Không rõ","hePhai":"Liên quan đồng tử trong bức tranh","soHuu":["Vương Lâm"],"blurb":"Ấn quyết Vương Lâm mô phỏng từ đồng tử trong bức tranh để thu nhỏ Tàng Phẩm Các.","detail":"Sau khi nhớ lại thủ ấn từng khiến lầu các rung động trong không gian bức tranh, Vương Lâm thi triển bên ngoài Tàng Phẩm Các. Lầu các tràn hào quang, thu nhỏ bằng lòng bàn tay và rơi vào tay hắn.","nguon":["@c0737"]},{"id":"cam-che-tren-manh-vo-dai-luc","name":"Cấm chế trên mảnh vỡ đại lục","cn":"","loai":"khac","loaiLabel":"Trận pháp/cấm chế","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Cấm chế nham hiểm do Vương Lâm bố trí sau khi thu Tàng Phẩm Các.","detail":"Vương Lâm dùng gần mười ngày lấy mảnh vỡ đại lục làm nền móng, bày nhiều cấm chế trên đường lớn nhằm đối phó người ngoài tiến vào, nhất là khi hắn đã kết thù với tứ đại gia tộc.","nguon":["@c0737"]},{"id":"tran-phap-cam-che-co-xua-bon-manh-vo","name":"Trận pháp cấm chế cổ xưa bốn mảnh vỡ","cn":"","loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"cổ xưa","hePhai":"Lôi Tiên Giới","soHuu":[],"blurb":"Trận pháp cấm chế cổ xưa xuất hiện trên bốn mảnh vỡ đại lục ở đông, tây, nam, bắc Lôi Tiên Giới. Chúng tỏa tiên lực nồng đậm, thu hút tu sĩ phá giải rồi mở ra các thông đạo dẫn tới thảm biến.","detail":"Bốn mảnh vỡ đại lục đồng thời xuất hiện dao động tiên lực và trận pháp cấm chế cổ xưa, khiến nhiều tu sĩ cùng cao thủ cấm chế tụ tập phá giải. Sau khi bị mở, các thông đạo hoặc hang động phía sau lần lượt biến thành bẫy chết: hồng quang, lốc xoáy ngũ sắc, tiếng kêu thảm và sụp đổ thông đạo giết nhiều tu sĩ, đồng thời góp phần kích hoạt biến cố phong ấn trong toàn Lôi Tiên Giới.","nguon":["@c0738"]},{"id":"chin-dau-an-phong-an","name":"Chín dấu ấn phong ấn","cn":"","loai":"khac","loaiLabel":"Trận pháp phong ấn","phamCap":"cổ xưa","hePhai":"Lôi Tiên Giới","soHuu":[],"blurb":"Chín dấu ấn trận pháp hiện ra trên chín mảnh vỡ đại lục trong Lôi Tiên Giới. Chúng tỏa hồng quang và liên quan trực tiếp tới việc cánh tay cụt bị phong ấn thoát ra.","detail":"Sau khi bốn thông đạo ở đông, tây, nam, bắc sụp đổ và tiên lực khổng lồ tràn ngập toàn giới, chín mảnh vỡ đại lục cùng chấn động. Mặt đất xuất hiện các dấu ấn trận pháp khác nhau, phát ra hồng quang khiến tu sĩ kinh hãi; trong một mảnh vỡ, phong ấn bị phá từ bên trong, để lộ cánh tay cụt từng bị phong ấn vô số năm.","nguon":["@c0738"]},{"id":"tu-loi","name":"Tử lôi","cn":"","aliases":["Lôi điện màu tím"],"loai":"than-thong","loaiLabel":"Thần thông lôi điện","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Tử lôi là lôi điện màu tím do Vương Lâm vận nguyên thần phóng ra. Khi đánh cánh tay cụt đỏ, thần thông này bị đối phương bóp nát và hấp thu nguyên lực.","detail":"Trong trận gặp cánh tay cụt ở hư vô Lôi Tiên Giới, Vương Lâm vận nguyên thần phóng lôi điện màu tím để công kích. Cánh tay cụt trực tiếp bóp nát tử lôi và hấp thu nguyên lực, cho thấy sức áp chế cực mạnh của tàn chi.","nguon":["@c0739"]},{"id":"loc-xoay-phong-an","name":"Lốc xoáy phong ấn","cn":"","aliases":[],"loai":"khac","loaiLabel":"Phong ấn","phamCap":"Không rõ","hePhai":"Thanh Thủy","soHuu":["Thanh Thủy"],"blurb":"Lốc xoáy phong ấn là thủ đoạn Thanh Thủy từng dùng để trấn áp quái nhân tóc bạc. Quái nhân nói phong ấn này khiến hắn bị giam qua thời gian dài nhưng cũng giúp hắn sống sót sau khi tiên giới sụp đổ.","detail":"Sau khi tái hợp thân thể, quái nhân tóc bạc nhắc Thanh Thủy Tiên Quân từng dùng lốc xoáy để phong ấn hắn. Phong ấn này liên quan tới cơn lốc xoáy trong Lôi Tiên Giới và là nguyên nhân khiến tàn chi, mắt phải cùng Cực Cảnh của hắn bị chia tách.","nguon":["@c0739"]},{"id":"tien-thuat-hoa-than","name":"Tiên thuật hóa thân","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Tiên thuật phân thân","phamCap":"Tiên thuật","hePhai":"Không rõ","soHuu":["Quái nhân tóc bạc"],"blurb":"Tiên thuật hóa thân là thuật phân thân của quái nhân tóc bạc. Hắn dùng thuật này phân hóa thành ba mươi hai phân thân để phong tỏa phạm vi ngàn trượng trước cửa Tiên Giới.","detail":"Khi các tu sĩ bỏ vây công để lao về cửa Lôi giới đang đóng, quái nhân tóc bạc thi triển Tiên thuật hóa thân. Thân thể hắn liên tục phân hóa từ hai thành bốn, cuối cùng thành ba mươi hai phân thân, chặn giết mọi tu sĩ tiến vào phạm vi ngàn trượng trước cửa Tiên Giới.","nguon":["@c0739"]},{"id":"dao-dung-thien-dia","name":"Đạo dung thiên địa","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cao thâm, tiên giới năm xưa cũng hiếm người đạt được","hePhai":"Dung nhập thiên địa","soHuu":["Vương Lâm","Quái nhân tóc bạc"],"blurb":"Trạng thái hoặc đạo pháp dung nhập cùng thiên địa, có thể ẩn thân trong hư vô và dịch chuyển tiếp cận mục tiêu. Quái nhân tóc bạc nhận ra pháp này và tự dùng cách tương tự để truy bắt.","detail":"Vương Lâm dùng đạo dung thiên địa để kéo Lý Nguyên tiếp cận đại môn Tiên giới, nhưng vì chưa hoàn toàn nắm giữ nên Lý Nguyên bị thương nặng trong quá trình di chuyển. Quái nhân tóc bạc phát hiện dấu vết, nói tiên giới năm xưa cũng không có nhiều người đạt đến đạo này, rồi dung nhập thiên địa truy tìm và ép hai người hiện thân gần đại môn.","nguon":["@c0740"]},{"id":"tu-bao-nguyen-than","name":"Tự bạo nguyên thần","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Thủ đoạn liều chết","phamCap":"Không rõ","hePhai":"Nguyên thần","soHuu":["Nhiều tu sĩ Âm Hư"],"blurb":"Thủ đoạn tự hủy nguyên thần và thân thể khi lâm vào tuyệt cảnh. Trong chương này, nó không thể cản quái nhân tóc bạc mà còn bị hắn thôn phệ nguyên lực.","detail":"Một số tu sĩ Âm Hư không thoát khỏi phong sát đã chọn tự bạo nguyên thần và thân thể. Nguyên lực sinh ra từ vụ tự bạo bị quái nhân tóc bạc thôn phệ, khiến thân thể hắn phình lên và khí tức càng mạnh.","nguon":["@c0740"]},{"id":"man-sang-do","name":"Màn sáng đỏ","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Phòng ngự thôn phệ","phamCap":"Không rõ","hePhai":"Quái nhân tóc bạc","soHuu":["Quái nhân tóc bạc"],"blurb":"Màn sáng hộ thân màu đỏ của quái nhân tóc bạc, vừa phòng ngự vừa thôn phệ. Nó phản chấn pháp bảo thần thông của nhóm vây công và hút nguyên lực từ người chạm phải.","detail":"Khi nhóm Dương Thực và Âm Hư vây công, quái nhân tóc bạc tạo màn đỏ ngoài thân. Màn sáng này ngăn thần thông pháp bảo, đẩy bật người công kích, đồng thời hấp thu tu sĩ va vào thành nguyên lực cho hắn.","nguon":["@c0740"]},{"id":"nut","name":"Nứt","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Quái nhân tóc bạc"],"blurb":"Nứt là thần thông quái nhân tóc bạc dùng để mở khe hở không gian trong trận đấu với Vương Lâm.","detail":"Khi đối kháng hắc long do Hô Phong hóa thành, quái nhân tóc bạc quát một tiếng khiến khe hở không gian lớn xuất hiện trước người, lao tới va chạm trực diện với hắc long và làm Vương Lâm bị đánh lui.","nguon":["@c0741"]},{"id":"tieu-dao-tu-mau-kho","name":"Tiêu Dao Tử Mẫu Khô","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm"],"blurb":"Tiêu Dao Tử Mẫu Khô là tên quái nhân tóc bạc gọi ra khi thấy Thú Cốt của Vương Lâm biến hóa.","detail":"Vương Lâm biến đồ án thú cốt trên mu bàn tay thành bộ thú cốt lớn có u quang, răng nanh và sát khí; quái nhân tóc bạc nhận ra lai lịch, gọi đúng là Tiêu Dao Tử Mẫu Khô và tỏ vẻ khó tin.","nguon":["@c0741"]},{"id":"phan-tien-hoa","name":"Phần Tiên Hỏa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"hỏa hệ","hePhai":"","soHuu":["Lão giả Vấn Đỉnh"],"blurb":"Hỏa thuật cực mạnh do lão giả mượn thân Vương Lâm thi triển trong trận chiến với Thanh Thủy.","detail":"Phần Tiên Hỏa khiến lửa bao phủ nửa thiên địa, mang khí tức luyện hóa trời đất và làm tu sĩ xung quanh kinh hãi. Thuật này tiếp tục triển khai qua các tầng Viêm và Diễm để vây công Thanh Thủy tiên quân.","nguon":["@c0742"]},{"id":"viem","name":"Viêm","cn":"","loai":"than-thong","loaiLabel":"Biến hóa hỏa thuật","phamCap":"","hePhai":"","soHuu":["Lão giả Vấn Đỉnh"],"blurb":"Một tầng triển khai của Phần Tiên Hỏa, biến biển lửa thành viêm long công kích.","detail":"Khi lão giả hô Viêm, hỏa diễm tụ quanh Thanh Thủy tiên quân, hóa thành vô số viêm long mang sóng nhiệt lao tới cắn xé đối thủ.","nguon":["@c0742"]},{"id":"diem","name":"Diễm","cn":"","loai":"than-thong","loaiLabel":"Biến hóa hỏa thuật","phamCap":"","hePhai":"","soHuu":["Lão giả Vấn Đỉnh"],"blurb":"Một tầng triển khai cao hơn của Phần Tiên Hỏa, tụ hỏa thành hỏa cầu lớn.","detail":"Diễm khiến biển lửa co rút thành hỏa cầu bao lấy Thanh Thủy tiên quân, có sức thiêu đốt cả vật hữu hình lẫn hư vô, dù cuối cùng vẫn bị Cực Cảnh xuyên phá.","nguon":["@c0742"]},{"id":"thu-lay-luc-luong-thien-dia","name":"Thu lấy lực lượng thiên địa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Lão giả Vấn Đỉnh"],"blurb":"Thần thông thu nhiếp bạch khí thiên địa ngưng thành bạch cầu để công kích.","detail":"Thân thể Vương Lâm dưới sự điều khiển của lão giả thu lấy lực lượng thiên địa, ngưng tụ thành bạch cầu đánh tới Thanh Thủy tiên quân, buộc đối phương dùng trường thương tạo hồng mang đối kháng.","nguon":["@c0742"]},{"id":"bach-pham-tien-thuat","name":"Bạch Phàm tiên thuật","cn":"","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"","hePhai":"","soHuu":["Bạch Phàm"],"blurb":"Tiên thuật của Bạch Phàm được Thanh Thủy nhắc tới khi đánh giá các thủ đoạn bên phía Vương Lâm.","detail":"Thanh Thủy tiên quân liệt kê Bạch Phàm tiên thuật cùng Thanh Sương tiên kiếm và pháp bảo của Tiêu Dao Tử, xem đây là một trong các yếu tố khiến đối thủ trước mặt đáng chú ý.","nguon":["@c0742"]},{"id":"tu-quang-ngung-tan","name":"Tử quang ngưng tán","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Lão giả thần bí trong thân thể Vương Lâm"],"blurb":"Thần thông dùng tử quang ngưng thành quang cầu rồi tán ra thành sóng gợn, đẩy tu sĩ khỏi phạm vi chiến đấu.","detail":"Trong chương 743, lão giả điều khiển thân thể Vương Lâm ngưng tử quang trong tay thành quang cầu, sau đó khiến nó tản ra thành từng vòng gợn sóng để đẩy toàn bộ tu sĩ xung quanh rời xa, tạo khoảng trống mười dặm chỉ còn Vương Lâm và thanh niên tà khí.","nguon":["@c0743"]},{"id":"dao-loi-dien-cua-than-cong-ho","name":"Đạo lôi điện của Thân Công Hổ","cn":"","loai":"than-thong","loaiLabel":"Đạo lôi pháp","phamCap":"không rõ","hePhai":"","soHuu":["Thân Công Hổ"],"blurb":"Lôi điện đỏ sậm là bí mật lớn nhất của Thân Công Hổ, được ngưng luyện nhiều năm từ chỉ điểm của Vương Lâm.","detail":"Đạo lôi điện này do Thân Công Hổ dung hợp toàn thân tu vi, lấy cảm ngộ từ chỉ điểm năm xưa của Vương Lâm về lôi lực mà ngưng luyện. Khi bị thanh niên tà khí áp sát, hắn dùng lôi điện đỏ sậm này chống cự nhưng bị đối phương bóp nát.","nguon":["@c0743"]},{"id":"tien-thuat-tieu","name":"Tiên thuật, tiêu","cn":"","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"tiên thuật","hePhai":"","soHuu":["Lão giả thần bí trong thân thể Vương Lâm"],"blurb":"Tiên thuật dùng nguyên lực dung nhập thiên địa, khiến nguyên lực ngưng tụ bên ngoài thân các tu sĩ đang bỏ chạy.","detail":"Lão giả điều khiển thân thể Vương Lâm dùng nguyên lực thay thế thiên địa trong phạm vi lớn rồi thi triển chữ “tiêu”, khiến nguyên lực bên ngoài thân các tu sĩ đang chạy trốn bị điều động, làm tiền đề cho tiên thuật “tán” đưa họ rời khỏi chiến trường.","nguon":["@c0743"]},{"id":"tien-thuat-tan","name":"Tiên thuật, tán","cn":"","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"tiên thuật","hePhai":"","soHuu":["Lão giả thần bí trong thân thể Vương Lâm"],"blurb":"Tiên thuật tiếp nối “tiêu”, ép toàn bộ tu sĩ bên ngoài chiến trường dung nhập thiên địa và biến mất khỏi tầm thôn phệ.","detail":"Sau khi thi triển “tiêu”, lão giả trong thân thể Vương Lâm dùng tiếp “tán” để làm các tu sĩ quanh chiến trường dung nhập vào thiên địa và biến mất, khiến thanh niên tà khí không còn mục tiêu thôn phệ trong khu vực.","nguon":["@c0743"]},{"id":"phan-than-ba-muoi-hai-dao","name":"Phân thân ba mươi hai đạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông phân thân","phamCap":"không rõ","hePhai":"","soHuu":["Quái nhân tóc bạc"],"blurb":"Thần thông phân ra ba mươi hai phân thân để chia nhau truy sát tu sĩ bỏ chạy.","detail":"Thanh niên tà khí sau khi bị ngăn thôn phệ Thân Công Hổ lại phân thân nhiều lần, tái hiện ba mươi hai đạo phân thân cùng lúc lao theo các tu sĩ đang bỏ chạy nhằm mở rộng phạm vi thôn phệ.","nguon":["@c0743"]},{"id":"loi-tien-dai-tran","name":"Lôi Tiên Đại Trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Lôi Tiên Giới","soHuu":["Viêm Lôi Tử"],"blurb":"Đại trận do Viêm Lôi Tử tái hiện để luyện hóa Lôi Tiên Giới. Trận lấy bốn mươi chín mảnh vỡ đại lục vận chuyển quanh trung tâm, dùng pháp linh dung nhập từng mảnh để biến một nửa Lôi Tiên Giới thành pháp bảo.","detail":"Trong chương 745, Viêm Lôi Tử thúc nguyên lực dung nhập mặt đất và tuyên bố Lôi Tiên Đại Trận tái hiện. Đại trận vận chuyển bốn mươi chín mảnh vỡ đại lục của Lôi Tiên Giới, tạo lốc xoáy và lực hút cực lớn; sau đó mảnh kính cũ thả nguyên thần Âm Hư, Dương Thực làm pháp linh để từng mảnh vỡ tăng linh tính, phục vụ kế hoạch luyện hóa Lôi Tiên Giới thành pháp bảo.","nguon":["@c0745"]},{"id":"dai-tran-hinh-hoa-mai-tu-bon-muoi-chin-manh-vo","name":"Đại trận hình hoa mai từ bốn mươi chín mảnh vỡ","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Lôi Tiên Giới","soHuu":["Viêm Lôi Tử"],"blurb":"Thế trận hình thành khi bốn mươi chín mảnh vỡ đại lục của Lôi Tiên Giới cùng vận chuyển. Mảnh vỡ nơi Vương Lâm và thanh niên đầy tà khí đứng được lấy làm trung tâm, các mảnh còn lại xoay quanh tạo hình hoa mai.","detail":"Khi đại lục Lôi Tiên Giới bị kích hoạt, bốn mươi chín mảnh vỡ đồng loạt chấn động, được Lôi Thú kéo bay lên và xoay quanh mảnh vỡ trung tâm. Cấu trúc hình hoa mai này là hình thái vận hành của đại trận, mở đầu cho quá trình toàn giới sụp đổ và bị luyện hóa.","nguon":["@c0745"]},{"id":"tien-gioi-dai-tran","name":"Tiên Giới Đại Trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Tiên giới đại trận","hePhai":"Lôi Tiên Giới","soHuu":["Viêm Lôi Tử"],"blurb":"Trận pháp tuyệt luân do bốn mươi chín mảnh vỡ đại lục hợp thành. Viêm Lôi Tử dùng nhiều nguyên thần cấp cao làm pháp bảo chi linh để nâng uy lực đại trận.","detail":"Tiên Giới Đại Trận lấy bốn mươi chín mảnh vỡ đại lục làm nền, đưa nguyên thần mạnh vào từng mảnh để tăng linh tính và uy áp. Khi hoàn thiện, Viêm Lôi Tử thu trận thành bốn mươi chín mảnh nhỏ quanh bản thể, cho thấy trận pháp đồng thời là căn cơ luyện hóa Lôi Tiên Giới của hắn.","nguon":["@c0746"]},{"id":"tai-hien","name":"Tái hiện","cn":"","loai":"bi-thuat","loaiLabel":"Pháp quyết","phamCap":"Không rõ","hePhai":"Viêm Lôi Tử","soHuu":["Viêm Lôi Tử"],"blurb":"Mệnh lệnh/pháp quyết Viêm Lôi Tử dùng để kích hoạt cổ kính tiếp tục gọi ra các nguyên thần cấp cao. Nhờ đó các nguyên thần thiên tiên, tiên vương và Tiên Quân lần lượt xuất hiện.","detail":"Trong quá trình hoàn thiện Tiên Giới Đại Trận, Viêm Lôi Tử dùng “Tái hiện” với cổ kính để đưa thêm nguyên thần mạnh quy vị. Pháp quyết này gắn trực tiếp với công năng triệu hiện của cổ kính trong chương.","nguon":["@c0746"]},{"id":"phong-an-u-quang-o-mi-tam","name":"Phong ấn u quang ở mi tâm","cn":"","loai":"khac","loaiLabel":"Phong ấn","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hai nguyên thần nhất phẩm Tiên Quân"],"blurb":"Dấu phong ấn u quang nằm giữa mi tâm hai nguyên thần nhất phẩm Tiên Quân. Nó cho thấy hai nguyên thần chưa hoàn chỉnh và đang trong trạng thái bị khóa giữ khi quy vị vào tiên trận.","detail":"Khi hai nguyên thần nhất phẩm Tiên Quân xuất hiện, mi tâm họ có phong ấn u quang và thân trạng không hoàn chỉnh. Dấu phong ấn này gắn với tình trạng bị khống chế hoặc giữ lại trong cổ kính trước khi được Viêm Lôi Tử đưa vào Tiên Giới Đại Trận.","nguon":["@c0746"]},{"id":"tien-tran-phap-chuyen","name":"Tiên trận, pháp chuyển","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Viêm Lôi Tử"],"blurb":"Trận pháp do Viêm Lôi Tử thi triển bằng bốn mươi chín mảnh vỡ để vây giữ Thanh Thủy.","detail":"Khi Thanh Thủy lao tới, Viêm Lôi Tử khiến bốn mươi chín mảnh vỡ bộc phát kim quang, tạo trận pháp xoay tròn vây khốn đối thủ trong lúc giao chiến.","nguon":["@c0747"]},{"id":"do-tien-thu","name":"Đồ Tiên Thứ","cn":"","loai":"than-thong","loaiLabel":"Tiên trận công kích","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Viêm Lôi Tử"],"blurb":"Công kích từ kim quang trận pháp của Viêm Lôi Tử, hóa thành các mũi nhọn màu vàng đâm vào Thanh Thủy.","detail":"Sau khi dùng Tiên trận, pháp chuyển vây Thanh Thủy, Viêm Lôi Tử kích phát Đồ Tiên Thứ, khiến từng mũi nhọn kim quang mang khí tức hủy diệt đâm vào thân thể Thanh Thủy.","nguon":["@c0747"]},{"id":"tien-tran-tu-nguyen","name":"Tiên trận, tụ nguyên","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Viêm Lôi Tử"],"blurb":"Trận pháp ngưng tụ nguyên lực từ bốn mươi chín mảnh vỡ để chống lại âm phong của Thanh Thủy.","detail":"Viêm Lôi Tử điều động bốn mươi chín mảnh vỡ ngưng tụ nguyên lực thành bốn mươi chín đạo cầu vồng, dùng để đối kháng sức ép từ âm phong trong trận chiến.","nguon":["@c0747"]},{"id":"do-hinh-thu-tien-thu","name":"Đồ Tiên Thứ","cn":"","loai":"than-thong","loaiLabel":"Tiên trận công kích","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Viêm Lôi Tử"],"blurb":"Công kích kim quang mang khí tức hủy diệt trong tiên trận của Viêm Lôi Tử.","detail":"Đồ Tiên Thứ được phát động trong kim quang trận pháp, hiện thành mũi nhọn màu vàng liên tiếp đâm vào Thanh Thủy trước khi bị Hô Phong phá thế trận.","nguon":["@c0747"]},{"id":"hoan-vu","name":"Hoán Vũ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Thanh Thủy"],"blurb":"Thần thông khiến phạm vi nghìn trượng xuất hiện mưa đỏ trong suốt như pha lê.","detail":"Thanh Thủy thi triển Hoán Vũ sau Hô Phong, khiến mưa đỏ bao phủ phạm vi nghìn trượng quanh chiến trường, tiếp nối bằng biến hóa băng ấn để ép Viêm Lôi Tử.","nguon":["@c0747"]},{"id":"hoan-vu-bang-an","name":"Hoãn Vũ, Băng Ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông biến hóa","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Thanh Thủy"],"blurb":"Biến hóa tiếp theo của mưa đỏ, khiến giọt mưa hóa thành bông tuyết liên kết tràn về phía Viêm Lôi Tử.","detail":"Trong phạm vi nghìn trượng, Thanh Thủy khiến các giọt mưa trở thành bông tuyết kéo dài, tạo thành thế công dày đặc hướng về Viêm Lôi Tử.","nguon":["@c0747"]},{"id":"sau-dai-than-thong-cua-su-ton-thanh-thuy","name":"Sáu đại thần thông của sư tôn Thanh Thủy","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Truyền thừa sư tôn Thanh Thủy","soHuu":["Thanh Thủy"],"blurb":"Sáu môn đại thần thông cả đời của sư tôn Thanh Thủy, trong đó có Hô Phong thuật.","detail":"Thanh Thủy nói Hô Phong thuật là một trong sáu đại thần thông cả đời của sư tôn mình, nhưng chương chưa nêu đủ sáu môn. Việc Vương Lâm học được Hô Phong thuật khiến Thanh Thủy xem hắn như truyền nhân sau nhiều năm tháng của sư tôn.","nguon":["@c0748"]},{"id":"bang-tinh-thuan-ty","name":"Băng tinh thuấn tý","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Chưa rõ","hePhai":"Viêm Lôi Tử","soHuu":["Viêm Lôi Tử"],"blurb":"Lớp phòng hộ băng tinh bao ngoài thân thể Viêm Lôi Tử.","detail":"Khi tia chớp Cực Cảnh của Thanh Thủy xuất hiện, lớp băng tinh thuấn tý bên ngoài thân thể Viêm Lôi Tử biến mất.","nguon":["@c0748"]},{"id":"tien-thuat-loi-tram","name":"Tiên thuật lôi trảm","cn":"","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"không rõ","hePhai":"","soHuu":["Lão giả bạch y"],"blurb":"Tiên thuật lôi trảm là tiên thuật lôi điện của lão giả bạch y. Lôi quang được ngưng thành lưỡi đao chém tới Vương Lâm nhưng bị nguyên thần Vương Lâm nuốt trọn.","detail":"Trong trận tranh đoạt mảnh nhỏ trăm trượng, lão giả bạch y thi triển Tiên thuật lôi trảm để đánh Vương Lâm. Công kích hóa thành lưỡi dao lôi điện áp sát, song nguyên thần Vương Lâm bay ra nuốt luôn lưỡi dao rồi trở về thân thể, khiến tiên thuật không tạo được uy hiếp.","nguon":["@c0750"]},{"id":"nguyen-than-nuot-loi-dao","name":"Nguyên thần nuốt lôi đao","cn":"","loai":"bi-thuat","loaiLabel":"Thủ đoạn nguyên thần","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Nguyên thần nuốt lôi đao là thủ đoạn Vương Lâm dùng để phá Tiên thuật lôi trảm. Nguyên thần bay ra từ mi tâm, nuốt công kích lôi điện rồi trở lại cơ thể.","detail":"Khi lưỡi đao lôi điện của lão giả bạch y áp sát, mi tâm Vương Lâm lóe sáng và nguyên thần bay ra nuốt luôn lưỡi dao trong nháy mắt. Thủ đoạn này trực tiếp hóa giải tiên thuật của đối thủ, đồng thời mở đầu cho việc Vương Lâm phản kích bằng Định thân tiên thuật.","nguon":["@c0750"]},{"id":"truy-hon","name":"Truy hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi Tiên Điện","soHuu":["Bảy sứ giả Lôi Tiên Điện bên ngoài truyền tống trận"],"blurb":"Thần thông truy kích bằng huyết kiếm hư ảo của một sứ giả Lôi Tiên Điện. Chiêu này được dùng để đuổi theo ngân quang của nam tử trung niên gầy gò nhưng bị Vương Lâm phá tan.","detail":"Sau khi bị ngân quang xuyên qua, sứ giả Lôi Tiên Điện dùng máu tươi tạo thành huyết kiếm hư ảo để truy kích đối thủ. Vương Lâm kịp thời ra tay bắt lấy huyết kiếm rồi đánh tan thành sương máu, khiến chiêu truy kích không thành.","nguon":["@c0752"]},{"id":"cuong-loi-mau-tim","name":"Cuồng lôi màu tím","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Lôi đình màu tím do Vương Lâm phóng ra trong trận phá vây. Đòn này đánh vào mi tâm sứ giả Lôi Tiên Điện, diệt cả nguyên thần đối phương trong nháy mắt.","detail":"Khi nam tử trung niên gầy gò cảnh giới Dương Thực xuyên ngực một sứ giả Lôi Tiên Điện, Vương Lâm chớp thời cơ chỉ tay phóng cuồng lôi màu tím vào mi tâm đối phương. Lôi đình này khiến thân thể sứ giả run lên và nguyên thần bị diệt ngay lập tức.","nguon":["@c0752"]},{"id":"khoa-nguyen-phong-than","name":"Khóa nguyên, phong thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi Tiên điện","soHuu":["Sáu sứ giả Lôi Tiên điện"],"blurb":"Pháp thuật do sứ giả Lôi Tiên điện thi triển thông qua khóa màu vàng để phong tỏa đối thủ.","detail":"Một sứ giả Lôi Tiên điện phun khóa vàng cùng tinh huyết nguyên thần rồi thi triển Khóa nguyên, phong thần, hóa ra vô số tia sáng vàng nhằm trói buộc Vương Lâm và các tu sĩ phía sau. Thần thông bị gió đen hóa rồng của Vương Lâm phá tan, pháp bảo cũng bị đoạt.","nguon":["@c0753"]},{"id":"gio-den-hoa-rong","name":"Gió đen hóa rồng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm"],"blurb":"Thần thông của Vương Lâm gọi gió đen hóa thành rồng đen để phá pháp thuật phong tỏa.","detail":"Vương Lâm bắt quyết gọi một luồng gió đen hóa thành cuồng phong và rồng đen, dùng âm phong thổi tan các tia sáng vàng từ Khóa nguyên, phong thần của sứ giả Lôi Tiên điện.","nguon":["@c0753"]},{"id":"truyen-tong-tran-tu-huy-van-chuyen","name":"Truyền tống trận tự hủy vận chuyển","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Lôi Tiên điện","soHuu":["Sáu sứ giả Lôi Tiên điện"],"blurb":"Cách cưỡng ép vận chuyển truyền tống trận bằng việc phá hủy chính trận pháp để tăng tốc truyền tống.","detail":"Ba sứ giả Lôi Tiên điện khoanh chân vận chuyển trận, dùng cách làm trận pháp tan vỡ để tốc độ truyền tống tăng mạnh. Cách này tạo cột sáng liên tục nhưng khiến trận pháp vượt quá sức chịu đựng và làm điểm xuất hiện có thể thay đổi.","nguon":["@c0753"]},{"id":"than-thong-cuu-nguoi-cua-hua-moc","name":"Thần thông cứu người của Hứa Mộc","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn được các tu sĩ sống sót truyền lại là Hứa Mộc từng dùng để cứu họ trong Lôi Tiên Giới. Chương chỉ nhắc theo lời truyền, chưa nêu tên chính thức hay cơ chế cụ thể.","detail":"Sau khi trở về đại lục thứ tư La Thiên, hơn trăm tu sĩ sống sót kể rằng Hứa Mộc đã dùng thần thông giúp họ thoát khỏi tử vong trong Lôi Tiên Giới, kháng lại quái nhân tóc bạc và dẫn mọi người tới truyền tống trận của Lôi Tiên điện. Do lời kể lan rộng, thủ đoạn này góp phần khiến danh tiếng Hứa Mộc được phóng đại khắp tinh vực La Thiên.","nguon":["@c0754"]},{"id":"dung-nhap-khong-gian-troi-dat","name":"Dung nhập không gian/trời đất","cn":"","aliases":["Dung hợp trời đất","Dung nhập không gian"],"loai":"than-thong","loaiLabel":"Thần thông di chuyển","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm"],"blurb":"Thần thông giúp Vương Lâm hòa vào trời đất, bước đi tạo gợn sóng rồi biến mất khỏi chỗ cũ. Trong vùng ranh giới phía Tây La Thiên, hắn dùng cách này để vượt qua sương mù kỳ dị.","detail":"Vương Lâm không dám tùy tiện thả thần thức trong màn sương vì cảm thấy sương mù có thể phát sinh biến hóa bất ngờ. Hắn bình tĩnh thả lỏng tinh thần, dựa vào kinh nghiệm dung hợp trời đất từng tích lũy từ Viêm Lôi tử, bước tới bước thứ ba thì thân hình biến mất, chỉ còn vòng sóng ở nơi cũ.","nguon":["@c0754"]},{"id":"dung-hop-voi-troi-dat","name":"Dung hợp với trời đất","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Trạng thái Vương Lâm dùng để hòa vào trời đất và hướng tới tinh cầu tu chân của mình. Trong chương này, trạng thái ấy bị bức tường thịt khổng lồ cản trở, khiến điểm đến lệch sang khu vực Tiên Di tộc.","detail":"Vương Lâm dựa vào trạng thái dung hợp với trời đất để di chuyển theo ý niệm tới tinh cầu tu chân của mình, nhưng giữa đường như va phải tường. Sau đó hắn xác định nguyên nhân chính là bức tường thịt khổng lồ đang nhúc nhích, nơi có khe hở dẫn tới đại lục lơ lửng của Tiên Di tộc.","nguon":["@c0755"]},{"id":"ky-hieu-thuc-vat-bay-la-cua-tien-di-toc","name":"Ký hiệu thực vật bảy lá của Tiên Di tộc","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên Di tộc","soHuu":["Nam tử áo vải Tiên Di tộc"],"blurb":"Dấu ấn kỳ dị của người Tiên Di tộc, khi vận chuyển kéo tới mi tâm và hóa thành thực vật bảy lá. Nó bao phủ thân thể bằng lực kỳ dị, giúp tốc độ tăng mạnh gần như thuấn di.","detail":"Khi nam tử áo vải bỏ chạy khỏi Vương Lâm, ký hiệu trên mặt hắn kéo dài tới mi tâm rồi hóa thành một gốc thực vật bảy lá. Lực kỳ dị từ dấu ấn này bao phủ thân thể, khiến tốc độ của hắn tăng gấp bội và làm Vương Lâm nhận ra đây là Tiên Di tộc.","nguon":["@c0755"]},{"id":"truu-hon-thuat","name":"Trừu Hồn thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Thuật pháp giúp Vương Lâm nhạy cảm hơn với dấu vết thời gian trên các kiến trúc cổ.","detail":"Sau khi có Trừu Hồn thuật, Vương Lâm khi nhìn khu kiến trúc cổ của tộc Tiên Di/Tiên Tuyển có thể cảm nhận rõ dấu vết năm tháng phủ lên nơi này.","nguon":["@c0756"]},{"id":"tran-phap-tien-vuong-bao-ve-toc","name":"Trận pháp tiên vương bảo vệ tộc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Tiên vương bày ra","hePhai":"Tiên giới / Tiên Di tộc","soHuu":["Tộc Tiên Di / Tộc Tiên Tuyển"],"blurb":"Cấm chế khổng lồ bao quanh nơi cư trú của tộc Tiên Di/Tiên Tuyển.","detail":"Theo lão nhân, trận pháp này do tiên vương năm xưa tự tay bố trí, dùng để giúp bộ tộc không bị Vụ thú xâm hại. Vương Lâm nhờ hiểu biết cấm chế nên nhận ra lớp cấm chế lớn khi tới gần khu kiến trúc cổ.","nguon":["@c0756"]},{"id":"cam-che","name":"Cấm chế","cn":"","loai":"khac","loaiLabel":"Hệ thống cấm pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Hệ cấm pháp mà Vương Lâm am hiểu, giúp hắn nhận ra trận pháp lớn quanh khu cư trú của bộ tộc.","detail":"Tại nơi ở của tộc Tiên Di/Tiên Tuyển, Vương Lâm dựa vào vốn hiểu biết về cấm chế cùng chỉ dẫn từng nhận được ở Lôi tiên giới để liếc mắt phát hiện cấm chế khổng lồ bên ngoài khu kiến trúc.","nguon":["@c0756"]},{"id":"ky-hieu-muoi-ba-la-cua-toc-tien-di-tien-tuyen","name":"Ký hiệu mười ba lá của tộc Tiên Di/Tiên Tuyển","cn":"","loai":"khac","loaiLabel":"Phù ký huyết tộc","phamCap":"Mười ba lá","hePhai":"Tộc Tiên Di / Tộc Tiên Tuyển","soHuu":["Tháp Sơn"],"blurb":"Ký hiệu huyết tộc hiện trên thân người Tiên Di/Tiên Tuyển, là dấu hiệu khiến Vụ thú không thể giả dạng họ.","detail":"Lão nhân nói ký hiệu trên người tộc nhân là nguyên nhân Vụ thú không thể biến thành người của bộ tộc. Tháp Sơn có ký hiệu đen dày đặc trên nửa thân trên, mi tâm hiện cây mười ba lá, được Vương Lâm liên hệ với cấp độ rất mạnh trong hệ Tiên Di.","nguon":["@c0756"]},{"id":"dai-phu-si-tu-luyen-than-the","name":"Đại Phù sĩ tu luyện thân thể","cn":"","loai":"luyen-the","loaiLabel":"Luyện thể","phamCap":"Không rõ","hePhai":"Tộc Tiên Di / Tộc Tiên Tuyển","soHuu":["Tháp Sơn"],"blurb":"Đường tu thân thể của Tháp Sơn, khác với Phù Chú sư.","detail":"Khi Tháp Sơn tung quyền, ký hiệu xuất hiện trong không trung và vây quanh nắm tay như trận pháp kỳ dị. Vương Lâm nhận định đối phương không phải Phù Chú sư mà là Đại Phù sĩ tu luyện thân thể.","nguon":["@c0756"]},{"id":"tien-tran-diet-sat","name":"Tiên trận diệt sát","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Tộc Tiên Tuyển","soHuu":["Lão nhân Tiên Di tộc tóc bạc","Tộc Tiên Tuyển"],"blurb":"Trận pháp khẩn cấp được lão nhân tộc Tiên Tuyển gọi ra khi Vụ thú bắt đầu thức tỉnh.","detail":"Khi một số Vụ thú mở mắt, thoát khỏi lực hút của pháp khí và bắt đầu giết tộc nhân, lão nhân trên bầu trời vừa né tránh vừa hô gọi Tiên trận diệt sát, cho thấy đây là biện pháp của tộc Tiên Tuyển để xử lý Vụ thú nguy hiểm.","nguon":["@c0757"]},{"id":"tieu-truyen-tong-tran","name":"Tiểu truyền tống trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":[],"blurb":"Trận pháp nhỏ nằm dưới đáy Huyền Âm đỉnh, bị hắc khí che phủ. Vương Lâm chỉ nhìn thấy nó trong khoảnh khắc hắc khí bị lôi cầu đẩy ra.","detail":"Tiểu truyền tống trận là điểm ẩn dưới đáy Huyền Âm đỉnh, xuất hiện khi Vương Lâm ném lôi cầu vào miệng đỉnh làm hắc khí tạm thời bị đẩy ra. Sự tồn tại của trận pháp này cho thấy Huyền Âm đỉnh không chỉ là vật cần canh giữ mà còn liên quan tới một lối dịch chuyển bị che giấu.","nguon":["@c0759"]},{"id":"ky-hieu-sau-net-tu-tien-but","name":"Ký hiệu sáu nét","cn":"","aliases":["Ký hiệu sáu nét từ tiên bút"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên bút","soHuu":["Vương Lâm"],"blurb":"Ký hiệu sáu nét do Vương Lâm dùng tiên bút vẽ ra, tỏa kim quang chói mắt và hóa thành một luồng công kích sắc bén.","detail":"Trong lúc Linh hồn Huyền Âm đỉnh định lao ra theo cánh cửa, Vương Lâm rút tiên bút, vẽ ra ký hiệu sáu nét. Ký hiệu này phát kim quang, như thanh kiếm sắc bay tới in lên bóng nữ tử, khiến đối phương run rẩy và bị cánh cửa đóng lại ngăn ở bên trong.","nguon":["@c0760"]},{"id":"bang-quyet","name":"Băng quyết","cn":"","aliases":["Băng"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Quyết pháp do Vương Lâm luyện ra từ bảy ký hiệu của Xạ Thần Xa, dùng tiếng hô “Băng” để đánh vỡ hồn thú khi giải phong pháp bảo.","detail":"Sau khi hấp thu đủ bảy ký hiệu trên Xạ Thần Xa, Vương Lâm dùng chúng hóa thành bảy đạo Băng quyết. Mỗi lần thi triển, hắn hô “Băng” khiến hồn thú trăm trượng do Xạ Thần Xa giải phong sinh ra tan vỡ; bảy lần liên tiếp tạo thành cơ hội ép hồn thú sợ hãi khuất phục, cuối cùng thu nhỏ hóa kén rồi nở thành bướm ngũ sắc.","nguon":["@c0761"]},{"id":"phu-van-no-phu","name":"Phù văn nô phù","cn":"","aliases":["Ấn ký trên thân tộc Tiên Tuyển","Phù văn ấn ký"],"loai":"than-thong","loaiLabel":"Thần thông khống chế","phamCap":"","hePhai":"","soHuu":["Nam nhân trung niên áo xanh"],"blurb":"Ấn ký phù văn khắc sâu trong cơ thể tộc nhân Tiên Tuyển, dùng để phản khống họ khi đối diện “tiên nhân”.","detail":"Phù văn nô phù tồn tại trong cơ thể tộc Tiên Tuyển như một loại ràng buộc khống chế. Khi nam nhân trung niên áo xanh xuất hiện và tự xưng “bản tiên”, ấn ký này phản khống chính tộc nhân Tiên Tuyển, ép họ quỳ xuống, khiến Tháp Sơn dù tấn công cũng bị lực lượng trong thân thể trấn áp, thổ máu và khó phản kháng.","nguon":["@c0761"]},{"id":"no-phu","name":"Nô phù","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Chưa rõ","hePhai":"Tiên nhân","soHuu":["Nam nhân trung niên áo xanh"],"blurb":"Phù ấn khống chế huyết mạch truyền thừa trên người Tiên Tuyển Tộc. Nó khiến tộc nhân không thể phản kháng mệnh lệnh của tiên nhân dù ý chí vẫn bi phẫn.","detail":"Nô phù biểu hiện như lực lượng áp chế đời đời, từng ép Tháp Sơn quỳ xuống dù hai gối vỡ vụn và khiến tộc nhân Tiên Tuyển Tộc bị điều động vây công Vương Lâm. Vương Lâm từ đó suy đoán Tiên Tuyển Tộc và Tiên Di Tộc đều là nô tộc bị tiên nhân gieo dấu ấn.","nguon":["@c0762"]},{"id":"ti-toc-no-phu","name":"Ti tộc nô phù","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Chưa rõ","hePhai":"Tiên nhân","soHuu":["Nam nhân trung niên áo xanh"],"blurb":"Mệnh lệnh điều khiển nô phù được nam nhân áo xanh dùng với Tiên Tuyển Tộc. Khi thi triển, nó ép tộc nhân bị áp chế phải vây công Vương Lâm.","detail":"Sau khi bị mảnh vỡ đại ấn đánh lui, nam nhân áo xanh hô lệnh này để kích hoạt nô phù trong Tiên Tuyển Tộc. Các tộc nhân dù mang bi ai và ý phản kháng vẫn bị thân thể cưỡng ép lao tới bao vây Vương Lâm.","nguon":["@c0762"]},{"id":"tu-mau-dao-kho-thu-doan","name":"Tử Mẫu Đạo Khô","cn":"","loai":"khac","loaiLabel":"Thủ đoạn chiến đấu","phamCap":"Chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn được Vương Lâm đặt cạnh Xạ Thần Xa trong đánh giá chiến lực mới. Khi phối hợp hai thứ, hắn cho rằng mình có thể chiến với Khuy Niết.","detail":"Sau khi chứng kiến uy lực Xạ Thần Xa thứ ba, Vương Lâm nhận định nếu phối hợp với Tử Mẫu Đạo Khô thì chiến lực của hắn đã đủ chạm tới cấp Khuy Niết. Chương này nhấn mạnh giá trị của thủ đoạn này trong tổ hợp chiến đấu của hắn.","nguon":["@c0762"]},{"id":"tam-nhan","name":"Tam nhãn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông con mắt thứ ba của Vương Lâm, phát hồng quang hình quạt để soi xét căn nguyên vật phẩm.","detail":"Trong chương 764, Vương Lâm dùng tam nhãn chiếu vào giọt chất lỏng màu vàng bên trong tiên bảo bị hủy. Dưới nguyên lực toàn lực vận chuyển, tam nhãn khiến chất lỏng tiêu tán thành kim tuyến giao thoa, để lộ phù văn phong ấn ẩn bên trong.","nguon":["@c0764"]},{"id":"phong-van","name":"Phong văn","cn":"","loai":"than-thong","loaiLabel":"Phù văn phong ấn","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Phù văn phong ấn do Vương Lâm rút ra từ pháp bảo chứa chất lỏng màu vàng.","detail":"Phong văn là phù văn đầu tiên Vương Lâm lấy ra được trong pháp bảo. Khi được tiên bút phục khắc, nó có thể vỡ thành chất lỏng màu vàng bao khóa mục tiêu; về sau hơn sáu mươi vạn đạo phong văn được dung nhập vào toái phiến đại ấn để luyện thành Phong Tiên Ấn.","nguon":["@c0764"]},{"id":"than-thong-phong-an","name":"Thần thông phong ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Năng lực phong ấn được Vương Lâm ban cho toái phiến đại ấn thông qua phong văn.","detail":"Sau khi suy ra phù văn có thể được đặt ngược vào pháp bảo khác, Vương Lâm quyết định ban thần thông phong ấn cho toái phiến đại ấn. Năng lực này trở thành cốt lõi của Phong Tiên Ấn sau khi bảo vật luyện thành.","nguon":["@c0764"]},{"id":"cam-che-che-giau-tien-khi-va-luc-phong-an","name":"Cấm chế che giấu tiên khí và lực phong ấn","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Các đạo cấm chế Vương Lâm đánh lên Phong Tiên Ấn để che giấu uy thế thật.","detail":"Sau khi Phong Tiên Ấn thành hình, Vương Lâm đánh nhiều đạo cấm chế lên bảo vật, che bớt tiên khí và hơn phân nửa lực phong ấn. Nhờ vậy tiểu ấn nhìn như một pháp bảo toái tiên ấn bình thường.","nguon":["@c0764"]},{"id":"than-thong-cuu-thap-son","name":"Thần thông cứu Tháp Sơn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Khôi lỗi","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm định dùng để giữ mạng cho Tháp Sơn khi nô phù trong huyết mạch cắn trả. Nếu thành công, Tháp Sơn không chết nhưng sẽ trở thành khôi lỗi không có ý thức.","detail":"Trước toàn bộ Tiên Tuyển tộc đang hô phản kháng, Vương Lâm nói mình có khoảng năm phần nắm chắc khiến Tháp Sơn không chết. Cái giá của cách này là Tháp Sơn sẽ thành khôi lỗi vô thức, còn việc có khôi phục ý thức hay không phụ thuộc vào chính Tháp Sơn.","nguon":["@c0765"]},{"id":"thuat-luyen-hoa-tien-ve","name":"Thuật luyện hóa tiên vệ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thuật Vương Lâm dùng để biến người sống thành tiên vệ, yêu cầu người bị luyện có niềm tin kiên định và hoàn toàn cam tâm tình nguyện.","detail":"Thuật luyện hóa biến một người thành tiên vệ. Điều kiện cốt lõi là người bị luyện phải có niềm tin kiên định và tuyệt đối cam tâm tình nguyện; nếu do dự thì tất bại. Vương Lâm dùng nguyên thần khí bao lấy thân thể, kết hợp Thiên Quỷ, tiên ngọc và đầu lâu tổ tiên làm phụ trợ. Khi thi triển với Tháp Sơn, kết quả tạo ra tiên vệ đạt chiến lực Dương Thực đỉnh nhưng khiến thần trí Tháp Sơn tan vỡ tồn tại trong thân, chưa khôi phục ngay. Vương Lâm nghi ngờ Thiên Quỷ có tác dụng tăng tỷ lệ thành công cho thuật này.","nguon":["@c0766"]},{"id":"huy-linh","name":"Hủy linh","cn":"","loai":"khac","loaiLabel":"Khác","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lệnh Vương Lâm ra cho Tháp Sơn khi cửa tế đàn mở, khiến tiên vệ lao vào thông đạo đối phó lực lượng bên trong.","detail":"Mệnh lệnh Vương Lâm ban khi cửa tế đàn được mở, khiến Tháp Sơn xông vào thông đạo để đối phó với hư ảnh nữ nhân và các lực lượng bên trong, dẫn tới việc phá vỡ Huyền Âm đỉnh.","nguon":["@c0766"]},{"id":"truyen-tong-tran-nho-duoi-huyen-am-dinh","name":"Truyền tống trận nhỏ dưới Huyền Âm đỉnh","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp lộ ra sau khi Huyền Âm đỉnh sụp đổ, hút hắc khí và hư ảnh nữ nhân rồi đưa Vương Lâm cùng Tiên Tuyển tộc rời đi.","detail":"Truyền tống trận nhỏ nằm dưới Huyền Âm đỉnh, xuất hiện sau khi đỉnh bị phá. Nó hút hắc khí và hư ảnh nữ nhân về nơi khác, đồng thời đưa Vương Lâm, Tháp Sơn và toàn bộ Tiên Tuyển tộc rời khỏi nơi cư trú nhiều đời.","nguon":["@c0766"]},{"id":"tran-phap-mau-do-sam-trong-hu-vo","name":"Trận pháp màu đỏ sậm trong hư vô","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp khổng lồ màu đỏ sậm như máu trong hư vô tối đen, tràn hắc khí vào quan tài pha lê ở trung tâm.","detail":"Trận pháp khổng lồ màu đỏ sậm như máu nằm trong hư vô tối đen âm u. Hắc khí tràn qua trận pháp và dung nhập vào chiếc quan tài pha lê ở trung tâm, nơi có thi thể nam nhân tuấn mỹ như ngủ say. Là bí ẩn mới hé lộ cuối chương.","nguon":["@c0766"]},{"id":"tran-phap-khong-lo","name":"Trận pháp khổng lồ","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Nam tử áo đen toàn thân xương trắng"],"blurb":"Trận pháp bao quanh quan tài pha lê, liên tục hấp thu hắc khí vào bên trong. Nam tử áo đen thủ hộ nơi này và tự nhận hiện không đủ lực để hủy pháp trận.","detail":"Trận pháp khổng lồ là trung tâm của khu vực hư vô trong chương này: hắc khí bị hút vào quan tài pha lê bên trong, còn nam tử áo đen ngồi bên ngoài thủ hộ. Sau khi diệt năm phân thân, Vương Lâm lần theo thần thức tìm tới nơi có trận pháp và quan tài pha lê.","nguon":["@c0767"]},{"id":"truong-thuong-hu-ao-tinh-quang","name":"Trường thương hư ảo tinh quang","cn":"","loai":"than-thong","loaiLabel":"Thuật pháp","phamCap":"không rõ","hePhai":"","soHuu":["Năm phân thân của nam tử áo đen"],"blurb":"Thuật pháp do phân thân áo lam thi triển khi giao chiến với Tháp Sơn. Tinh quang được ngưng thành trường thương hư ảo để tấn công.","detail":"Phân thân áo lam bấm quyết, khiến tinh quang xuất hiện và hóa thành trường thương hư ảo nhằm đánh Tháp Sơn. Đây là thủ đoạn tấn công trực tiếp của phân thân trong đợt chặn đường đầu tiên.","nguon":["@c0767"]},{"id":"tien-thuat-tam-dung-than-the","name":"Tiên thuật tạm dừng thân thể","cn":"","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Tiên thuật Vương Lâm dùng để khiến một phân thân đang chuẩn bị tự bạo tạm dừng. Khoảnh khắc ngắn này tạo cơ hội cho Tháp Sơn ôm phân thân lao ra xa.","detail":"Khi một phân thân áp sát và sắp tự bạo, Vương Lâm chỉ tay thi triển tiên thuật làm thân thể đối phương khựng lại trong chốc lát. Tháp Sơn lập tức nhảy tới ôm phân thân mang ra xa, nhờ đó giảm nguy hiểm trực tiếp cho Vương Lâm.","nguon":["@c0767"]},{"id":"dinh-thien","name":"Đỉnh Thiên","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Tiên giới","soHuu":["Long Đạo Tử"],"blurb":"Thần thông Long Đạo Tử dùng để ngưng tụ lực đạo kỳ dị trong phạm vi ngàn dặm lên hai tay, chống lại Phong Tiên Ấn.","detail":"Khi giao chiến với Vương Lâm, Long Đạo Tử thi triển Đỉnh Thiên để dồn lực đạo trong hư không ngàn dặm vào hai tay, dùng sức chống Phong Tiên Ấn đang nện xuống. Thần thông này có thể làm thế hạ xuống của Phong Tiên Ấn bị giảm, nhưng không đủ để hóa giải hoàn toàn áp lực sau khi ấn được giải phong.","nguon":["@c0768"]},{"id":"thap-long-dinh-thien","name":"Thập Long Đỉnh Thiên","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Tiên giới","soHuu":["Long Đạo Tử"],"blurb":"Thần thông biến hắc quang từ mi tâm thành mười hắc long, nối với mi tâm Long Đạo Tử để chống Phong Tiên Ấn.","detail":"Long Đạo Tử dùng hắc quang từ mi tâm hóa thành mười hắc long, để chúng liên tục va vào Phong Tiên Ấn nhằm cản thế áp xuống của pháp bảo. Dù tạo thành sức chống cự mạnh, Thập Long Đỉnh Thiên vẫn không thể khiến Phong Tiên Ấn hoàn toàn dừng lại.","nguon":["@c0768"]},{"id":"thap-long-toai-khong","name":"Thập Long Toái Không","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Tiên giới","soHuu":["Long Đạo Tử"],"blurb":"Thần thông cho mười hắc long tự bạo, tạo lực hủy diệt để phá thế phong ấn và nhấc Phong Tiên Ấn lên.","detail":"Sau khi Thập Long Đỉnh Thiên không đủ ngăn Phong Tiên Ấn, Long Đạo Tử thi triển Thập Long Toái Không, khiến mười hắc long tự bạo toàn bộ. Lực hủy diệt do vụ nổ tạo ra đẩy phù văn phong ấn màu vàng và làm Phong Tiên Ấn tạm thời bị nhấc lên, đồng thời dư uy buộc Tháp Sơn phải dùng thân thể che chắn cho Vương Lâm.","nguon":["@c0768"]},{"id":"giai-an-chi-phong","name":"Giải ấn chi phong","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Pháp quyết điều khiển Phong Tiên Ấn, giải phong để kim quang và phù văn phong ấn bùng phát mạnh hơn.","detail":"Vương Lâm dùng Giải ấn chi phong để mở phong ấn của Phong Tiên Ấn trong lúc đối đầu Long Đạo Tử. Sau khi giải ấn, Phong Tiên Ấn bùng phát kim quang và hơn mười vạn phù văn, áp lực tăng mạnh đến mức ép Long Đạo Tử phải rời khỏi tư thế thủ hộ đã duy trì vô số vạn năm.","nguon":["@c0768"]},{"id":"tran-phap-trong-mieng-u-minh-thu","name":"Trận pháp trong miệng U Minh Thú","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp nằm trong miệng U Minh Thú, phát hào quang làm lối ra khỏi không gian bên trong thân thú.","detail":"Khi U Minh Thú mở miệng, trong miệng nó hiện ra một tòa trận pháp. Vương Lâm và Tiên Tuyển tộc thông qua lối này rời khỏi thế giới bên trong U Minh Thú để trở lại vùng sương mù La Thiên Tây Vực.","nguon":["@c0769"]},{"id":"buoc-phap-dung-nhap-thien-dia","name":"Bước pháp dung nhập thiên địa","cn":"","loai":"than-thong","loaiLabel":"Thần thông di chuyển","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Bước pháp giúp Vương Lâm dung nhập thiên địa để di chuyển bí mật. Khi thi triển, dưới chân hắn xuất hiện sóng gợn và đến bước thứ ba thì cả người biến mất tại chỗ.","detail":"Trong lúc nghi ngờ ba tu sĩ Huyền Trần Tinh, Vương Lâm dùng bước pháp này để quay lại kiểm tra. Thần thông thể hiện bằng từng bước tạo gợn sóng dưới chân, tới bước thứ ba thì thân hình biến mất khỏi vị trí cũ.","nguon":["@c0770"]},{"id":"phap-thuat-cuop-doat-than-thuc","name":"Pháp thuật cướp đoạt thần thức","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn cưỡng ép lục lọi thần thức nguyên thần đối phương. Vương Lâm dùng nguyên lực quét vào nguyên thần trung niên văn sĩ để đoạt ký ức.","detail":"Vương Lâm nhấn tay lên đỉnh nguyên thần, dùng nguyên lực xâm nhập và cưỡng ép cướp đoạt thần thức, khiến nguyên thần đối phương thống khổ, suy kiệt. Chương này thủ đoạn được dùng để lấy thông tin từ kẻ truy sát liên hệ Diêu gia.","nguon":["@c0771"]},{"id":"suu-than-thuat","name":"Sưu thần thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Thần thông lục lọi ký ức nguyên thần. Vương Lâm dùng lên ba nguyên thần truy sát để nắm tình hình La Thiên Tinh Vực trong nửa năm gần đây.","detail":"Sau khi bắt nguyên thần trung niên văn sĩ và hai lão nhân Âm Hư, Vương Lâm dùng cùng một phương pháp sưu thần để tổng hợp ký ức ba người. Nhờ đó hắn biết Diêu gia đã phát động truy sát quy mô lớn và nhiều tu sĩ bước thứ hai tại La Thiên Tinh Vực có ngọc giản chứa chân dung hắn.","nguon":["@c0771"]},{"id":"thuan-di","name":"Thuấn Di","cn":"","loai":"than-thong","loaiLabel":"Thần thông di chuyển","phamCap":"không rõ","hePhai":"phổ biến trong tu sĩ cấp cao","soHuu":["Các tu sĩ chặn đường Diêu gia"],"blurb":"Thuấn Di được nhiều tu sĩ dùng để chạy trốn hoặc phối hợp quấy nhiễu thiên địa. Trong trận này, Vương Lâm nhiều lần vặn vẹo sức mạnh thiên địa để ép đối thủ hiện ra khỏi thuấn di.","detail":"Các tu sĩ trong vòng vây cố dùng thuấn di để rút lui hoặc tạo sóng gợn phá khả năng dung nhập thiên địa của Vương Lâm, nhưng bị hắn khống chế phạm vi trăm trượng, bức hiện thân và truy sát.","nguon":["@c0772"]},{"id":"than-thong-quay-nhieu-suc-manh-thien-dia","name":"Thần thông quấy nhiễu sức mạnh thiên địa","cn":"","loai":"than-thong","loaiLabel":"Thần thông phối hợp","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Các tu sĩ chặn đường Diêu gia"],"blurb":"Thần thông phối hợp này nhằm tạo sóng gợn trong phạm vi trăm trượng để phá lối dung nhập thiên địa của Vương Lâm. Hiệu quả không đủ để ngăn hắn tiếp tục ẩn hiện và phản sát.","detail":"Một nhóm tu sĩ thi triển thần thông, châm đen và thuấn di phối hợp để làm nhiễu sức mạnh thiên địa quanh chiến trường. Dù vậy, Vương Lâm vẫn xuất hiện bình thường và tiếp tục giết người.","nguon":["@c0772"]},{"id":"dao-canh-vinh-quang-dieu-toc","name":"Đạo cảnh vinh quang Diêu tộc","cn":"","loai":"khac","loaiLabel":"Ý cảnh/đạo cảnh","phamCap":"","hePhai":"Diêu gia","soHuu":["Diêu Trường Không"],"blurb":"Ý cảnh của Diêu Trường Không, lấy tín niệm vinh quang tổ tiên Diêu gia ngưng thành hư ảnh tiên nhân để đối kháng đạo niệm Nhân Quả của Vương Lâm.","detail":"Trong trận chiến với Vương Lâm, Diêu Trường Không dựa vào niềm tin Diêu gia kế thừa tiên giới và là hậu duệ tiên nhân để ngưng tụ đạo cảnh vinh quang tổ tiên. Đạo cảnh này hiện ra hư ảnh tiên nhân, nhưng bị Vương Lâm dùng lập luận Nhân Quả về sự sụp đổ của tiên giới và cái chết của tiên nhân công phá, khiến đạo tâm Diêu Trường Không chấn động, thổ huyết và hư ảnh tan biến.","nguon":["@c0773"]},{"id":"phong-tien-an","name":"Phong Tiên Ấn","cn":"","loai":"than-thong","loaiLabel":"Phong ấn/thần thông kèm pháp ấn","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông phong ấn kiêm pháp ấn của Vương Lâm, dùng kim phù và ấn pháp để chặn, khóa và công kích đối thủ.","detail":"Trong trận với Diêu Trường Không, Vương Lâm dựng Phong Tiên Ấn trước người để chặn kiếm quang, sau đó gọi ra vô số kim phù phong ấn và dùng pháp ấn nện xuống. Phong Tiên Ấn được đưa vào sát cục cùng Trảm La quyết, công kích của Tháp Sơn và các thủ đoạn khác, nhưng bị kim đan tiên nhân của Diêu Trường Không hấp thu.","nguon":["@c0773"]},{"id":"hu-bang","name":"Hư Băng","cn":"","loai":"tien-thuat","loaiLabel":"Tiên thuật","phamCap":"","hePhai":"Diêu gia","soHuu":["Diêu Trường Không"],"blurb":"Tiên thuật do Diêu Trường Không thi triển, khiến tinh không sụp xuống tạo sức công kích mạnh.","detail":"Diêu Trường Không dùng Hư Băng trong lúc giao chiến với Vương Lâm. Tiên thuật này khiến không gian trong tinh không sụp đổ, tạo thế áp chế buộc Vương Lâm phải lùi tránh và liên tục dung nhập thiên địa để né đòn.","nguon":["@c0773"]},{"id":"tuy-anh-chi-bang","name":"Tùy Ảnh Chi Băng","cn":"","loai":"tien-thuat","loaiLabel":"Tiên thuật","phamCap":"","hePhai":"Diêu gia","soHuu":["Diêu Trường Không"],"blurb":"Tiên thuật truy kích của Diêu Trường Không, tiếp nối Hư Băng bằng cách khiến không gian sụp đổ đuổi theo mục tiêu.","detail":"Sau Hư Băng, Diêu Trường Không thi triển Tùy Ảnh Chi Băng để duy trì áp lực lên Vương Lâm. Không gian sụp đổ không dừng lại tại một điểm mà tiếp tục truy đuổi, khiến Vương Lâm phải dùng năng lực dung nhập thiên địa để né tránh.","nguon":["@c0773"]},{"id":"muoi-chin-hon","name":"Mười chín hồn","cn":"","loai":"tien-thuat","loaiLabel":"Tiên thuật","phamCap":"","hePhai":"Diêu gia","soHuu":["Diêu Trường Không"],"blurb":"Tiên thuật triệu ra mười chín hồn trẻ con đen như quỷ vật, lao vào công kích Vương Lâm.","detail":"Diêu Trường Không phun ra sương trắng mang tiếng kêu thê thảm, trong đó hiện ra mười chín trẻ con đen như quỷ vật lao về phía Vương Lâm. Vương Lâm dùng Tử Mẫu Đạo Khô để hóa đá các hư ảnh trẻ con bên ngoài Diêu Trường Không, làm chúng sụp đổ.","nguon":["@c0773"]},{"id":"huyet-hon-luc-chuyen","name":"Huyết hồn lục chuyển","cn":"","loai":"tien-thuat","loaiLabel":"Tiên thuật/huyết hồn","phamCap":"","hePhai":"Diêu gia","soHuu":["Diêu Trường Không"],"blurb":"Tiên thuật huyết hồn do tổ tiên Huyết Thần Tử truyền thụ, được Diêu Trường Không dùng để chống Hô Phong.","detail":"Khi Vân Kiếp bị hắc phong của Hô Phong thổi tan và Diêu Trường Không lâm vào nguy cơ, hắn tiêu hao nhiều nguyên lực, phun huyết nguyên thần để thi triển Huyết hồn lục chuyển. Huyết dịch chuyển động thành gió xoáy màu máu, va chạm với âm phong của Hô Phong nhằm triệt tiêu thế công của Vương Lâm.","nguon":["@c0773"]},{"id":"van-kiep","name":"Vân Kiếp","cn":"","loai":"tien-thuat","loaiLabel":"Tiên thuật","phamCap":"","hePhai":"Diêu gia","soHuu":["Diêu Trường Không"],"blurb":"Tiên thuật tạo mây mù và lôi quang thủ hộ, được Diêu Trường Không dùng để chống lại Hô Phong.","detail":"Trước sức ép của Hô Phong, Diêu Trường Không thi triển Vân Kiếp để tạo tầng mây mù và lôi quang thủ hộ quanh thân. Tuy nhiên, hắc phong do Vương Lâm gọi ra thổi tan lớp mây này rất nhanh, buộc Diêu Trường Không phải chuyển sang Huyết hồn lục chuyển.","nguon":["@c0773"]},{"id":"be-than-tien-thuat","name":"Bế Thần Tiên thuật","cn":"","loai":"bi-thuat","loaiLabel":"Cấm thuật","phamCap":"","hePhai":"Diêu gia","soHuu":["Diêu Băng Vân"],"blurb":"Cấm thuật Diêu gia mà Diêu Băng Vân cải tu sau Vấn Đỉnh, yêu cầu tự phong bế thất khiếu và thần thức cảm tri.","detail":"Diêu Băng Vân sau Vấn Đỉnh cải tu Bế Thần Tiên thuật của Diêu gia. Cấm thuật này cần người tu phong bế thất khiếu, không nhìn, không nói, không nghe, không nghĩ; từng có nhiều tộc nhân Diêu gia chết trong quá trình tu luyện. Diêu Băng Vân từng bế quan ở Hàn Băng Tinh năm trăm năm để tu thuật này và cảm ngộ thiên đạo.","nguon":["@c0773"]},{"id":"bang-pha","name":"Băng phá","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"băng hệ","soHuu":["Diêu Băng Vân"],"blurb":"Băng phá là thần thông băng hệ Diêu Băng Vân dùng trong trận truy sát Vương Lâm. Một chỉ của nàng ngưng bông tuyết lam, phóng hàn khí đóng băng một vùng tinh không.","detail":"Khi Vương Lâm lao ra khỏi tinh cầu hoang phế với lôi cầu tím, Diêu Băng Vân thi triển Băng phá để tạo băng phong trong tinh không, chặn thế công của hắn. Thần thông này bị Vương Lâm phối hợp lôi cầu, Tháp Sơn và Hô Phong thuật phá vỡ.","nguon":["@c0774"]},{"id":"huyet-bang","name":"Huyết, băng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"băng hệ","soHuu":["Diêu Băng Vân"],"blurb":"Huyết, băng là thần thông Diêu Băng Vân dùng để khắc chế Tháp Sơn. Nó khiến máu trong cơ thể mục tiêu phun ra thành sương máu và làm quyền thế tan rã.","detail":"Trong lúc Tháp Sơn áp sát tung quyền, Diêu Băng Vân phun ra hai chữ Huyết, băng. Máu trong cơ thể Tháp Sơn lập tức trào ra, khiến một quyền không thể đánh ra và hắn bị lực lượng mạnh mẽ đẩy lui về hư ảnh sau lưng Vương Lâm.","nguon":["@c0774"]},{"id":"cuu-tuyet-ton-than-tran","name":"Cửu Tuyệt Tổn Thần Trận","cn":"","loai":"khac","loaiLabel":"Trận pháp cấm thuật","phamCap":"Một trong tam đại Cấm chế Cấm thuật","hePhai":"Phá diệt Cấm chế","soHuu":["Vương Lâm","Lý Nguyên"],"blurb":"Trận pháp cấm thuật do Vương Lâm bố trí trên tu chân tinh hoang để sát thương đội truy sát.","detail":"Trận dùng nhiều nguyên thần và lạc ấn làm vật liệu, khiến mảnh vỡ tinh cầu sau khi bị phá hủy nối nhau bằng tử lôi, tự bạo liên hoàn và hấp thu nguyên thần người chết để gia tăng uy lực. Trận thuộc truyền thừa Cấm chế của Lý Nguyên và được gọi là một trong tam đại Cấm chế Cấm thuật.","nguon":["@c0776"]},{"id":"pha-diet-cam-che","name":"Phá diệt Cấm chế","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Truyền thừa cấm chế","hePhai":"Lý Nguyên","soHuu":["Lý Nguyên","Vương Lâm"],"blurb":"Hệ cấm chế Lý Nguyên truyền cho Vương Lâm, bao hàm nhiều cấm thuật mạnh.","detail":"Cửu Tuyệt Tổn Thần Trận thuộc hệ Phá diệt Cấm chế này. Một số pháp thuật trong hệ bị hạn chế khi chưa có Phá diệt Tâm cấm, nhưng trận pháp này vẫn có thể thi triển nếu có đủ nguyên thần.","nguon":["@c0776"]},{"id":"pha-diet-tam-cam","name":"Phá diệt Tâm cấm","cn":"","loai":"khac","loaiLabel":"Cấm chế hạch tâm","phamCap":"Không rõ","hePhai":"Phá diệt Cấm chế","soHuu":["Lý Nguyên"],"blurb":"Cấm chế hạch tâm được nhắc như điều kiện để hoàn thiện một số thủ đoạn Phá diệt Cấm chế.","detail":"Vương Lâm chưa có Phá diệt Tâm cấm nên Ẩn Nặc thuật và một số pháp thuật truyền từ Lý Nguyên còn có hạn chế. Cửu Tuyệt Tổn Thần Trận là ngoại lệ vì có thể thi triển mà không cần Tâm cấm.","nguon":["@c0776"]},{"id":"an-nac-thuat","name":"Ẩn Nặc thuật","cn":"","loai":"bi-thuat","loaiLabel":"Ẩn thân thuật","phamCap":"Không rõ","hePhai":"Phá diệt Cấm chế","soHuu":["Vương Lâm","Lý Nguyên"],"blurb":"Pháp thuật ẩn nặc do Lý Nguyên truyền cho Vương Lâm.","detail":"Vương Lâm dùng thuật này để thu liễm khí tức và hòa với tu chân tinh hoang sau khi bố trí Cửu Tuyệt Tổn Thần Trận. Vì thiếu Phá diệt Tâm cấm, thuật vẫn có nguy cơ bị phát hiện.","nguon":["@c0776"]},{"id":"ton-than-an","name":"Tổn Thần Ấn","cn":"","loai":"than-thong","loaiLabel":"Tiên thuật thần thông","phamCap":"Không rõ","hePhai":"Diêu gia","soHuu":["Diêu Băng Vân"],"blurb":"Tiên thuật một chỉ chuyên đả thương nguyên thần của Diêu Băng Vân.","detail":"Diêu Băng Vân chuẩn bị Tổn Thần Ấn để đánh lúc Vương Lâm hiện thân sau trận nổ. Một chỉ này đánh bật Vương Lâm ra ngoài trăm trượng và làm hắn thổ huyết, nhưng không giết được hắn.","nguon":["@c0776"]},{"id":"dieu-gia-tien-thuat","name":"Diêu gia Tiên thuật","cn":"","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"Không rõ","hePhai":"Diêu gia","soHuu":["Nam tử Diêu gia mặc hoa phục"],"blurb":"Tiên thuật do nam tử Diêu gia thi triển khi hợp lực phá hủy tu chân tinh hoang.","detail":"Trong đợt công kích tinh cầu, nam tử Diêu gia thi triển tiên thuật của gia tộc, góp phần làm tu chân tinh sụp đổ và vô tình kích hoạt bố trí của Vương Lâm.","nguon":["@c0776"]},{"id":"song-chi-thanh-kiem","name":"Song chỉ thành kiếm","cn":"","loai":"than-thong","loaiLabel":"Kiếm chỉ","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn Vương Lâm dùng hai ngón tay hóa kiếm chỉ đánh vào hậu tâm đối thủ.","detail":"Vương Lâm dùng Song chỉ thành kiếm khi Diêu Vân Hải bị con Vọng Nguyệt trăm trượng phía trước thu hút. Đòn đánh từ phía sau phá thế phòng bị, mở đầu việc bắt nguyên thần Diêu Vân Hải.","nguon":["@c0778"]},{"id":"bang-don","name":"Băng độn","cn":"","loai":"than-thong","loaiLabel":"Thần thông độn thuật","phamCap":"Không rõ","hePhai":"Diêu Băng Vân","soHuu":["Diêu Băng Vân"],"blurb":"Thần thông giúp Diêu Băng Vân biến mất trong băng tầng rồi áp sát Vương Lâm.","detail":"Sau khi lam quang đóng băng không gian phía trước, Diêu Băng Vân dùng Băng độn xuất hiện ngay trước người Vương Lâm, buộc hắn phải phun Phong Tiên Ấn để phòng hộ.","nguon":["@c0779"]},{"id":"thap-quyet-ton-than-an","name":"Thập Quyết Tổn Thần Ấn","cn":"","loai":"than-thong","loaiLabel":"Ấn quyết công kích nguyên thần","phamCap":"Không rõ","hePhai":"Diêu Băng Vân","soHuu":["Diêu Băng Vân"],"blurb":"Ấn quyết toàn lực của Diêu Băng Vân, tạo mười huyết sắc phù văn đánh vào nguyên thần đối thủ.","detail":"Khi đối đầu Vương Lâm trong cơ thể Vọng Nguyệt, Diêu Băng Vân thi triển Thập Quyết Tổn Thần Ấn. Phong Tiên Ấn làm suy yếu mười quyết còn bốn quyết, nhưng bốn đạo hồng quang vẫn phá vào thân thể và hướng tới nguyên thần Vương Lâm.","nguon":["@c0779"]},{"id":"phong-an-cua-phong-tien-an","name":"Phong ấn của Phong Tiên Ấn","cn":"","loai":"than-thong","loaiLabel":"Phong ấn pháp bảo","phamCap":"Không rõ","hePhai":"Phong Tiên Ấn","soHuu":["Vương Lâm"],"blurb":"Lực phong ấn do phù văn màu vàng của Phong Tiên Ấn hình thành.","detail":"Vương Lâm dùng hơn mười vạn phù văn màu vàng của Phong Tiên Ấn tạo từng đạo phong ấn, làm suy yếu Thập Quyết Tổn Thần Ấn của Diêu Băng Vân trước khi đòn này đánh vào nguyên thần hắn.","nguon":["@c0779"]},{"id":"bang-phong-tu-dan-mau-lam","name":"Băng phong từ đan màu lam","cn":"","loai":"than-thong","loaiLabel":"Băng thuật","phamCap":"Không rõ","hePhai":"Diêu Băng Vân","soHuu":["Diêu Băng Vân"],"blurb":"Băng thuật diện rộng phát ra từ viên đan màu lam của Diêu Băng Vân.","detail":"Khi bị Vọng Nguyệt áp sát và Vương Lâm chuẩn bị phản kích, Diêu Băng Vân lấy viên đan màu lam từ mi tâm, khiến âm hàn khí bộc phát thành băng phong cực nhanh, đóng băng Tử Mẫu Đạo Khô và phần lớn xúc tu Vọng Nguyệt.","nguon":["@c0779"]},{"id":"than-thong-cua-vong-nguyet","name":"Thần thông của Vọng Nguyệt","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Vọng Nguyệt","soHuu":["Vọng Nguyệt"],"blurb":"Thần thông mà Vọng Nguyệt chuẩn bị thi triển sau khi thức tỉnh trong phẫn nộ.","detail":"Khi lửa giận chưa tan, Vọng Nguyệt phát ra ngôn ngữ phức tạp khiến tu sĩ sống sót kinh hãi; họ cho rằng nếu nó thật sự thi triển thần thông thì toàn bộ tu sĩ quanh đó có thể bị diệt sạch.","nguon":["@c0781"]},{"id":"tran-phap-ho-tinh","name":"Trận pháp hộ tinh","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"La Thiên Bắc Vực","soHuu":["Ngũ đại chủ tinh của La Thiên Bắc Vực"],"blurb":"Trận pháp phòng hộ được các chủ tinh La Thiên Bắc Vực mở ra khi Vọng Nguyệt đồ sát tu sĩ.","detail":"Tu sĩ trên ngũ đại chủ tinh chứng kiến Vọng Nguyệt tàn sát liền mở trận pháp hộ tinh để tự bảo vệ, không ai dám ra ngoài tương trợ đám người đang bỏ chạy.","nguon":["@c0781"]},{"id":"do-an-bat-giac-huyet-sac","name":"Đồ án bát giác huyết sắc","cn":"","loai":"khac","loaiLabel":"trận pháp phong ấn","phamCap":"khong-ro","hePhai":"Hướng gia / đại năng La Thiên","soHuu":["Lão già hồng bào"],"blurb":"Trận pháp phong ấn màu huyết sắc do lão già họ Hướng thi triển để tạm vây Vọng Nguyệt.","detail":"Đồ án bát giác giáng xuống tạo sóng gợn bao quanh thân thể khổng lồ của Vọng Nguyệt, hình thành lao địa và tạm phong cả những Vọng Nguyệt nhỏ. Phong ấn bị Cổ Thần chỉ phá nát khi Vọng Nguyệt nổi giận.","nguon":["@c0782"]},{"id":"viem-long","name":"Viêm long","cn":"","loai":"than-thong","loaiLabel":"thần thông hóa thân công kích","phamCap":"khong-ro","hePhai":"Lôi Tiên Điện","soHuu":["Viêm Lôi Tử"],"blurb":"Hóa thân công kích do phân thân Viêm Lôi Tử ngưng tụ toàn bộ hỏa diễm và thực lực.","detail":"Viêm long lao vào Cổ Thần chỉ để thử uy lực một kích mạnh nhất của Vọng Nguyệt, nhưng sau va chạm thì sụp đổ thành biển lửa.","nguon":["@c0782"]},{"id":"hong-kiem","name":"Hồng kiếm","cn":"","loai":"than-thong","loaiLabel":"thần thông hóa thân công kích","phamCap":"khong-ro","hePhai":"Hướng gia / đại năng La Thiên","soHuu":["Lão già hồng bào"],"blurb":"Thanh kiếm màu hồng do lão già họ Hướng hóa thân thành khi giao kích với Cổ Thần chỉ.","detail":"Sau khi viêm long quấn lấy Cổ Thần chỉ, lão già họ Hướng hóa thành hồng kiếm đâm tới nhưng vẫn bị uy lực của một chỉ đánh nát.","nguon":["@c0782"]},{"id":"hac-ung","name":"Hắc ưng","cn":"","loai":"than-thong","loaiLabel":"thần thông hóa thân công kích","phamCap":"khong-ro","hePhai":"thượng cổ tu chân gia tộc","soHuu":["Người đàn ông trung niên"],"blurb":"Hư ảnh hắc ưng do trung niên hắc bào hóa thành để va chạm với Cổ Thần chỉ.","detail":"Hắc ưng mang khí tức tang thương lao vào Cổ Thần chỉ sau viêm long và hồng kiếm, nhưng cũng tiêu tán trước uy lực của Vọng Nguyệt.","nguon":["@c0782"]},{"id":"vien-co-tran-phap-trong-loi-tien-dien","name":"Viễn cổ trận pháp trong Lôi Tiên Điện","cn":"","loai":"khac","loaiLabel":"trận pháp","phamCap":"viễn cổ","hePhai":"Lôi Tiên Điện","soHuu":["Viêm Lôi Tử","Lão già hồng bào","Người đàn ông trung niên"],"blurb":"Trận pháp trong mật thất Lôi Tiên Điện nơi ba đại năng ngồi ở các phương vị mấu chốt.","detail":"Sau khi phân thân ngoài chiến trường bị Cổ Thần chỉ đánh tan, bản thể ba đại năng đồng thời mở mắt trong mật thất, cho thấy họ ra tay thông qua liên kết phân thân hoặc trận pháp đặc thù.","nguon":["@c0782"]},{"id":"than-thong-chan-nat-nguyen-than-cua-vong-nguyet","name":"Thần thông chấn nát nguyên thần của Vọng Nguyệt","cn":"","loai":"than-thong","loaiLabel":"thần thông âm ba","phamCap":"khong-ro","hePhai":"Vọng Nguyệt","soHuu":["Vọng Nguyệt"],"blurb":"Tiếng gầm trong cơ thể Vọng Nguyệt tác động trực tiếp lên nguyên thần đối phương.","detail":"Âm thanh tăng dần như sấm, khiến nguyên thần Vương Lâm đau đớn như bị xé nát. Để chống đỡ, hắn buộc phải mặc lại Cổ Thần bì giáp dù biết khí tức bì giáp sẽ hấp dẫn Vọng Nguyệt nhỏ.","nguon":["@c0782"]},{"id":"song-gon-tim-di-vat-trong-co-the-vong-nguyet","name":"Sóng gợn tìm dị vật trong cơ thể Vọng Nguyệt","cn":"","loai":"than-thong","loaiLabel":"thần thông dò tìm","phamCap":"khong-ro","hePhai":"Vọng Nguyệt","soHuu":["Vọng Nguyệt"],"blurb":"Dao động quét ngang trong cơ thể Vọng Nguyệt để tìm dị vật xâm nhập.","detail":"Sóng gợn xuyên qua thân thể Vương Lâm và giúp Vọng Nguyệt xác định vị trí của hắn, mở đầu cho tiếng gầm chấn nguyên thần và cuộc vây săn của Vọng Nguyệt nhỏ.","nguon":["@c0782"]},{"id":"than-thong-cua-dieu-bang-van","name":"Thần thông của Diêu Băng Vân","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Diêu gia","soHuu":["Diêu Băng Vân"],"blurb":"Thần thông từng khiến nguyên thần Vương Lâm bị thương nặng trong trận với Diêu Băng Vân.","detail":"Tại chương này, Vương Lâm xác nhận nguyên thần mình vẫn bị thương dù có Cổ Thần bì giáp bảo vệ, cho thấy thần thông của Diêu Băng Vân có uy lực trực tiếp lên nguyên thần và tạo hậu quả kéo dài sau giao chiến.","nguon":["@c0784"]}]};
